function rebuildWorldBackgroundCanvas(){
  if(!worldBgImgReady)return;
  const pad=34;
  worldBgCanvas=document.createElement('canvas');
  worldBgCanvas.width=WORLD;
  worldBgCanvas.height=WORLD;
  const bc=worldBgCanvas.getContext('2d');
  bc.fillStyle='#030612';
  bc.fillRect(0,0,WORLD,WORLD);
  bc.save();
  bc.filter=`blur(${WORLD_BG_BLUR}px)`;
  bc.globalAlpha=WORLD_BG_ALPHA;
  drawCoverImageToRect(bc,worldBgImg,-pad,-pad,WORLD+pad*2,WORLD+pad*2);
  bc.restore();
}
