function addWeapon(id){if(!player.weapons[id]){player.weapons[id]={level:1};player.timers[id]=0;message('获得武器：'+weaponDefs.find(w=>w.id===id).name);playSfx('level')}else{player.weapons[id].level++;message('强化：'+weaponDefs.find(w=>w.id===id).name+' Lv.'+player.weapons[id].level);playSfx('level')}}function applySkill(id){let s=skillDefs.find(x=>x.id===id);if(!s)return;player.skills[id]=(player.skills[id]||0)+1;s.apply(player);message('获得被动：'+s.name);playSfx('level')}function shuffle(a){return[...a].sort(()=>Math.random()-.5)}
function buildUpgradeChoices(){let pool=[];for(const w of weaponDefs){if(!player.weapons[w.id])pool.push({kind:'weapon',id:w.id,title:`获得 ${w.name}`,desc:w.desc,tag:'新武器'});else if(player.weapons[w.id].level<5)pool.push({kind:'weapon',id:w.id,title:`强化 ${w.name} Lv.${player.weapons[w.id].level+1}`,desc:`提升 ${w.name} 的伤害、范围、数量或触发效率。`,tag:`武器强化 · Lv.${player.weapons[w.id].level+1}`})}for(const s of skillDefs)pool.push({kind:'skill',id:s.id,title:s.name+(player.skills[s.id]?` Lv.${player.skills[s.id]+1}`:''),desc:s.desc,tag:s.tag});return shuffle(pool).slice(0,3)}
function showStartingWeaponSelect(){choosingStart=true;startPickCount=0;const overlay=document.getElementById('levelOverlay'),cards=document.getElementById('cards'),title=overlay.querySelector('h1'),sub=overlay.querySelector('.subtitle');title.textContent='选择初始武器';sub.textContent='开局前自选两个武器。卡牌预览使用游戏内真实技能风格绘制。';cards.innerHTML='';weaponDefs.forEach(w=>{const div=buildChoiceCard({id:w.id,title:w.name,desc:w.desc,tag:'初始武器'},()=>{if(player.weapons[w.id]||!choosingStart)return;addWeapon(w.id);startPickCount++;div.style.opacity=.45;div.style.pointerEvents='none';div.querySelector('.tag').textContent='已选择';if(startPickCount>=2){choosingStart=false;overlay.style.display='none';title.textContent='星舰改装';sub.textContent='选择一项升级。';paused=false;clearKeys();message('第 1 关开始')}});cards.appendChild(div)});overlay.style.display='flex'}function levelUp(){paused=true;const overlay=document.getElementById('levelOverlay');overlay.querySelector('h1').textContent='星舰改装';overlay.querySelector('.subtitle').textContent='选择一项升级。卡牌预览直接使用游戏内技能视觉风格。';const cards=document.getElementById('cards');cards.innerHTML='';buildUpgradeChoices().forEach(c=>{const div=buildChoiceCard(c,()=>{if(c.kind==='weapon')addWeapon(c.id);else applySkill(c.id);overlay.style.display='none';paused=false;clearKeys()});cards.appendChild(div)});overlay.style.display='flex'}
function update(dt){if(paused||gameOver||document.getElementById('levelOverlay').style.display==='flex')return;screenFlash=Math.max(0,screenFlash-dt*1.9);stageTime+=dt;updateStage(dt);updatePlayer(dt);updateWeapons(dt);updateProjectiles(dt);updateEnemies(dt);updatePickups(dt);updateParticles(dt);let targetCamX=clamp(player.x-W/2,0,WORLD-W),targetCamY=clamp(player.y-H/2,0,WORLD-H);camera.x+=((targetCamX-camera.x)*smooth01(9,dt));camera.y+=((targetCamY-camera.y)*smooth01(9,dt));shake=Math.max(0,shake-dt*14);updateUI()}var updateStage=window.GameStageSystem.updateStage,nextStage=window.GameStageSystem.nextStage,spawnWave=window.GameEnemySystem.spawnWave,spawnEnemy=window.GameEnemySystem.spawnEnemy,spawnBoss=window.GameBossSystem.spawnBoss,spawnDef=window.GameEnemySystem.spawnDef;
function updatePlayer(dt){
  let mx=(keys.KeyD||keys.ArrowRight?1:0)-(keys.KeyA||keys.ArrowLeft?1:0),my=(keys.KeyS||keys.ArrowDown?1:0)-(keys.KeyW||keys.ArrowUp?1:0),moving=!!(mx||my),n=norm(mx,my);
  let boosting=keys.ShiftLeft||keys.ShiftRight;
  let canBoost=boosting&&player.boost>0&&moving;
  let slow=player.slowMove>0?.62:1;
  player.slowMove=Math.max(0,(player.slowMove||0)-dt);
  let moveSpeed=player.speed*(canBoost?1.58:1)*slow;
  let targetVx=moving?n.x*moveSpeed:0,targetVy=moving?n.y*moveSpeed:0;
  let accelRate=moving?(canBoost?15:12):18;
  player.vx=(player.vx||0)+(targetVx-(player.vx||0))*smooth01(accelRate,dt);
  player.vy=(player.vy||0)+(targetVy-(player.vy||0))*smooth01(accelRate,dt);
  let curSpeed=Math.hypot(player.vx,player.vy),maxSpeed=moveSpeed*(canBoost?1.03:1);
  if(curSpeed>maxSpeed&&curSpeed>0){player.vx=player.vx/curSpeed*maxSpeed;player.vy=player.vy/curSpeed*maxSpeed}
  let flameTarget=player.dashTime>0?1.15:(moving?clamp(.62+curSpeed/(player.speed*1.55)*.36,.62,.98):.18);
  if(canBoost)flameTarget=1.06;
  let flameNow=player.flamePower??.18;
  player.flamePower=flameNow+(flameTarget-flameNow)*smooth01(flameTarget>flameNow?9:5,dt);
  player.flameFlicker=(player.flameFlicker||0)+dt*(5+player.flamePower*13);
  if(canBoost){player.boost=Math.max(0,player.boost-38*dt);playSfx('boost')}
  else player.boost=Math.min(player.boostMax,player.boost+24*dt);
  player.x+=player.vx*dt;
  player.y+=player.vy*dt;
  if(player.x<30||player.x>WORLD-30)player.vx=0;
  if(player.y<30||player.y>WORLD-30)player.vy=0;
  player.x=clamp(player.x,30,WORLD-30);
  player.y=clamp(player.y,30,WORLD-30);
  player.targetAngle=Math.atan2(mouse.y-(player.y-camera.y),mouse.x-(player.x-camera.x));
  player.angle=angleLerp(player.angle,player.targetAngle,smooth01(18,dt));
  player.dashCd=Math.max(0,player.dashCd-dt);
  player.invuln=Math.max(0,player.invuln-dt);
  if(player.dashTime>0){
    player.dashTime-=dt;
    player.x+=Math.cos(player.dashAng)*680*dt;
    player.y+=Math.sin(player.dashAng)*680*dt;
    player.vx=player.vx*.82+Math.cos(player.dashAng)*75;
    player.vy=player.vy*.82+Math.sin(player.dashAng)*75;
  }
  if(keys.Space&&player.dashCd<=0){
    player.dashCd=player.dashMax;player.dashTime=.18;player.invuln=.42;
    let dx=mx,dy=my;if(!dx&&!dy){dx=Math.cos(player.angle);dy=Math.sin(player.angle)}
    let nn=norm(dx,dy);player.dashAng=Math.atan2(nn.y,nn.x);shake=5;playSfx('dash')
  }
}var damagePlayer=window.GameCombat.damagePlayer,gainXp=window.GameCombat.gainXp;function endGame(){gameOver=true;pauseCustomBgm();document.getElementById('finalStats').innerHTML=`到达关卡：第 ${stage} 关<br>本关进度：${Math.floor(stageTime/STAGE_LEN*100)}%<br>击杀敌人：${kills}<br>等级：${player.level}`;document.getElementById('gameOver').style.display='flex'}
