var spawnEnemySkill=window.GameEnemySystem.spawnEnemySkill,bossBeam=window.GameBossSystem.bossBeam,bossNova=window.GameBossSystem.bossNova,bossOrbRing=window.GameBossSystem.bossOrbRing;
var updateEnemies=window.GameEnemySystem.updateEnemies,updateBossPhase=window.GameBossSystem.updateBossPhase;function updatePickups(dt){for(let i=pickups.length-1;i>=0;i--){let p=pickups[i],d=Math.hypot(p.x-player.x,p.y-player.y);if(d<80*player.pickupMul){let a=angleTo(p,player);p.x+=Math.cos(a)*330*dt;p.y+=Math.sin(a)*330*dt}if(d<player.r+p.r+4){if(p.type==='xp'){gainXp(p.val);playSfx('pickup')}else{player.hp=clamp(player.hp+p.val,0,player.maxHp);playSfx('heal')}pickups.splice(i,1)}}}var updateParticles=window.GameEffectSystem.updateParticles,burst=window.GameEffectSystem.burst,trail=window.GameEffectSystem.trail;
function draw(){
  ctx.clearRect(0,0,W,H);
  let sx=(Math.random()-.5)*shake*settings.shake,sy=(Math.random()-.5)*shake*settings.shake;
  ctx.save();
  ctx.translate(-camera.x+sx,-camera.y+sy);
  drawWorld(ctx,camera.x,camera.y,W,H,stageTime);
  drawPickups();
  drawEnemies();
  ctx.save();ctx.globalCompositeOperation='lighter';drawProjectiles();drawParticles();ctx.restore();
  drawPlayer();
  drawForegroundAtmosphere(ctx,camera.x,camera.y,W,H,stageTime);
  ctx.restore();
  drawVignette(ctx,W,H);
}
function drawWorld(c,cx,cy,w,h,t){
  let g=c.createLinearGradient(cx,cy,cx+w,cy+h);g.addColorStop(0,'#040816');g.addColorStop(.34,'#09142b');g.addColorStop(.68,'#161033');g.addColorStop(1,'#050611');c.fillStyle=g;c.fillRect(cx,cy,w,h);
  c.save();c.globalCompositeOperation='lighter';
  for(const n of bgNebulas){if(n.x<cx-n.r||n.x>cx+w+n.r||n.y<cy-n.r||n.y>cy+h+n.r)continue;c.save();c.translate(n.x,n.y);c.rotate(n.rot+.03*Math.sin(t*.08+n.x));let rg=c.createRadialGradient(0,0,0,0,0,n.r);rg.addColorStop(0,`rgba(${n.color},${n.alpha})`);rg.addColorStop(.42,`rgba(${n.color},${n.alpha*.42})`);rg.addColorStop(1,`rgba(${n.color},0)`);c.fillStyle=rg;c.beginPath();c.ellipse(0,0,n.r*1.25,n.r*.62,0,0,Math.PI*2);c.fill();c.restore()}
  c.restore();
  for(const p of bgPlanets){if(p.x<cx-p.r*2.5||p.x>cx+w+p.r*2.5||p.y<cy-p.r*2.5||p.y>cy+h+p.r*2.5)continue;drawProceduralPlanet(c,p,t)}
  for(const s of bgStars){if(s.x<cx-20||s.x>cx+w+20||s.y<cy-20||s.y>cy+h+20)continue;let tw=.68+.32*Math.sin(t*s.s+s.x*.03+s.y*.01);c.globalAlpha=s.a*tw;c.fillStyle=`hsl(${s.h},90%,88%)`;c.beginPath();c.arc(s.x,s.y,s.r,0,Math.PI*2);c.fill();if(s.r>1.9){c.strokeStyle='rgba(210,235,255,.28)';c.lineWidth=.8;c.beginPath();c.moveTo(s.x-5,s.y);c.lineTo(s.x+5,s.y);c.moveTo(s.x,s.y-5);c.lineTo(s.x,s.y+5);c.stroke()}c.globalAlpha=1}
  for(const a of bgAsteroids){if(a.x<cx-80||a.x>cx+w+80||a.y<cy-80||a.y>cy+h+80)continue;drawAsteroid(c,a,t)}
  for(const r of bgRelics){if(r.x<cx-90||r.x>cx+w+90||r.y<cy-90||r.y>cy+h+90)continue;c.save();c.translate(r.x,r.y);c.rotate(r.rot+.05*Math.sin(t*.2+r.x));if(r.type==='ring'){c.strokeStyle='rgba(140,190,255,.12)';c.lineWidth=3;c.beginPath();c.arc(0,0,r.r,0,Math.PI*2);c.stroke();c.strokeStyle='rgba(255,220,120,.08)';c.lineWidth=1;c.beginPath();c.arc(0,0,r.r*.65,0,Math.PI*2);c.stroke()}else{c.fillStyle='rgba(130,155,190,.08)';c.strokeStyle='rgba(190,230,255,.08)';c.lineWidth=1;c.beginPath();c.moveTo(-r.r,-r.r*.25);c.lineTo(r.r*.2,-r.r*.6);c.lineTo(r.r,0);c.lineTo(r.r*.1,r.r*.5);c.lineTo(-r.r*.8,r.r*.25);c.closePath();c.fill();c.stroke()}c.restore()}
  c.strokeStyle='rgba(120,170,255,.038)';c.lineWidth=1;let step=90;for(let x=Math.floor(cx/step)*step;x<cx+w+step;x+=step){c.beginPath();c.moveTo(x,cy);c.lineTo(x,cy+h);c.stroke()}for(let y=Math.floor(cy/step)*step;y<cy+h+step;y+=step){c.beginPath();c.moveTo(cx,y);c.lineTo(cx+w,y);c.stroke()}c.strokeStyle='rgba(255,211,106,.22)';c.lineWidth=4;c.strokeRect(20,20,WORLD-40,WORLD-40)
}
function drawProceduralPlanet(c,p,t){c.save();c.translate(p.x,p.y);c.rotate(p.rot);c.globalAlpha=p.a;if(p.ring){c.strokeStyle='rgba(180,220,255,.18)';c.lineWidth=8;c.beginPath();c.ellipse(0,0,p.r*1.65,p.r*.42,0,0,Math.PI*2);c.stroke()}let pg=c.createRadialGradient(-p.r*.35,-p.r*.42,0,0,0,p.r);pg.addColorStop(0,p.c2);pg.addColorStop(.5,p.c1);pg.addColorStop(1,'rgba(0,0,0,.95)');c.fillStyle=pg;c.beginPath();c.arc(0,0,p.r,0,Math.PI*2);c.fill();c.globalAlpha=p.a*.55;c.strokeStyle='rgba(255,255,255,.32)';c.lineWidth=2;for(let i=-2;i<=2;i++){c.beginPath();c.ellipse(0,i*p.r*.22,p.r*.82,p.r*.08,0,0,Math.PI*2);c.stroke()}c.restore();c.globalAlpha=1}
function drawAsteroid(c,a,t){c.save();c.translate(a.x,a.y);c.rotate(a.rot+t*a.spin);c.fillStyle=`rgba(160,175,190,${a.shade})`;c.strokeStyle=`rgba(220,235,255,${a.shade*.9})`;c.lineWidth=1;c.beginPath();for(let i=0;i<9;i++){let ang=i*Math.PI*2/9,rr=a.r*(.72+Math.sin(i*2.1+a.x)*.22),x=Math.cos(ang)*rr,y=Math.sin(ang)*rr;if(i===0)c.moveTo(x,y);else c.lineTo(x,y)}c.closePath();c.fill();c.stroke();c.fillStyle=`rgba(255,255,255,${a.shade*.32})`;c.beginPath();c.arc(-a.r*.25,-a.r*.2,a.r*.18,0,Math.PI*2);c.fill();c.restore()}
function drawForegroundAtmosphere(c,cx,cy,w,h,t){c.save();c.globalCompositeOperation='lighter';for(const d of bgDust){let x=((d.x+d.vx*t*18)%WORLD+WORLD)%WORLD,y=((d.y+d.vy*t*18)%WORLD+WORLD)%WORLD;if(x<cx-20||x>cx+w+20||y<cy-20||y>cy+h+20)continue;c.globalAlpha=d.a*(.55+.45*Math.sin(t*1.2+x));c.fillStyle='#cde7ff';c.beginPath();c.arc(x,y,d.r,0,Math.PI*2);c.fill()}c.globalAlpha=1;c.restore()}
function drawPlayer(){let shipBoost=player.dashTime>0||(((keys.ShiftLeft||keys.ShiftRight)&&Math.hypot(player.vx||0,player.vy||0)>30));drawShip(ctx,player.x,player.y,player.angle,shipBoost,player.invuln>0&&Math.floor(stageTime*18)%2===0,1,player.flamePower||.18);/* v48: removed player dash-ready circle */let ow=player.weapons.holyPrism;if(ow){let n=2+Math.floor(ow.level/2),rad=78+ow.level*8;for(let i=0;i<n;i++){let ox=player.x+Math.cos(player.orbit*2.6+i*Math.PI*2/n)*rad,oy=player.y+Math.sin(player.orbit*2.6+i*Math.PI*2/n)*rad;drawPrism(ctx,ox,oy,10,'#fff3a3')}}}function drawShip(c,x,y,a,boost=false,blink=false,scale=1){
  c.save();c.translate(x,y);c.rotate(a);c.scale(scale,scale);c.globalAlpha=blink?.45:1;
  c.globalCompositeOperation='lighter';let flameLen=boost?72:42;
  for(const off of[-15,0,15]){let fg=c.createLinearGradient(-54,off,-58-flameLen,off);fg.addColorStop(0,'rgba(255,255,255,.10)');fg.addColorStop(.18,'rgba(130,250,255,.96)');fg.addColorStop(.55,'rgba(75,130,255,.62)');fg.addColorStop(1,'rgba(75,130,255,0)');c.fillStyle=fg;c.shadowColor='#6ef6ff';c.shadowBlur=24;c.beginPath();c.moveTo(-38,off);c.lineTo(-48-flameLen,off-7);c.lineTo(-20,off);c.lineTo(-48-flameLen,off+7);c.closePath();c.fill()}
  c.globalCompositeOperation='source-over';c.shadowColor='#66e6ff';c.shadowBlur=16;c.fillStyle='#070b18';c.beginPath();c.moveTo(64,0);c.lineTo(32,-24);c.lineTo(-6,-25);c.lineTo(-38,-18);c.lineTo(-56,-8);c.lineTo(-56,8);c.lineTo(-38,18);c.lineTo(-6,25);c.lineTo(32,24);c.closePath();c.fill();
  for(const side of[-1,1]){let wg=c.createLinearGradient(-44,side*34,24,0);wg.addColorStop(0,'#172344');wg.addColorStop(.55,'#587da6');wg.addColorStop(1,'#d1edf8');c.fillStyle=wg;c.beginPath();c.moveTo(10,side*10);c.lineTo(-14,side*34);c.lineTo(-46,side*25);c.lineTo(-16,side*7);c.closePath();c.fill();c.strokeStyle='rgba(126,247,255,.86)';c.lineWidth=2;c.beginPath();c.moveTo(-34,side*23);c.lineTo(-8,side*10);c.stroke();c.fillStyle='#26344f';c.fillRect(-18,side*19-3,22,6)}
  let hull=c.createLinearGradient(-54,-24,66,24);hull.addColorStop(0,'#203055');hull.addColorStop(.28,'#5e86ad');hull.addColorStop(.56,'#e3f4fb');hull.addColorStop(.82,'#8baec7');hull.addColorStop(1,'#314261');c.fillStyle=hull;c.beginPath();c.moveTo(68,0);c.lineTo(34,-22);c.lineTo(4,-22);c.lineTo(-26,-17);c.lineTo(-48,-8);c.lineTo(-48,8);c.lineTo(-26,17);c.lineTo(4,22);c.lineTo(34,22);c.closePath();c.fill();
  let deck=c.createLinearGradient(-12,-13,38,13);deck.addColorStop(0,'#34486d');deck.addColorStop(1,'#c4e2f2');c.fillStyle=deck;c.beginPath();c.moveTo(34,0);c.lineTo(10,-12);c.lineTo(-12,-10);c.lineTo(-26,0);c.lineTo(-12,10);c.lineTo(10,12);c.closePath();c.fill();let cg=c.createRadialGradient(18,-2,0,16,0,20);cg.addColorStop(0,'#ffffff');cg.addColorStop(.35,'#86f2ff');cg.addColorStop(1,'#2768bd');c.fillStyle=cg;c.shadowColor='#7ef7ff';c.shadowBlur=18;c.beginPath();c.moveTo(31,0);c.lineTo(9,-8);c.lineTo(1,0);c.lineTo(9,8);c.closePath();c.fill();
  c.shadowBlur=0;c.fillStyle='#536b8d';c.fillRect(-7,-7,22,14);c.fillStyle='#d7edf9';c.fillRect(8,-2,24,4);for(const side of[-1,1]){c.fillStyle='#4b5b76';c.fillRect(18,side*8-2,18,4);c.fillStyle='#eefaff';c.fillRect(34,side*8-1,13,2)}c.strokeStyle='rgba(255,255,255,.68)';c.lineWidth=2;c.beginPath();c.moveTo(44,0);c.lineTo(10,-14);c.moveTo(44,0);c.lineTo(10,14);c.stroke();c.strokeStyle='rgba(30,70,130,.92)';c.beginPath();c.moveTo(68,0);c.lineTo(34,-22);c.lineTo(4,-22);c.lineTo(-26,-17);c.lineTo(-48,-8);c.lineTo(-48,8);c.lineTo(-26,17);c.lineTo(4,22);c.lineTo(34,22);c.closePath();c.stroke();c.globalCompositeOperation='lighter';c.fillStyle='#8efaff';c.shadowColor='#66f6ff';c.shadowBlur=22;c.beginPath();c.arc(52,0,5.5,0,Math.PI*2);c.fill();c.restore()
}
function drawEnemies(){for(const e of enemies){drawEnemyShape(ctx,e);if(e.elite){ctx.strokeStyle=e.mod==='shield'?'#9eeeff':e.mod==='swift'?'#ffe38a':e.mod==='volatile'?'#ff9f43':'#c493ff';ctx.shadowColor=ctx.strokeStyle;ctx.shadowBlur=12;ctx.lineWidth=2;ctx.beginPath();ctx.arc(e.x,e.y,e.r+7,0,Math.PI*2);ctx.stroke();ctx.shadowBlur=0}if(e.shield>0){ctx.strokeStyle='rgba(158,238,255,.65)';ctx.lineWidth=3;ctx.beginPath();ctx.arc(e.x,e.y,e.r+11,0,Math.PI*2);ctx.stroke()}if(!(e.def&&e.def.boss)){let bw=e.r*2.2;ctx.fillStyle='rgba(0,0,0,.35)';ctx.fillRect(e.x-bw/2,e.y-e.r-14,bw,4);ctx.fillStyle='#ff6868';ctx.fillRect(e.x-bw/2,e.y-e.r-14,bw*(e.hp/e.maxHp),4)}}}function drawEnemyShape(c,e){c.save();c.translate(e.x,e.y);c.shadowColor=e.def.color;c.shadowBlur=e.hit?30:14;if(e.hit)c.globalAlpha=.82;let r=e.r;switch(e.def.shape){case'wisp':c.fillStyle=e.def.color;c.beginPath();c.arc(0,0,r*.72,0,Math.PI*2);c.fill();c.globalAlpha=.45;c.beginPath();c.arc(-r*.45,r*.15,r*.5,0,Math.PI*2);c.fill();c.beginPath();c.arc(r*.4,r*.25,r*.36,0,Math.PI*2);c.fill();break;case'skull':c.fillStyle=e.def.color;c.beginPath();c.arc(0,-2,r*.78,0,Math.PI*2);c.fill();c.fillRect(-r*.45,r*.1,r*.9,r*.45);c.fillStyle='#111';c.beginPath();c.arc(-r*.22,-r*.1,r*.15,0,Math.PI*2);c.fill();c.beginPath();c.arc(r*.22,-r*.1,r*.15,0,Math.PI*2);c.fill();break;case'bug':c.fillStyle=e.def.color;c.beginPath();c.ellipse(0,0,r*.85,r*.65,0,0,Math.PI*2);c.fill();c.beginPath();c.ellipse(-r*.6,0,r*.35,r*.32,0,0,Math.PI*2);c.fill();c.beginPath();c.ellipse(r*.55,0,r*.28,r*.28,0,0,Math.PI*2);c.fill();c.strokeStyle='rgba(255,255,255,.45)';for(const sy of[-1,1]){c.beginPath();c.moveTo(-r*.1,sy*r*.2);c.lineTo(-r*.8,sy*r*.55);c.stroke();c.beginPath();c.moveTo(r*.15,sy*r*.2);c.lineTo(r*.75,sy*r*.58);c.stroke()}break;case'golem':c.fillStyle=e.def.color;c.fillRect(-r*.55,-r*.5,r*1.1,r);c.fillRect(-r*.85,-r*.2,r*.28,r*.7);c.fillRect(r*.57,-r*.2,r*.28,r*.7);c.fillStyle='rgba(255,255,255,.18)';c.fillRect(-r*.25,-r*.2,r*.5,r*.18);break;case'bat':c.fillStyle=e.def.color;c.beginPath();c.moveTo(0,0);c.lineTo(-r*1.25,-r*.55);c.lineTo(-r*.5,r*.15);c.closePath();c.fill();c.beginPath();c.moveTo(0,0);c.lineTo(r*1.25,-r*.55);c.lineTo(r*.5,r*.15);c.closePath();c.fill();c.beginPath();c.arc(0,0,r*.42,0,Math.PI*2);c.fill();break;case'flame':let g=c.createRadialGradient(0,0,2,0,0,r);g.addColorStop(0,'#fff6bf');g.addColorStop(.4,'#ffb166');g.addColorStop(1,e.def.color);c.fillStyle=g;c.beginPath();c.moveTo(0,-r);c.bezierCurveTo(r*.8,-r*.3,r*.8,r*.5,0,r);c.bezierCurveTo(-r*.8,r*.5,-r*.8,-r*.3,0,-r);c.fill();break;case'guard':c.fillStyle=e.def.color;c.beginPath();c.moveTo(0,-r);c.lineTo(r*.75,0);c.lineTo(0,r);c.lineTo(-r*.75,0);c.closePath();c.fill();c.strokeStyle='rgba(255,255,255,.65)';c.beginPath();c.moveTo(0,-r*.65);c.lineTo(0,r*.65);c.stroke();break;case'priest':c.fillStyle=e.def.color;c.beginPath();c.moveTo(0,-r*.9);c.lineTo(r*.55,r*.75);c.lineTo(-r*.55,r*.75);c.closePath();c.fill();c.strokeStyle='rgba(255,255,255,.7)';c.beginPath();c.arc(0,-r*1.02,r*.32,0,Math.PI*2);c.stroke();break;case'brute':c.fillStyle=e.def.color;c.beginPath();c.arc(0,-r*.25,r*.55,0,Math.PI*2);c.fill();c.fillRect(-r*.7,-r*.05,r*1.4,r*1.1);break;case'bossKnight':c.rotate(stageTime*.35);c.fillStyle=e.def.color;c.beginPath();for(let i=0;i<16;i++){let rr=i%2?r*.82:r*1.1,aa=i*Math.PI/8;c.lineTo(Math.cos(aa)*rr,Math.sin(aa)*rr)}c.closePath();c.fill();c.fillStyle='#a995ff';c.beginPath();c.arc(0,0,r*.42,0,Math.PI*2);c.fill();c.strokeStyle='#ff4f6f';c.lineWidth=3;c.beginPath();c.moveTo(-r*.8,-r*.2);c.lineTo(r*.9,0);c.lineTo(-r*.8,r*.2);c.stroke();break;case'bossSeraph':c.rotate(Math.sin(stageTime)*.12);c.fillStyle=e.def.color;for(const side of[-1,1]){c.beginPath();c.moveTo(0,0);c.lineTo(side*r*1.55,-r*.85);c.lineTo(side*r*.55,0);c.lineTo(side*r*1.55,r*.85);c.closePath();c.fill()}c.fillStyle='#e8dcff';c.beginPath();c.moveTo(0,-r*1.05);c.lineTo(r*.58,0);c.lineTo(0,r*1.05);c.lineTo(-r*.58,0);c.closePath();c.fill();c.fillStyle='#7a5cff';c.beginPath();c.arc(0,0,r*.34,0,Math.PI*2);c.fill();break;case'bossLeviathan':c.fillStyle='#18243a';c.beginPath();c.ellipse(0,0,r*1.45,r*.62,0,0,Math.PI*2);c.fill();c.fillStyle=e.def.color;for(let i=-2;i<=2;i++){c.beginPath();c.ellipse(i*r*.42,Math.sin(stageTime*2+i)*5,r*.42,r*.42,0,0,Math.PI*2);c.fill()}c.strokeStyle='#ff8b42';c.lineWidth=3;c.beginPath();c.moveTo(-r*1.3,0);c.lineTo(r*1.35,0);c.stroke();break;case'bossHive':c.rotate(stageTime*.18);c.fillStyle=e.def.color;for(let i=0;i<6;i++){let a=i*Math.PI/3;c.beginPath();c.arc(Math.cos(a)*r*.52,Math.sin(a)*r*.52,r*.52,0,Math.PI*2);c.fill()}c.fillStyle='#ffd6ff';c.beginPath();c.arc(0,0,r*.5,0,Math.PI*2);c.fill();c.fillStyle='#3a103f';c.beginPath();c.arc(0,0,r*.24,0,Math.PI*2);c.fill();break}c.restore()}
function drawProjectiles(){for(const p of projectiles){if(p.type==='slash')drawSlash(ctx,p);else if(p.type==='flame')drawFlame(ctx,p);else if(p.type==='ring')drawIceRing(ctx,p);else if(p.type==='meteor')drawMeteor(ctx,p);else if(p.type==='zone')drawZone(ctx,p);else if(p.type==='blackhole')drawBlackhole(ctx,p);else if(p.type==='swordWave')drawSwordWave(ctx,p);else if(p.type==='bolt')drawSpear(ctx,p);else if(p.type==='boomerang')drawBlade(ctx,p);else if(p.type==='homing')drawDagger(ctx,p);else if(p.type==='missile')drawMissile(ctx,p);else if(p.type==='rail')drawRail(ctx,p);else if(p.type==='chain')drawChain(ctx,p);else if(p.type==='mine')drawMine(ctx,p);else if(p.type==='beam')drawBeam(ctx,p);else if(p.type==='enemyFireball')drawEnemyFireball(ctx,p);else if(p.type==='enemyIce')drawEnemyIce(ctx,p);else if(p.type==='enemyOrb')drawEnemyOrb(ctx,p);else if(p.type==='enemyShockwave')drawEnemyShockwave(ctx,p);else if(p.type==='enemyBeamWarn')drawEnemyBeamWarn(ctx,p);else if(p.type==='enemyBeam')drawEnemyBeam(ctx,p);else if(p.type==='enemyBossNova')drawEnemyBossNova(ctx,p);else glowCircle(ctx,p.x,p.y,p.r,p.color)}}function drawSlash(c,p){c.save();c.translate(player.x,player.y);c.rotate(p.a);c.globalAlpha=p.life/p.max;c.shadowColor=p.color;c.shadowBlur=30;for(let i=0;i<4;i++){c.strokeStyle=i%2?'rgba(255,255,255,.75)':p.color;c.lineWidth=18-i*4;c.beginPath();c.arc(0,0,p.r+i*5,-.78,.78);c.stroke()}c.restore();c.globalAlpha=1}function drawSwordWave(c,p){c.save();c.translate(p.x,p.y);c.rotate(p.a!==undefined?p.a:Math.atan2(p.vy,p.vx));let a=clamp(p.life/(p.max||.54),0,1),len=p.visualLen||120,w=p.visualWidth||16;c.globalAlpha=clamp(.25+a*.75,0,1);c.globalCompositeOperation='lighter';let g=c.createLinearGradient(-len*.45,0,len*.55,0);g.addColorStop(0,'rgba(255,211,106,0)');g.addColorStop(.18,'rgba(255,211,106,.46)');g.addColorStop(.55,'rgba(255,255,255,.92)');g.addColorStop(1,'rgba(255,211,106,0)');c.fillStyle=g;c.shadowColor=p.color;c.shadowBlur=28;c.beginPath();c.moveTo(len*.56,0);c.quadraticCurveTo(len*.12,-w*1.35,-len*.48,-w*.62);c.quadraticCurveTo(-len*.12,0,-len*.48,w*.62);c.quadraticCurveTo(len*.12,w*1.35,len*.56,0);c.closePath();c.fill();c.strokeStyle='rgba(255,255,255,.82)';c.lineWidth=Math.max(2,w*.18);c.beginPath();c.moveTo(-len*.35,0);c.lineTo(len*.52,0);c.stroke();c.restore();c.globalAlpha=1}function drawFlame(c,p){c.save();c.translate(player.x,player.y);c.rotate(p.a);for(let i=0;i<6;i++){c.globalAlpha=.16;c.fillStyle=i%2?'#ffd36a':p.color;c.shadowColor=p.color;c.shadowBlur=28;c.beginPath();c.moveTo(0,0);c.arc(0,0,p.r-rand(0,16),-p.arc+rand(-.08,.08),p.arc+rand(-.08,.08));c.closePath();c.fill()}c.restore();c.globalAlpha=1}function drawIceRing(c,p){c.globalAlpha=clamp(p.life/p.max,0,1);c.strokeStyle=p.color;c.shadowColor=p.color;c.shadowBlur=24;c.lineWidth=6;c.beginPath();c.arc(p.x,p.y,p.r,0,Math.PI*2);c.stroke();for(let i=0;i<18;i++){let a=i*Math.PI*2/18+stageTime;glowCircle(c,p.x+Math.cos(a)*p.r,p.y+Math.sin(a)*p.r,2.5,p.color)}c.globalAlpha=1;c.shadowBlur=0}function drawMeteor(c,p){let t=1-p.life/p.max;c.globalAlpha=.35;c.strokeStyle=p.color;c.lineWidth=3;c.beginPath();c.arc(p.x,p.y,p.impact*t,0,Math.PI*2);c.stroke();c.globalAlpha=1;drawComet(c,p.x-120*p.life,p.y-180*p.life,14+22*t,p.color)}function drawZone(c,p){c.globalAlpha=.24+.08*Math.sin(stageTime*8);c.fillStyle=p.color;c.shadowColor=p.color;c.shadowBlur=24;c.beginPath();c.arc(p.x,p.y,p.r,0,Math.PI*2);c.fill();c.strokeStyle='rgba(255,255,255,.35)';for(let i=0;i<7;i++){c.beginPath();c.arc(p.x,p.y,p.r*(i+1)/7,0,Math.PI*2);c.stroke()}c.globalAlpha=1;c.shadowBlur=0}function drawBlackhole(c,p){c.save();c.translate(p.x,p.y);c.rotate(stageTime*3);c.fillStyle='rgba(15,8,35,.95)';c.shadowColor=p.color;c.shadowBlur=36;c.beginPath();c.arc(0,0,p.r,0,Math.PI*2);c.fill();c.strokeStyle=p.color;c.lineWidth=3;for(let i=0;i<4;i++){c.beginPath();c.ellipse(0,0,p.r*(1.05+i*.18),p.r*(.42+i*.09),0,0,Math.PI*2);c.stroke()}c.restore()}function drawSpear(c,p){c.save();c.translate(p.x,p.y);c.rotate(Math.atan2(p.vy,p.vx));c.shadowColor=p.color;c.shadowBlur=24;c.strokeStyle=p.color;c.lineWidth=5;c.beginPath();c.moveTo(-30,0);c.lineTo(22,0);c.stroke();c.fillStyle='#fff';c.beginPath();c.moveTo(32,0);c.lineTo(12,-8);c.lineTo(12,8);c.closePath();c.fill();c.restore()}function drawBlade(c,p){c.save();c.translate(p.x,p.y);c.rotate((p.age||stageTime)*8);c.shadowColor=p.color;c.shadowBlur=22;c.fillStyle=p.color;c.beginPath();c.ellipse(0,0,22,8,0,0,Math.PI*2);c.fill();c.fillStyle='#fff';c.beginPath();c.ellipse(6,0,12,3,0,0,Math.PI*2);c.fill();c.restore()}function drawDagger(c,p){c.save();c.translate(p.x,p.y);c.rotate(Math.atan2(p.vy,p.vx));c.shadowColor=p.color;c.shadowBlur=18;c.fillStyle=p.color;c.beginPath();c.moveTo(18,0);c.lineTo(-10,-5);c.lineTo(-5,0);c.lineTo(-10,5);c.closePath();c.fill();c.restore()}function drawMissile(c,p){c.save();c.translate(p.x,p.y);c.rotate(Math.atan2(p.vy,p.vx));c.shadowColor=p.color;c.shadowBlur=20;c.fillStyle='#d7e6f1';c.beginPath();c.moveTo(16,0);c.lineTo(-10,-5);c.lineTo(-4,0);c.lineTo(-10,5);c.closePath();c.fill();let fg=c.createLinearGradient(-8,0,-26,0);fg.addColorStop(0,'rgba(255,255,255,.95)');fg.addColorStop(.4,'rgba(255,200,120,.8)');fg.addColorStop(1,'rgba(255,120,60,0)');c.fillStyle=fg;c.beginPath();c.moveTo(-8,0);c.lineTo(-24,-4);c.lineTo(-14,0);c.lineTo(-24,4);c.closePath();c.fill();c.restore()}function drawRail(c,p){c.globalAlpha=p.life/p.max;c.strokeStyle=p.color;c.shadowColor=p.color;c.shadowBlur=28;c.lineWidth=8;c.beginPath();c.moveTo(p.x1,p.y1);c.lineTo(p.x2,p.y2);c.stroke();c.strokeStyle='rgba(255,255,255,.9)';c.lineWidth=3;c.beginPath();c.moveTo(p.x1,p.y1);c.lineTo(p.x2,p.y2);c.stroke();c.globalAlpha=1;c.shadowBlur=0}function drawChain(c,p){c.globalAlpha=p.life/p.max;c.strokeStyle=p.color;c.shadowColor=p.color;c.shadowBlur=22;c.lineWidth=3;c.beginPath();for(let i=0;i<p.points.length;i++){if(i===0)c.moveTo(p.points[i].x,p.points[i].y);else c.lineTo(p.points[i].x+rand(-5,5),p.points[i].y+rand(-5,5))}c.stroke();c.globalAlpha=1;c.shadowBlur=0}function drawMine(c,p){c.save();c.translate(p.x,p.y);c.rotate(stageTime*2);c.shadowColor=p.color;c.shadowBlur=18;c.fillStyle='#29303e';c.beginPath();c.arc(0,0,p.r,0,Math.PI*2);c.fill();c.strokeStyle=p.color;c.lineWidth=2;for(let i=0;i<4;i++){c.beginPath();c.moveTo(0,0);c.lineTo(Math.cos(i*Math.PI/2)*18,Math.sin(i*Math.PI/2)*18);c.stroke()}c.restore()}function drawBeam(c,p){c.globalAlpha=p.life/p.max;let x2=p.x+Math.cos(p.a)*p.len,y2=p.y+Math.sin(p.a)*p.len;c.strokeStyle=p.color;c.shadowColor=p.color;c.shadowBlur=26;c.lineWidth=p.width;c.beginPath();c.moveTo(p.x,p.y);c.lineTo(x2,y2);c.stroke();c.strokeStyle='rgba(255,255,255,.75)';c.lineWidth=Math.max(3,p.width*.35);c.beginPath();c.moveTo(p.x,p.y);c.lineTo(x2,y2);c.stroke();c.globalAlpha=1;c.shadowBlur=0}
function dangerStroke(c){return settings.danger?'#ff2f4f':'rgba(255,80,90,.45)'}
function dangerWidth(v){return settings.danger?v:Math.max(1,v*.45)}
function drawEnemyFireball(c,p){c.save();c.translate(p.x,p.y);c.shadowColor=p.color;c.shadowBlur=24;let g=c.createRadialGradient(0,0,2,0,0,p.r);g.addColorStop(0,'#fff2b8');g.addColorStop(.45,'#ffb15d');g.addColorStop(1,p.color);c.fillStyle=g;c.beginPath();c.arc(0,0,p.r,0,Math.PI*2);c.fill();c.strokeStyle=dangerStroke(c);c.lineWidth=dangerWidth(3);c.shadowColor=dangerStroke(c);c.beginPath();c.arc(0,0,p.r+4,0,Math.PI*2);c.stroke();c.restore()}function drawEnemyIce(c,p){c.save();c.translate(p.x,p.y);c.rotate(Math.atan2(p.vy,p.vx));c.shadowColor=p.color;c.shadowBlur=18;c.fillStyle=p.color;c.beginPath();c.moveTo(16,0);c.lineTo(-10,-6);c.lineTo(-2,0);c.lineTo(-10,6);c.closePath();c.fill();c.strokeStyle=dangerStroke(c);c.lineWidth=dangerWidth(2.5);c.beginPath();c.ellipse(0,0,18,10,0,0,Math.PI*2);c.stroke();c.restore()}function drawEnemyOrb(c,p){c.save();c.translate(p.x,p.y);c.shadowColor=p.color;c.shadowBlur=26;c.fillStyle=p.color;c.beginPath();c.arc(0,0,p.r,0,Math.PI*2);c.fill();c.strokeStyle=dangerStroke(c);c.lineWidth=dangerWidth(3);c.beginPath();c.arc(0,0,p.r+5,0,Math.PI*2);c.stroke();c.restore()}function drawEnemyShockwave(c,p){c.globalAlpha=.18+.14*Math.sin(stageTime*16);c.fillStyle=p.color;c.beginPath();c.arc(p.x,p.y,p.r,0,Math.PI*2);c.fill();c.globalAlpha=1;c.strokeStyle=dangerStroke(c);c.shadowColor=dangerStroke(c);c.shadowBlur=settings.danger?20:8;c.lineWidth=dangerWidth(6);c.beginPath();c.arc(p.x,p.y,p.r+8,0,Math.PI*2);c.stroke();c.shadowBlur=0}function drawEnemyBeamWarn(c,p){let x2=p.x+Math.cos(p.a)*p.len,y2=p.y+Math.sin(p.a)*p.len;c.globalAlpha=.28+.22*Math.sin(stageTime*18);c.strokeStyle=dangerStroke(c);c.lineWidth=settings.danger?p.width*1.8:p.width*.8;c.beginPath();c.moveTo(p.x,p.y);c.lineTo(x2,y2);c.stroke();c.strokeStyle=p.color;c.lineWidth=p.width*.7;c.beginPath();c.moveTo(p.x,p.y);c.lineTo(x2,y2);c.stroke();c.globalAlpha=1}function drawEnemyBeam(c,p){let x2=p.x+Math.cos(p.a)*p.len,y2=p.y+Math.sin(p.a)*p.len;c.globalAlpha=p.life/p.max;c.strokeStyle=dangerStroke(c);c.shadowColor=dangerStroke(c);c.shadowBlur=settings.danger?30:10;c.lineWidth=settings.danger?p.width+12:p.width+3;c.beginPath();c.moveTo(p.x,p.y);c.lineTo(x2,y2);c.stroke();c.strokeStyle=p.color;c.lineWidth=p.width;c.beginPath();c.moveTo(p.x,p.y);c.lineTo(x2,y2);c.stroke();c.globalAlpha=1;c.shadowBlur=0}function drawEnemyBossNova(c,p){c.globalAlpha=.18;c.fillStyle=p.color;c.beginPath();c.arc(p.x,p.y,p.r,0,Math.PI*2);c.fill();c.globalAlpha=1;c.strokeStyle=dangerStroke(c);c.shadowColor=dangerStroke(c);c.shadowBlur=settings.danger?24:10;c.lineWidth=dangerWidth(9);c.beginPath();c.arc(p.x,p.y,p.r+8,0,Math.PI*2);c.stroke();c.shadowBlur=0}
function drawPickups(){for(const p of pickups){if(p.type==='heal'){ctx.save();ctx.translate(p.x,p.y);ctx.shadowColor='#ff5b73';ctx.shadowBlur=18;ctx.fillStyle='rgba(255,255,255,.92)';ctx.beginPath();ctx.arc(0,0,p.r,0,Math.PI*2);ctx.fill();ctx.fillStyle='#ff3355';ctx.fillRect(-3,-8,6,16);ctx.fillRect(-8,-3,16,6);ctx.restore()}else glowCircle(ctx,p.x,p.y,p.r,'#66f6ff')}}function drawParticles(){for(const p of particles){ctx.globalAlpha=clamp(p.life/p.max,0,1);ctx.fillStyle=p.color;ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fill();ctx.globalAlpha=1}for(const f of texts){ctx.globalAlpha=clamp(f.life/.6,0,1);ctx.fillStyle=f.color;ctx.font='bold 14px Segoe UI';ctx.fillText(f.text,f.x,f.y);ctx.globalAlpha=1}}function glowCircle(c,x,y,r,color){c.save();c.shadowColor=color;c.shadowBlur=22;c.fillStyle=color;c.beginPath();c.arc(x,y,r,0,Math.PI*2);c.fill();c.restore()}function drawPrism(c,x,y,r,col){c.save();c.translate(x,y);c.rotate(stageTime*3);c.shadowColor=col;c.shadowBlur=24;c.fillStyle=col;c.beginPath();c.moveTo(0,-r);c.lineTo(r,r);c.lineTo(-r,r);c.closePath();c.fill();c.restore()}function drawComet(c,x,y,r,col){c.save();c.shadowColor=col;c.shadowBlur=30;c.fillStyle=col;c.beginPath();c.arc(x,y,r,0,Math.PI*2);c.fill();c.strokeStyle='rgba(255,255,255,.65)';c.lineWidth=4;c.beginPath();c.moveTo(x-70,y-90);c.lineTo(x,y);c.stroke();c.restore()}function drawVignette(c,w,h){let g=c.createRadialGradient(w/2,h/2,Math.min(w,h)*.22,w/2,h/2,Math.max(w,h)*.72);g.addColorStop(0,'rgba(0,0,0,0)');g.addColorStop(1,'rgba(0,0,0,.58)');c.fillStyle=g;c.fillRect(0,0,w,h);let hpRatio=player?player.hp/player.maxHp:1;if(hpRatio<.32){let pulse=.18+.13*Math.sin(stageTime*8);let rg=c.createRadialGradient(w/2,h/2,Math.min(w,h)*.18,w/2,h/2,Math.max(w,h)*.7);rg.addColorStop(0,'rgba(255,0,60,0)');rg.addColorStop(1,`rgba(255,0,60,${pulse*(1-hpRatio/.32)})`);c.fillStyle=rg;c.fillRect(0,0,w,h)}c.save();c.globalAlpha=.055;c.fillStyle='#ffffff';for(let y=0;y<h;y+=4)c.fillRect(0,y,w,1);c.globalAlpha=.035;for(let i=0;i<90;i++){let x=Math.random()*w,y=Math.random()*h;c.fillRect(x,y,Math.random()*2+1,Math.random()*2+1)}c.restore();c.fillStyle='rgba(0,0,0,.16)';c.fillRect(0,0,w,10);c.fillRect(0,h-10,w,10)}
function drawSkillPreview(c,id,t,w,h){c.clearRect(0,0,w,h);let g=c.createRadialGradient(w/2,h/2,10,w/2,h/2,w*.65);g.addColorStop(0,'rgba(80,110,255,.16)');g.addColorStop(1,'rgba(4,7,18,.96)');c.fillStyle=g;c.fillRect(0,0,w,h);c.strokeStyle='rgba(120,170,255,.08)';for(let x=0;x<w;x+=26){c.beginPath();c.moveTo(x,0);c.lineTo(x,h);c.stroke()}for(let y=0;y<h;y+=26){c.beginPath();c.moveTo(0,y);c.lineTo(w,y);c.stroke()}c.save();c.translate(w/2,h/2);let col=(weaponDefs.find(x=>x.id===id)||{}).color||'#7ef7ff';let p={color:col,life:.5,max:1,x:0,y:0,r:36,a:0};if(id==='starSword'){drawShip(c,-88,0,0,false,false,.42);drawPreviewSwordWave(c,-28,0,118,0,'#ffd36a',t)}else if(id==='thunderLance'){drawShip(c,-85,0,0,false,false,.38);drawPreviewSpear(c,-20,0,0,'#66f6ff',t)}else if(id==='moonBlade'){drawShip(c,-70,0,0,false,false,.38);drawPreviewBlade(c,Math.sin(t*2)*55,0,'#8ee7ff',t)}else if(id==='frostRing'){drawShip(c,0,0,0,false,false,.36);drawPreviewRing(c,0,0,35+Math.sin(t*4)*22,'#b7f7ff')}else if(id==='holyPrism'){drawShip(c,0,0,0,false,false,.33);for(let i=0;i<3;i++){let a=t*2+i*Math.PI*2/3;drawPrism(c,Math.cos(a)*55,Math.sin(a)*34,9,'#fff3a3')}}else if(id==='shadowDagger'){drawShip(c,-76,0,0,false,false,.36);for(let i=0;i<3;i++)drawPreviewDagger(c,-10+i*38,Math.sin(t*5+i)*18,'#c493ff',0)}else if(id==='meteorStaff'){drawShip(c,-65,18,0,false,false,.34);drawComet(c,35-30*Math.sin(t*2),-30+55*((t*.8)%1),18,'#ff8b42');drawPreviewRing(c,40,30,28,'#ff8b42')}else if(id==='poisonVine'){drawPreviewZone(c,0,12,58,'#70ff8d');for(let i=0;i<5;i++)glowCircle(c,Math.sin(t*2+i)*40,Math.cos(t*1.4+i)*20+8,4,'#70ff8d')}else if(id==='dragonBreath'){drawShip(c,-84,0,0,false,false,.36);drawPreviewFlame(c,-45,0,'#ff5b42',t)}else if(id==='voidHole'){drawPreviewBlackhole(c,0,0,46,'#7a5cff',t);for(let i=0;i<4;i++)glowCircle(c,Math.cos(t+i)*70,Math.sin(t*1.2+i)*40,4,'#c7b0ff')}else if(id==='missilePod'){drawShip(c,-84,0,0,false,false,.36);for(let i=0;i<3;i++)drawPreviewMissile(c,-15+i*36,Math.sin(t*3+i)*18,'#ff9f7a',0)}else if(id==='railCannon'){drawShip(c,-82,0,0,false,false,.36);drawPreviewRail(c,-40,0,112,0,'#a9ecff')}else if(id==='arcEmitter'){let pts=[[-80,0],[-25,-22],[30,20],[85,-8]];drawPreviewChain(c,pts,'#8bd8ff',t)}else if(id==='mineLayer'){for(let i=0;i<3;i++)drawPreviewMine(c,-45+i*45,Math.sin(t*2+i)*20,'#ffe38a',t+i)}else if(id==='beamCore'){drawShip(c,-88,0,0,false,false,.36);drawPreviewBeam(c,-48,0,118,0,'#90fff0')}else drawPassivePreview(c,id,t);c.restore()}
function drawPreviewSlash(c,p){c.save();c.globalAlpha=.78;c.shadowColor=p.color;c.shadowBlur=24;for(let i=0;i<3;i++){c.strokeStyle=i%2?'rgba(255,255,255,.8)':p.color;c.lineWidth=14-i*4;c.beginPath();c.arc(0,0,p.r+i*5,-.78,.78);c.stroke()}c.restore()}function drawPreviewSpear(c,x,y,a,col,t){c.save();c.translate(x+((t*120)%130),y);c.rotate(a);c.shadowColor=col;c.shadowBlur=22;c.strokeStyle=col;c.lineWidth=5;c.beginPath();c.moveTo(-42,0);c.lineTo(22,0);c.stroke();c.fillStyle='#fff';c.beginPath();c.moveTo(35,0);c.lineTo(12,-8);c.lineTo(12,8);c.closePath();c.fill();c.restore()}function drawPreviewBlade(c,x,y,col,t){c.save();c.translate(x,y);c.rotate(t*8);c.shadowColor=col;c.shadowBlur=20;c.fillStyle=col;c.beginPath();c.ellipse(0,0,24,8,0,0,Math.PI*2);c.fill();c.fillStyle='#fff';c.beginPath();c.ellipse(7,0,12,3,0,0,Math.PI*2);c.fill();c.restore()}function drawPreviewRing(c,x,y,r,col){c.save();c.strokeStyle=col;c.shadowColor=col;c.shadowBlur=20;c.lineWidth=5;c.beginPath();c.arc(x,y,r,0,Math.PI*2);c.stroke();c.restore()}function drawPreviewDagger(c,x,y,col,a){c.save();c.translate(x,y);c.rotate(a);c.shadowColor=col;c.shadowBlur=16;c.fillStyle=col;c.beginPath();c.moveTo(18,0);c.lineTo(-10,-5);c.lineTo(-5,0);c.lineTo(-10,5);c.closePath();c.fill();c.restore()}function drawPreviewZone(c,x,y,r,col){c.save();c.globalAlpha=.35;c.fillStyle=col;c.shadowColor=col;c.shadowBlur=22;c.beginPath();c.arc(x,y,r,0,Math.PI*2);c.fill();c.globalAlpha=1;c.restore()}function drawPreviewFlame(c,x,y,col,t){c.save();c.translate(x,y);c.globalAlpha=.5;for(let i=0;i<4;i++){c.fillStyle=i%2?'#ffd36a':col;c.shadowColor=col;c.shadowBlur=22;c.beginPath();c.moveTo(0,0);c.arc(0,0,110-i*12,-.55-.05*Math.sin(t*5),.55+.05*Math.sin(t*5));c.closePath();c.fill()}c.globalAlpha=1;c.restore()}function drawPreviewBlackhole(c,x,y,r,col,t){c.save();c.translate(x,y);c.rotate(t*2);c.fillStyle='rgba(10,5,25,.95)';c.shadowColor=col;c.shadowBlur=30;c.beginPath();c.arc(0,0,r,0,Math.PI*2);c.fill();c.strokeStyle=col;c.lineWidth=3;for(let i=0;i<3;i++){c.beginPath();c.ellipse(0,0,r*(1+i*.22),r*(.45+i*.1),0,0,Math.PI*2);c.stroke()}c.restore()}function drawPreviewMissile(c,x,y,col,a){c.save();c.translate(x,y);c.rotate(a);c.shadowColor=col;c.shadowBlur=18;c.fillStyle='#d7e6f1';c.beginPath();c.moveTo(16,0);c.lineTo(-10,-5);c.lineTo(-4,0);c.lineTo(-10,5);c.closePath();c.fill();c.fillStyle=col;c.beginPath();c.moveTo(-8,0);c.lineTo(-24,-4);c.lineTo(-14,0);c.lineTo(-24,4);c.closePath();c.fill();c.restore()}function drawPreviewRail(c,x,y,len,a,col){c.save();c.translate(x,y);c.rotate(a);c.strokeStyle=col;c.shadowColor=col;c.shadowBlur=26;c.lineWidth=9;c.beginPath();c.moveTo(0,0);c.lineTo(len,0);c.stroke();c.strokeStyle='#fff';c.lineWidth=3;c.beginPath();c.moveTo(0,0);c.lineTo(len,0);c.stroke();c.restore()}function drawPreviewSwordWave(c,x,y,len,a,col,t){c.save();c.translate(x,y);c.rotate(a);c.globalCompositeOperation='lighter';let w=18+Math.sin((t||0)*6)*2,g=c.createLinearGradient(-len*.35,0,len*.6,0);g.addColorStop(0,'rgba(255,211,106,0)');g.addColorStop(.25,'rgba(255,211,106,.5)');g.addColorStop(.58,'rgba(255,255,255,.9)');g.addColorStop(1,'rgba(255,211,106,0)');c.fillStyle=g;c.shadowColor=col;c.shadowBlur=24;c.beginPath();c.moveTo(len*.62,0);c.quadraticCurveTo(len*.15,-w,-len*.36,-w*.45);c.quadraticCurveTo(-len*.08,0,-len*.36,w*.45);c.quadraticCurveTo(len*.15,w,len*.62,0);c.closePath();c.fill();c.strokeStyle='rgba(255,255,255,.85)';c.lineWidth=3;c.beginPath();c.moveTo(-len*.28,0);c.lineTo(len*.55,0);c.stroke();c.restore()}function drawPreviewBeam(c,x,y,len,a,col){c.save();c.translate(x,y);c.rotate(a);c.strokeStyle=col;c.shadowColor=col;c.shadowBlur=28;c.lineWidth=18;c.beginPath();c.moveTo(0,0);c.lineTo(len,0);c.stroke();c.strokeStyle='rgba(255,255,255,.85)';c.lineWidth=6;c.beginPath();c.moveTo(0,0);c.lineTo(len,0);c.stroke();c.restore()}function drawPreviewChain(c,pts,col,t){c.save();c.strokeStyle=col;c.shadowColor=col;c.shadowBlur=22;c.lineWidth=4;c.beginPath();for(let i=0;i<pts.length;i++){let x=pts[i][0]+Math.sin(t*10+i)*3,y=pts[i][1]+Math.cos(t*9+i)*3;if(i===0)c.moveTo(x,y);else c.lineTo(x,y)}c.stroke();for(const p of pts)glowCircle(c,p[0],p[1],6,col);c.restore()}function drawPreviewMine(c,x,y,col,t){c.save();c.translate(x,y);c.rotate(t*2);c.shadowColor=col;c.shadowBlur=18;c.fillStyle='#29303e';c.beginPath();c.arc(0,0,15,0,Math.PI*2);c.fill();c.strokeStyle=col;c.lineWidth=3;for(let i=0;i<4;i++){c.beginPath();c.moveTo(0,0);c.lineTo(Math.cos(i*Math.PI/2)*23,Math.sin(i*Math.PI/2)*23);c.stroke()}c.restore()}function drawPassivePreview(c,id,t){let col='#7ef7ff';if(id==='hullPlating'){col='#83c7ff';drawPreviewRing(c,0,0,48,col);drawShip(c,0,0,0,false,false,.45)}else if(id==='reactorBoost'){col='#ffd36a';glowCircle(c,0,0,20,col);drawPreviewRing(c,0,0,42+Math.sin(t*4)*8,col)}else if(id==='overclockCore'||id==='coolingLoop'){col=id==='overclockCore'?'#8bd8ff':'#b7f7ff';c.save();c.rotate(t*3);drawPreviewMine(c,0,0,col,t);c.restore()}else if(id==='ionThrusters'||id==='boostCell'){drawShip(c,-20,0,0,true,false,.42);for(let i=0;i<3;i++)drawPreviewSpear(c,-70+i*12,-18+i*18,0,'#7ef7ff',t+i)}else if(id==='expandedMagnet'){col='#7ef7ff';drawPreviewBlackhole(c,0,0,28,col,t);for(let i=0;i<5;i++)glowCircle(c,Math.cos(t+i)*65,Math.sin(t+i)*38,4,'#66f6ff')}else if(id==='targetingAI'){col='#ff8cff';drawPreviewRing(c,0,0,42+Math.sin(t*4)*4,col);c.strokeStyle=col;c.beginPath();c.moveTo(-60,0);c.lineTo(60,0);c.moveTo(0,-50);c.lineTo(0,50);c.stroke()}else if(id==='warheadArray'){for(let i=0;i<4;i++)drawPreviewMissile(c,-65+i*34,-20+i*13,'#ff9f7a',0)}else if(id==='nanoRepair'){col='#77ff9a';c.fillStyle=col;c.shadowColor=col;c.shadowBlur=20;c.fillRect(-7,-28,14,56);c.fillRect(-28,-7,56,14);drawPreviewRing(c,0,0,42+Math.sin(t*4)*8,col)}else if(id==='fieldAmplifier'){drawPreviewRing(c,0,0,30+Math.sin(t*4)*8,'#c493ff');drawPreviewRing(c,0,0,58+Math.sin(t*4)*8,'#c493ff')}else if(id==='acceleratorRails'){for(let i=0;i<3;i++)drawPreviewSpear(c,-75,-22+i*22,0,'#a9ecff',t+i)}}function renderPreviewCanvases(){document.querySelectorAll('.previewCanvas').forEach(cv=>{let c=cv.getContext('2d'),id=cv.dataset.preview,t=performance.now()/1000;drawSkillPreview(c,id,t,cv.width,cv.height)});requestAnimationFrame(renderPreviewCanvases)}
function fmt(t){let m=Math.floor(t/60),s=Math.floor(t%60);return`${m}:${String(s).padStart(2,'0')}`}function loop(now){let dt=Math.min(.033,(now-last)/1000||0);last=now;update(dt);draw();requestAnimationFrame(loop)}

const RARITY_ORDER=['common','uncommon','rare','epic','legendary'];
const RARITIES={common:{id:'common',tier:'白',name:'普通',rank:0,color:'#f4f7ff'},uncommon:{id:'uncommon',tier:'绿',name:'优秀',rank:1,color:'#67f28f'},rare:{id:'rare',tier:'蓝',name:'稀有',rank:2,color:'#62b8ff'},epic:{id:'epic',tier:'紫',name:'史诗',rank:3,color:'#c58cff'},legendary:{id:'legendary',tier:'金',name:'传说',rank:4,color:'#ffd36a'}};
const BUILD_TAGS=['输出','机动','生存','资源'];
const WEAPON_BUILD_META={starSword:{rarity:'common',build:'直线剑气'},thunderLance:{rarity:'common',build:'电磁弹道'},moonBlade:{rarity:'uncommon',build:'回旋弹幕'},frostRing:{rarity:'uncommon',build:'控场范围'},holyPrism:{rarity:'rare',build:'环绕棱镜'},shadowDagger:{rarity:'rare',build:'追踪弹幕'},meteorStaff:{rarity:'epic',build:'爆破范围'},poisonVine:{rarity:'uncommon',build:'持续法阵'},dragonBreath:{rarity:'rare',build:'扇形喷射'},voidHole:{rarity:'epic',build:'牵引奇点'},missilePod:{rarity:'uncommon',build:'追踪爆破'},railCannon:{rarity:'rare',build:'贯穿狙击'},arcEmitter:{rarity:'rare',build:'连锁电弧'},mineLayer:{rarity:'uncommon',build:'陷阱爆破'},beamCore:{rarity:'rare',build:'引导光束'}};
for(const w of weaponDefs)Object.assign(w,WEAPON_BUILD_META[w.id]||{rarity:'common',build:'武器核心'});
const EXTRA_BUILD_SKILLS=[
{id:'emberCatalyst',name:'余烬催化',tag:'输出',rarity:'uncommon',max:5,desc:'非持续命中有 8% 施加燃烧，持续造成伤害。',apply:p=>{p.burnChance=(p.burnChance||0)+.08;p.burnDps=(p.burnDps||0)+7}},
{id:'executionLens',name:'处决透镜',tag:'输出',rarity:'rare',max:4,desc:'对生命低于 35% 的敌人伤害 +18%，Boss 半效。',apply:p=>{p.executeMul=(p.executeMul||1)*1.18;p.bossMul=(p.bossMul||1)*1.04}},
{id:'stormRelay',name:'风暴继电器',tag:'输出',rarity:'epic',max:3,requires:p=>hasAnyWeapon(['thunderLance','arcEmitter','railCannon','beamCore']),desc:'非持续命中有 12% 向附近敌人跳电。',apply:p=>{p.arcChance=(p.arcChance||0)+.12}},
{id:'criticalOverload',name:'暴击过载',tag:'输出',rarity:'epic',max:3,desc:'命中会按暴击率触发小型爆炸，适合高暴击构筑。',apply:p=>{p.critSplash=(p.critSplash||0)+.45}},
{id:'phaseCapacitor',name:'相位电容',tag:'机动',rarity:'rare',max:3,desc:'闪避后 1.2 秒内武器伤害 +18%。',apply:p=>{p.phaseDamage=(p.phaseDamage||0)+.18}},
{id:'scrapHarvester',name:'残骸回收',tag:'资源',rarity:'uncommon',max:5,desc:'经验收益 +12%，精英额外更容易掉落补给。',apply:p=>{p.xpMul=(p.xpMul||1)*1.12;p.eliteDrop=(p.eliteDrop||0)+.06}},
{id:'repairSpoils',name:'战场整备',tag:'生存',rarity:'rare',max:4,desc:'击杀回复少量生命，精英和 Boss 回复更多。',apply:p=>{p.onKillHeal=(p.onKillHeal||0)+1.2}},
{id:'aegisBattery',name:'宙盾电池',tag:'生存',rarity:'epic',max:2,desc:'生命低于 40% 时获得额外 18% 伤害减免。',apply:p=>{p.lowHpGuard=(p.lowHpGuard||0)+.18}},
{id:'bloodReactor',name:'血色反应堆',tag:'生存',rarity:'epic',max:2,desc:'生命低于 45% 时武器伤害 +16%，击杀回复翻倍。',apply:p=>{p.lowHpDamage=(p.lowHpDamage||0)+.16;p.lowHpLeech=(p.lowHpLeech||0)+1}},
{id:'prismProtocol',name:'棱镜协议',tag:'输出',rarity:'rare',max:3,requires:p=>hasAnyWeapon(['holyPrism','beamCore','railCannon']),desc:'光束、棱镜、轨道炮构筑更稳定，暴击率 +5%。',apply:p=>{p.crit+=.05;p.prismBonus=(p.prismBonus||0)+.05}},
{id:'singularityForge',name:'奇点熔炉',tag:'输出',rarity:'legendary',max:1,requires:p=>p.level>=7&&hasAnyWeapon(['voidHole','meteorStaff','poisonVine']),desc:'击杀有概率引爆小型奇点，范围类武器半径 +10%。',apply:p=>{p.killNova=(p.killNova||0)+.18;p.areaMul*=1.1}},
{id:'goldenCore',name:'黄金核心',tag:'资源',rarity:'legendary',max:1,requires:p=>p.level>=8&&Object.keys(p.weapons).length>=4,desc:'每拥有一种武器都会提高伤害，并提升蓝紫金卡出现率。',apply:p=>{p.goldCore=true;p.damageMul*=1+Object.keys(p.weapons).length*.03}}
];
for(const s of EXTRA_BUILD_SKILLS)if(!skillDefs.some(x=>x.id===s.id))skillDefs.push(s);
function hasAnyWeapon(ids){return ids.some(id=>player&&player.weapons&&player.weapons[id])}
function maxWeaponLevel(){return player?Math.max(0,...Object.values(player.weapons).map(w=>w.level)):0}
function rarityInfo(id){return RARITIES[id]||RARITIES.common}
function rarityRank(id){return rarityInfo(id).rank}
function maxRarity(a,b){return rarityRank(a)>=rarityRank(b)?a:b}
function weaponLevelRarity(lv){return lv>=5?'legendary':lv>=4?'epic':lv>=3?'rare':lv>=2?'uncommon':'common'}
function inferChoiceRarity(c){if(c.rarity)return c.rarity;if(c.kind==='weapon'){let w=weaponDefs.find(x=>x.id===c.id),held=player&&player.weapons&&player.weapons[c.id],next=held?held.level+1:1;return maxRarity(w&&w.rarity||'common',weaponLevelRarity(next))}let s=skillDefs.find(x=>x.id===c.id),lv=player&&player.skills?player.skills[c.id]||0:0,base=s&&s.rarity||'common';if(lv>=5)base=maxRarity(base,'epic');else if(lv>=3)base=maxRarity(base,'rare');else if(lv>=1)base=maxRarity(base,'uncommon');return base}
function rarityLegendHTML(){return`<div class="rarityLegend">${RARITY_ORDER.map(id=>{let r=rarityInfo(id);return`<span style="--rarity:${r.color}"><i></i>${r.tier}${r.name}</span>`}).join('')}</div>`}
function buildTagCount(tag){let n=0;if(!player||!player.skills)return n;for(const id in player.skills){let s=skillDefs.find(x=>x.id===id);if(s&&s.tag===tag)n+=player.skills[id]}return n}
function buildTagSummary(){return BUILD_TAGS.map(t=>`${t}${buildTagCount(t)}`).join(' / ')}
function activeBuildLines(){let out=buildTagCount('输出'),mob=buildTagCount('机动'),surv=buildTagCount('生存'),res=buildTagCount('资源'),wc=player?Object.keys(player.weapons).length:0,mx=maxWeaponLevel();return[
{active:out>=3,text:`输出 ${out}/3：全伤害 +8%`},{active:out>=6,text:`输出 ${out}/6：暴击 +6%，过载概率提高`},
{active:mob>=2,text:`机动 ${mob}/2：移速 +10`},{active:mob>=4,text:`机动 ${mob}/4：闪避更快，相位伤害提高`},
{active:surv>=2,text:`生存 ${surv}/2：最大生命 +18`},{active:surv>=4,text:`生存 ${surv}/4：低血减伤提高`},
{active:res>=2,text:`资源 ${res}/2：拾取范围 +15%`},{active:res>=4,text:`资源 ${res}/4：经验收益 +12%，稀有保底推进`},
{active:wc>=4,text:`武库 ${wc}/4：全武器冷却 -4%`},{active:mx>=5,text:`满级武器 Lv.${mx}/5：全伤害 +10%`}
]}
function unlockBuildBonus(key,text,fn){if(!player.build.unlocked[key]){player.build.unlocked[key]=true;fn();message('构筑共鸣：'+text);playSfx('level')}}
function syncBuildBonuses(){if(!player)return;if(!player.build)player.build={picks:0,rarityPity:0,lastRarity:'common',unlocked:{}};let out=buildTagCount('输出'),mob=buildTagCount('机动'),surv=buildTagCount('生存'),res=buildTagCount('资源'),wc=Object.keys(player.weapons).length,mx=maxWeaponLevel();if(out>=3)unlockBuildBonus('out3','输出 3 件',()=>{player.damageMul*=1.08});if(out>=6)unlockBuildBonus('out6','输出 6 件',()=>{player.crit+=.06;player.critSplash=(player.critSplash||0)+.15});if(mob>=2)unlockBuildBonus('mob2','机动 2 件',()=>{player.speed+=10});if(mob>=4)unlockBuildBonus('mob4','机动 4 件',()=>{player.dashMax=Math.max(.55,player.dashMax-.08);player.phaseDamage=(player.phaseDamage||0)+.08});if(surv>=2)unlockBuildBonus('surv2','生存 2 件',()=>{player.maxHp+=18;player.hp=clamp(player.hp+18,0,player.maxHp)});if(surv>=4)unlockBuildBonus('surv4','生存 4 件',()=>{player.lowHpGuard=(player.lowHpGuard||0)+.12});if(res>=2)unlockBuildBonus('res2','资源 2 件',()=>{player.pickupMul*=1.15});if(res>=4)unlockBuildBonus('res4','资源 4 件',()=>{player.xpMul=(player.xpMul||1)*1.12;player.build.rarityPity=Math.max(player.build.rarityPity,2)});if(wc>=4)unlockBuildBonus('weapon4','武库 4 件',()=>{player.cdMul*=.96});if(mx>=5)unlockBuildBonus('weapon5','武器满级',()=>{player.damageMul*=1.1})}
function recordRarityPick(id){if(!player||!player.build)return;let rank=rarityRank(id);player.build.picks++;player.build.lastRarity=id;player.build.rarityPity=rank>=2?0:Math.min(6,player.build.rarityPity+1)}
function choiceWeight(c){let rank=rarityRank(c.rarity),base=[76,42,18,7,2.5][rank],lvl=player?player.level:1,pity=player&&player.build?player.build.rarityPity:0;if(rank>=2)base*=1+Math.max(0,lvl-3)*.09+pity*.35;if(rank>=3&&lvl<5)base*=.25;if(rank>=4&&lvl<8)base*=.14;if(player&&player.goldCore&&rank>=2)base*=1.45;if(c.kind==='weapon')base*=player.weapons[c.id]?1.2:(Object.keys(player.weapons).length<4?1.28:.72);let s=skillDefs.find(x=>x.id===c.id);if(s&&s.tag&&buildTagCount(s.tag)>=2)base*=1.24;if(s&&s.max&&(player.skills[s.id]||0)>=s.max)base=0;return base}
function weightedChoices(pool,count){let picks=[],copy=pool.slice();for(let n=0;n<count&&copy.length;n++){let total=copy.reduce((a,c)=>a+choiceWeight(c),0);if(total<=0)break;let roll=rand(0,total),idx=0;for(;idx<copy.length;idx++){roll-=choiceWeight(copy[idx]);if(roll<=0)break}picks.push(copy[idx]);copy.splice(idx,1)}if(picks.length<count){for(const c of shuffle(pool))if(!picks.includes(c)&&picks.length<count)picks.push(c)}return picks.sort((a,b)=>rarityRank(a.rarity)-rarityRank(b.rarity))}
buildUpgradeChoices=function(){let pool=[];for(const w of weaponDefs){if(!player.weapons[w.id])pool.push({kind:'weapon',id:w.id,title:`获得 ${w.name}`,desc:w.desc,tag:`新武器 · ${w.build}`,rarity:inferChoiceRarity({kind:'weapon',id:w.id})});else if(player.weapons[w.id].level<5){let next=player.weapons[w.id].level+1;pool.push({kind:'weapon',id:w.id,title:`强化 ${w.name} Lv.${next}`,desc:`提升 ${w.name} 的伤害、范围、数量或触发效率。高等级会提升卡牌稀有度。`,tag:`${w.build} · Lv.${next}`,rarity:inferChoiceRarity({kind:'weapon',id:w.id})})}}for(const s of skillDefs){let lv=player.skills[s.id]||0;if(s.max&&lv>=s.max)continue;if(s.requires&&!s.requires(player))continue;let c={kind:'skill',id:s.id,title:s.name+(lv?` Lv.${lv+1}`:''),desc:s.desc,tag:s.max?`${s.tag} · ${lv}/${s.max}`:s.tag};c.rarity=inferChoiceRarity(c);pool.push(c)}return weightedChoices(pool,3)}
function buildChoiceHint(c){let r=rarityInfo(c.rarity);if(c.kind==='weapon'){let w=weaponDefs.find(x=>x.id===c.id),held=player&&player.weapons&&player.weapons[c.id];return held?`当前 Lv.${held.level}，继续投入会推进到更高稀有度。`:`${w.build} 入库，适合围绕同类武器继续加深。`}let s=skillDefs.find(x=>x.id===c.id),count=s?buildTagCount(s.tag):0;return`${s?s.tag:'构筑'} 当前 ${count} 层。稀有度：${r.tier}${r.name}。`}
buildChoiceCard=function(c,onPick){let r=rarityInfo(c.rarity||inferChoiceRarity(c)),div=document.createElement('div');div.className=`card rarity-${r.id}`;div.innerHTML=`<div class="rarityRibbon"><span>${r.tier}</span><b>${r.name}</b></div>${buildPreviewHTML(c.id)}<h3>${c.title}</h3><p>${c.desc}</p><div class="cardMeta"><span class="tag">${c.tag}</span><span class="buildTag">${r.tier}${r.name}</span></div><div class="choiceFooter">${buildChoiceHint(c)}</div>`;div.onclick=()=>{if(!c.noRarityTrack)recordRarityPick(r.id);onPick()};return div}
showStartingWeaponSelect=function(){choosingStart=true;startPickCount=0;const overlay=document.getElementById('levelOverlay'),cards=document.getElementById('cards'),title=overlay.querySelector('h1'),sub=overlay.querySelector('.subtitle');title.textContent='选择初始武器';sub.innerHTML='开局前自选两个武器。武器也带有初始稀有度，后续强化会逐步推高卡牌品质。'+rarityLegendHTML();cards.innerHTML='';weaponDefs.slice().sort((a,b)=>rarityRank(a.rarity)-rarityRank(b.rarity)).forEach(w=>{const div=buildChoiceCard({id:w.id,title:w.name,desc:w.desc,tag:`初始武器 · ${w.build}`,rarity:w.rarity,kind:'weapon',noRarityTrack:true},()=>{if(player.weapons[w.id]||!choosingStart)return;addWeapon(w.id);startPickCount++;div.style.opacity=.45;div.style.pointerEvents='none';div.querySelector('.tag').textContent='已选择';if(startPickCount>=2){choosingStart=false;overlay.style.display='none';title.textContent='星舰改装';sub.textContent='选择一项升级。';paused=false;clearKeys();message('第 1 关开始')}});cards.appendChild(div)});overlay.style.display='flex'}
levelUp=function(){paused=true;const overlay=document.getElementById('levelOverlay');overlay.querySelector('h1').textContent='星舰改装';overlay.querySelector('.subtitle').innerHTML='选择一项升级。卡牌按白、绿、蓝、紫、金排序；同类标签会激活构筑共鸣。'+rarityLegendHTML();const cards=document.getElementById('cards');cards.innerHTML='';buildUpgradeChoices().forEach(c=>{const div=buildChoiceCard(c,()=>{if(c.kind==='weapon')addWeapon(c.id);else applySkill(c.id);syncBuildBonuses();overlay.style.display='none';paused=false;clearKeys();updateUI()});cards.appendChild(div)});overlay.style.display='flex'}
const __baseFreshPlayer=freshPlayer;freshPlayer=function(){let p=__baseFreshPlayer();p.build={picks:0,rarityPity:0,lastRarity:'common',unlocked:{}};p.xpMul=1;p.executeMul=1;p.bossMul=1;p.burnChance=0;p.burnDps=0;p.arcChance=0;p.critSplash=0;p.phaseDamage=0;p.phaseOverload=0;p.onKillHeal=0;p.eliteDrop=0;p.lowHpGuard=0;p.lowHpDamage=0;p.lowHpLeech=0;p.killNova=0;p.goldCore=false;return p};
