const __baseDamagePlayer=damagePlayer;damagePlayer=function(d){if(player&&player.lowHpGuard&&player.hp/player.maxHp<.4)d*=Math.max(.45,1-player.lowHpGuard);__baseDamagePlayer(d)};
const __baseKillEnemy=killEnemy;killEnemy=function(e,color){if(e.dead)return;let x=e.x,y=e.y,elite=e.elite,boss=e.def.boss;__baseKillEnemy(e,color);if(player&&player.onKillHeal){let heal=player.onKillHeal*(boss?8:elite?3:1)*(player.hp/player.maxHp<.45?1+(player.lowHpLeech||0):1);player.hp=clamp(player.hp+heal,0,player.maxHp);if(settings.damageNumbers&&heal>=3)texts.push({x,y:y-36,text:'+'+Math.ceil(heal),life:.7,color:'#77ff9a'})}if(player&&player.eliteDrop&&elite&&Math.random()<player.eliteDrop)pickups.push({type:'heal',x:x+rand(-14,14),y:y+rand(-14,14),r:10,val:12});if(player&&player.killNova&&Math.random()<player.killNova)explode(x,y,92+stage*3,20+stage*3,'#ffd36a')};
function applyBurn(e,dps,duration,color){let cur=e.burn||{dps:0,life:0,tick:.35,color};let tick=cur.tick===undefined ? .35 : cur.tick;e.burn={dps:Math.min(cur.dps+dps,90+stage*8),life:Math.max(cur.life,duration),tick:Math.min(tick,.25),color:color||'#ff8b42'}}
function tickBuildStatuses(dt){for(const e of enemies){if(e.dead||!e.burn)continue;e.burn.life-=dt;e.burn.tick-=dt;if(e.burn.tick<=0){e.burn.tick=.35;__baseHitEnemy(e,e.burn.dps*.35,e.burn.color,true);if(settings.damageNumbers&&Math.random()<.32)texts.push({x:e.x,y:e.y-24,text:'燃',life:.45,color:'#ff8b42'})}if(e.burn.life<=0)e.burn=null}}
function arcJump(origin,dmg,color){let points=[{x:origin.x,y:origin.y}],used=[origin],cur=origin,jumps=1+Math.floor((player.arcChance||0)*5);for(let i=0;i<jumps;i++){let next=null,b=99999;for(const e of enemies){if(e.dead||used.includes(e))continue;let d=Math.hypot(e.x-cur.x,e.y-cur.y);if(d<220&&d<b){b=d;next=e}}if(!next)break;used.push(next);points.push({x:next.x,y:next.y});__baseHitEnemy(next,dmg*(.46-i*.07),'#8bd8ff');cur=next}if(points.length>1)projectiles.push({type:'chain',points,life:.18,max:.18,color:'#8bd8ff'})}
const __baseHitEnemy=hitEnemy;let __buildProcDepth=0;hitEnemy=function(e,dmg,color,dot=false){if(e.dead)return;if(!dot&&player){if(e.def&&e.def.boss)dmg*=player.bossMul||1;if(e.hp/e.maxHp<.35)dmg*=e.def&&e.def.boss?1+((player.executeMul||1)-1)*.5:player.executeMul||1;if(player.lowHpDamage&&player.hp/player.maxHp<.45)dmg*=1+player.lowHpDamage;if(player.phaseOverload>0)dmg*=1+(player.phaseDamage||0);if(player.goldCore)dmg*=1+Math.min(Object.keys(player.weapons).length*.01,.08)}let canProc=!dot&&__buildProcDepth<1;__baseHitEnemy(e,dmg,color,dot);if(canProc&&!e.dead&&player){__buildProcDepth++;if(player.burnChance&&Math.random()<player.burnChance)applyBurn(e,player.burnDps||6,2.4,color);if(player.arcChance&&Math.random()<player.arcChance)arcJump(e,dmg*.38,color);let splashChance=Math.min(.36,(player.crit||0)*.75+(player.critSplash||0)*.08);if(player.critSplash&&Math.random()<splashChance)explode(e.x,e.y,54+player.critSplash*8,dmg*.34,'#ffd36a');__buildProcDepth--}};
const __baseUpdateEnemies=updateEnemies;updateEnemies=function(dt){tickBuildStatuses(dt);__baseUpdateEnemies(dt)};
const __baseUpdatePlayer=updatePlayer;updatePlayer=function(dt){let was=player&&player.dashTime>0;__baseUpdatePlayer(dt);if(player&&player.phaseDamage){if(!was&&player.dashTime>0)player.phaseOverload=1.2;player.phaseOverload=Math.max(0,(player.phaseOverload||0)-dt)}};
const __baseUpdateUI=updateUI;updateUI=function(){__baseUpdateUI();if(!player||!player.build)return;document.getElementById('stats').insertAdjacentHTML('beforeend',`<div>构筑：${buildTagSummary()}</div><div>稀有保底：${player.build.rarityPity}</div>`);let lines=activeBuildLines().map(l=>`<div class="buildLine ${l.active?'active':''}"><span class="buildDot"></span>${l.text}</div>`).join('');document.getElementById('weapons').innerHTML+=`<div class="buildBlock"><div class="buildLine active"><span class="buildDot"></span>构筑共鸣</div>${lines}</div>`};
const __baseDrawPassivePreview=drawPassivePreview;drawPassivePreview=function(c,id,t){if(id==='emberCatalyst'||id==='bloodReactor'){drawPreviewFlame(c,-52,0,'#ff8b42',t);drawPreviewRing(c,26,0,36+Math.sin(t*4)*7,'#ff5b42')}else if(id==='executionLens'||id==='criticalOverload'){drawPreviewRing(c,0,0,52,'#ffd36a');c.strokeStyle='#ffd36a';c.lineWidth=3;c.beginPath();c.moveTo(-62,0);c.lineTo(62,0);c.moveTo(0,-52);c.lineTo(0,52);c.stroke();if(id==='criticalOverload')drawPreviewRing(c,0,0,22+Math.sin(t*8)*8,'#ff8b42')}else if(id==='stormRelay'){drawPreviewChain(c,[[-75,0],[-28,-25],[20,18],[78,-8]],'#8bd8ff',t)}else if(id==='phaseCapacitor'){drawShip(c,-28,0,0,true,false,.42);drawPreviewRing(c,0,0,54+Math.sin(t*5)*8,'#7ef7ff')}else if(id==='scrapHarvester'){drawPreviewBlackhole(c,0,0,28,'#67f28f',t);for(let i=0;i<7;i++)glowCircle(c,Math.cos(t+i)*62,Math.sin(t*1.3+i)*35,4,'#66f6ff')}else if(id==='repairSpoils'||id==='aegisBattery'){let col=id==='repairSpoils'?'#77ff9a':'#9eeeff';c.fillStyle=col;c.shadowColor=col;c.shadowBlur=18;c.fillRect(-7,-28,14,56);c.fillRect(-28,-7,56,14);drawPreviewRing(c,0,0,48+Math.sin(t*4)*7,col)}else if(id==='prismProtocol'||id==='goldenCore'){let col=id==='goldenCore'?'#ffd36a':'#fff3a3';glowCircle(c,0,0,20,col);for(let i=0;i<4;i++)drawPreviewRing(c,0,0,28+i*12+Math.sin(t*3+i)*4,col)}else if(id==='singularityForge'){drawPreviewBlackhole(c,0,0,48,'#ffd36a',t);drawPreviewRing(c,0,0,70,'#ff8b42')}else __baseDrawPassivePreview(c,id,t)};
/* === User request patch: random 6 starting weapons + boss golden reward === */
let __bossRewardClaimedStage = 0;
let __bossRewardChoiceOpen = false;

function __eligibleSkillChoices(){
  const pool=[];
  for(const s of skillDefs){
    const lv=player&&player.skills?player.skills[s.id]||0:0;
    if(s.max&&lv>=s.max)continue;
    if(s.requires&&!s.requires(player))continue;
    const c={kind:'skill',id:s.id,title:s.name+(lv?` Lv.${lv+1}`:''),desc:s.desc,tag:s.max?`${s.tag} · ${lv}/${s.max}`:s.tag};
    c.rarity=inferChoiceRarity(c);
    pool.push(c);
  }
  return pool;
}

function __cloneChoice(c){return Object.assign({},c)}

function buildBossRewardChoices(){
  const pool=__eligibleSkillChoices();
  if(!pool.length)return buildUpgradeChoices();
  const legendaryPool=pool.filter(c=>rarityRank(c.rarity)>=4);
  let guaranteed=__cloneChoice(legendaryPool.length?shuffle(legendaryPool)[0]:weightedChoices(pool,1)[0]||shuffle(pool)[0]);
  guaranteed.rarity='legendary';
  guaranteed.title=(rarityRank((legendaryPool[0]&&guaranteed.rarity)||guaranteed.rarity)>=4?'':'')+guaranteed.title.replace(/^|^/,'');
  guaranteed.tag='Boss 奖励 · '+guaranteed.tag;
  guaranteed.desc=guaranteed.desc+'\nBoss 奖励保底金卡。';
  const restPool=pool.filter(c=>c.id!==guaranteed.id);
  const rest=weightedChoices(restPool,2).map(__cloneChoice);
  const picked=[guaranteed,...rest];
  while(picked.length<3){
    const extra=shuffle(pool).find(c=>!picked.some(p=>p.id===c.id))||pool[0];
    if(!extra)break;
    picked.push(__cloneChoice(extra));
  }
  return picked.slice(0,3).sort((a,b)=>rarityRank(a.rarity)-rarityRank(b.rarity));
}

function showBossRewardSelect(){
  if(!player||gameOver||__bossRewardChoiceOpen)return;
  __bossRewardChoiceOpen=true;
  __bossRewardClaimedStage=stage;
  paused=true;
  const overlay=document.getElementById('levelOverlay'),cards=document.getElementById('cards'),title=overlay.querySelector('h1'),sub=overlay.querySelector('.subtitle');
  title.textContent='Boss 战利品';
  sub.innerHTML='击杀 Boss 后获得一次技能选择，本次至少出现一张金色卡牌。'+rarityLegendHTML();
  cards.innerHTML='';
  buildBossRewardChoices().forEach(c=>{
    const div=buildChoiceCard(c,()=>{
      applySkill(c.id);
      syncBuildBonuses();
      overlay.style.display='none';
      __bossRewardChoiceOpen=false;
      paused=false;
      clearKeys();
      updateUI();
      message('Boss 战利品已装备');
    });
    cards.appendChild(div);
  });
  overlay.style.display='flex';
  playSfx('level');
}

showStartingWeaponSelect=function(){
  choosingStart=true;
  startPickCount=0;
  const overlay=document.getElementById('levelOverlay'),cards=document.getElementById('cards'),title=overlay.querySelector('h1'),sub=overlay.querySelector('.subtitle');
  title.textContent='选择初始武器';
  sub.innerHTML='开局随机出现 6 个 Lv.1 初始武器，全部按最低等级开始。请选择其中两个。'+rarityLegendHTML();
  cards.innerHTML='';
  shuffle(weaponDefs).slice(0,6).forEach(w=>{
    const div=buildChoiceCard({id:w.id,title:w.name,desc:w.desc,tag:`初始武器 · Lv.1 · ${w.build}`,rarity:'common',kind:'weapon',noRarityTrack:true},()=>{
      if(player.weapons[w.id]||!choosingStart)return;
      addWeapon(w.id);
      startPickCount++;
      div.style.opacity=.45;
      div.style.pointerEvents='none';
      const tag=div.querySelector('.tag');
      if(tag)tag.textContent='已选择';
      if(startPickCount>=2){
        choosingStart=false;
        overlay.style.display='none';
        title.textContent='星舰改装';
        sub.textContent='选择一项升级。';
        paused=false;
        clearKeys();
        message('第 1 关开始');
      }
    });
    cards.appendChild(div);
  });
  overlay.style.display='flex';
};

const __userReqBossRewardKillEnemy=killEnemy;
killEnemy=function(e,color){
  if(e.dead)return;
  const wasBoss=!!(e.def&&e.def.boss);
  const killedStage=stage;
  __userReqBossRewardKillEnemy(e,color);
  if(wasBoss&&!gameOver&&__bossRewardClaimedStage!==killedStage){
    showBossRewardSelect();
  }
};

const __userReqOldNextStage=nextStage;
nextStage=function(){
  const rewardedThisStage=__bossRewardClaimedStage===stage;
  stage++;
  stageTime=0;
  waveFlags={w1:false,w2:false};
  bossSpawned=false;
  player.hp=clamp(player.hp+35,0,player.maxHp);
  showStage();
  if(!rewardedThisStage)levelUp();
};

try{
  const startSub=document.querySelector('#startOverlay .subtitle');
  if(startSub)startSub.textContent='俯视角太空 Rogue Survivor。开局随机出现 6 个最低等级武器，玩家选择 2 个；击杀 Boss 后会获得一次至少含金卡的技能选择。';
}catch(e){}
/* === End user request patch === */

/* === Offline visual quality upgrade: procedural art, no external assets === */
let artNebulaVeils=[],artEnergyRibbons=[],artDerelicts=[],artStarbursts=[];
const ART_WEAPON_ROLE={starSword:'直线剑气',thunderLance:'高速穿透',moonBlade:'回旋切割',frostRing:'范围控场',holyPrism:'环绕棱镜',shadowDagger:'追踪弹幕',meteorStaff:'陨落爆破',poisonVine:'持续法阵',dragonBreath:'扇形喷焰',voidHole:'牵引奇点',missilePod:'追踪爆破',railCannon:'贯穿狙击',arcEmitter:'连锁电弧',mineLayer:'陷阱爆破',beamCore:'引导光束'};
function artAlpha(color,a){if(!color||color[0]!=='#')return color;let h=color.slice(1);if(h.length===3)h=h.split('').map(x=>x+x).join('');let n=parseInt(h,16);return`rgba(${(n>>16)&255},${(n>>8)&255},${n&255},${a})`}
function artPath(c,pts){c.beginPath();pts.forEach((p,i)=>i?c.lineTo(p[0],p[1]):c.moveTo(p[0],p[1]));c.closePath()}
function artRoundRect(c,x,y,w,h,r){r=Math.min(r,w/2,h/2);c.beginPath();c.moveTo(x+r,y);c.lineTo(x+w-r,y);c.quadraticCurveTo(x+w,y,x+w,y+r);c.lineTo(x+w,y+h-r);c.quadraticCurveTo(x+w,y+h,x+w-r,y+h);c.lineTo(x+r,y+h);c.quadraticCurveTo(x,y+h,x,y+h-r);c.lineTo(x,y+r);c.quadraticCurveTo(x,y,x+r,y);c.closePath()}
function artPoly(c,pts,fill,stroke=null,lw=1){artPath(c,pts);c.fillStyle=fill;c.fill();if(stroke){c.strokeStyle=stroke;c.lineWidth=lw;c.stroke()}}
function artGlow(c,x,y,r,color,core=.9){let g=c.createRadialGradient(x,y,0,x,y,Math.max(1,r));g.addColorStop(0,'rgba(255,255,255,'+core+')');g.addColorStop(.22,artAlpha(color,.9));g.addColorStop(1,artAlpha(color,0));c.fillStyle=g;c.beginPath();c.arc(x,y,r,0,Math.PI*2);c.fill()}
function artStrokeGlow(c,color,lw,blur=18,alpha=1){c.strokeStyle=artAlpha(color,alpha);c.lineWidth=lw;c.shadowColor=color;c.shadowBlur=blur}
const __artInitBackgroundDecor=initBackgroundDecor;
initBackgroundDecor=function(){
  __artInitBackgroundDecor();
  artNebulaVeils=[];artEnergyRibbons=[];artDerelicts=[];artStarbursts=[];
  for(let i=0;i<16;i++)artNebulaVeils.push({x:rand(180,WORLD-180),y:rand(180,WORLD-180),r:rand(260,620),rot:rand(0,Math.PI*2),stretch:rand(.52,1.08),color:['#2fd3ff','#7f77ff','#ff6b9a','#ffb65f','#6dffbd'][Math.floor(rand(0,5))],a:rand(.07,.18)});
  for(let i=0;i<8;i++)artEnergyRibbons.push({x:rand(0,WORLD),y:rand(0,WORLD),len:rand(760,1380),rot:rand(0,Math.PI*2),color:['#56e8ff','#ffcf6a','#ff6b78'][Math.floor(rand(0,3))],a:rand(.06,.13),phase:rand(0,9)});
  for(let i=0;i<13;i++)artDerelicts.push({x:rand(180,WORLD-180),y:rand(180,WORLD-180),r:rand(34,92),rot:rand(0,Math.PI*2),kind:Math.random()<.5?'gate':'ship',a:rand(.09,.18)});
  for(let i=0;i<32;i++)artStarbursts.push({x:rand(0,WORLD),y:rand(0,WORLD),r:rand(2.4,5.5),h:rand(180,45+360),a:rand(.18,.5),s:rand(.8,2.2)});
}
function drawWorld(c,cx,cy,w,h,t){
  c.save();
  c.fillStyle='#030612';
  c.fillRect(cx,cy,w,h);

  // 用 3.png 作为世界背景，替代原来的星云、星星、行星、陨石、残骸等程序背景。
  if(worldBgCanvas){
    c.drawImage(worldBgCanvas,cx,cy,w,h,cx,cy,w,h);
  }else if(worldBgImgReady){
    // 极少数浏览器未及时生成离屏 canvas 时的兜底绘制。
    c.save();
    c.filter=`blur(${WORLD_BG_BLUR}px)`;
    c.globalAlpha=WORLD_BG_ALPHA;
    drawCoverImageToRect(c,worldBgImg,cx-24,cy-24,w+48,h+48);
    c.restore();
  }else{
    let fallback=c.createLinearGradient(cx,cy,cx+w,cy+h);
    fallback.addColorStop(0,'#030612');
    fallback.addColorStop(.55,'#08101f');
    fallback.addColorStop(1,'#05050a');
    c.fillStyle=fallback;
    c.fillRect(cx,cy,w,h);
  }

  // 轻微压暗背景，避免图片太抢眼，保证战机、敌人、弹幕可读性。
  let shade=c.createRadialGradient(cx+w*.5,cy+h*.5,Math.min(w,h)*.18,cx+w*.5,cy+h*.5,Math.max(w,h)*.72);
  shade.addColorStop(0,`rgba(2,5,12,${WORLD_BG_CENTER_DIM})`);
  shade.addColorStop(1,`rgba(1,3,9,${WORLD_BG_EDGE_DIM})`);
  c.fillStyle=shade;
  c.fillRect(cx,cy,w,h);

  // 保留原版世界网格，但整体更淡。
  drawFadedWorldGrid(c,cx,cy,w,h,t);
  c.restore();
}
function drawFadedWorldGrid(c,cx,cy,w,h,t){
  c.save();
  const step=80;
  c.lineWidth=1;
  c.strokeStyle=`rgba(86,180,255,${WORLD_GRID_ALPHA})`;
  for(let x=Math.floor(cx/step)*step;x<cx+w+step;x+=step){
    c.beginPath();
    c.moveTo(x,cy);
    c.lineTo(x,cy+h);
    c.stroke();
  }
  for(let y=Math.floor(cy/step)*step;y<cy+h+step;y+=step){
    c.beginPath();
    c.moveTo(cx,y);
    c.lineTo(cx+w,y);
    c.stroke();
  }

  // 世界边界也保留，但比原来淡，避免压过背景图。
  const pulse=.45+.55*Math.sin(t*1.2);
  c.strokeStyle=`rgba(255,211,106,${.09+pulse*.035})`;
  c.lineWidth=4;
  c.strokeRect(20,20,WORLD-40,WORLD-40);
  c.strokeStyle='rgba(255,255,255,.045)';
  c.lineWidth=1;
  c.strokeRect(32,32,WORLD-64,WORLD-64);
  c.restore();
}
function drawForegroundAtmosphere(c,cx,cy,w,h,t){
  // 原版前景尘埃/扫描线也去掉，只保留上面的淡网格和背景图。
}
function glowCircle(c,x,y,r,color){c.save();c.globalCompositeOperation='lighter';artGlow(c,x,y,r*3.4,color,.48);artGlow(c,x,y,r*1.35,color,.86);c.fillStyle='#fff';c.globalAlpha=.75;c.beginPath();c.arc(x,y,Math.max(1.2,r*.32),0,Math.PI*2);c.fill();c.restore()}
function drawEngineFlame(c,boost=false,blink=false,flamePower=.18){
  if(!thrustFlameImgReady)return;
  const p=clamp(flamePower,.12,1.15);
  const flicker=1+Math.sin((player?.flameFlicker||stageTime*10))*0.055+Math.sin(stageTime*31)*0.025;
  const flameScale=(.64+p*.48)*(boost?1.08:1)*flicker;
  const w=ENGINE_FLAME.w*flameScale;
  const h=ENGINE_FLAME.h*flameScale;
  const x=ENGINE_FLAME.x;
  const y=ENGINE_FLAME.y+(1-p)*10;
  c.save();
  c.globalCompositeOperation='lighter';
  c.globalAlpha=(blink?.34:1)*(.20+p*.68);
  c.shadowColor='#4fdfff';
  c.shadowBlur=p<.3?4:14+14*p;
  c.drawImage(thrustFlameImg,x-w/2,y,w,h);
  c.globalAlpha=(blink?.18:.42)*(.25+p*.65);
  c.drawImage(thrustFlameImg,x-w*.43,y+h*.04,w*.86,h*.92);
  c.restore();
}
function drawShip(c,x,y,a,boost=false,blink=false,scale=1,flamePower=.18){
  c.save();
  c.translate(x,y);
  c.rotate(a+PLAYER_SHIP_ROTATION_OFFSET);
  c.scale(scale,scale);

  // 先绘制 2.png 尾焰，再绘制机体；这样尾焰会在战机后面，不遮住机身。
  drawEngineFlame(c,boost,blink,flamePower);
  c.globalAlpha=blink?.42:1;

  // 导入 1.png 后不再绘制原版喷气口/尾焰线条，避免与图片素材重叠。
  c.globalCompositeOperation='source-over';
  if(playerShipImgReady){
    const w=120,h=120; // 原 160×160，显示尺寸缩小 25%，不修改 1.png 文件本身。
    c.shadowColor='#66f6ff';
    c.shadowBlur=boost?22:12;
    c.drawImage(playerShipImg,-w/2,-h/2,w,h);
    // v48: removed center glow overlay around the player ship.
  }else{
    c.shadowColor='#5fe7ff';c.shadowBlur=18;artPoly(c,[[-64,-10],[-37,-27],[4,-31],[40,-25],[78,0],[40,25],[4,31],[-37,27],[-64,10]],'#050912','rgba(112,230,255,.32)',2);
    for(const s of[-1,1]){let wg=c.createLinearGradient(-46,s*42,38,0);wg.addColorStop(0,'#121b2b');wg.addColorStop(.48,'#3e607b');wg.addColorStop(.78,'#9dc8dc');wg.addColorStop(1,'#f2fbff');artPoly(c,[[20,s*11],[-12,s*43],[-58,s*31],[-20,s*8]],wg,'rgba(126,247,255,.68)',2);c.fillStyle='#1a2638';c.fillRect(-26,s*26-3,30,6);c.strokeStyle='rgba(255,219,128,.56)';c.lineWidth=2;c.beginPath();c.moveTo(-44,s*29);c.lineTo(-8,s*13);c.stroke()}
    let hull=c.createLinearGradient(-62,-28,80,26);hull.addColorStop(0,'#17233a');hull.addColorStop(.28,'#60809b');hull.addColorStop(.48,'#f2fbff');hull.addColorStop(.7,'#8db0c4');hull.addColorStop(1,'#243650');artPoly(c,[[-54,-9],[-24,-20],[8,-23],[36,-17],[82,0],[36,17],[8,23],[-24,20],[-54,9]],hull,'rgba(16,58,108,.95)',2.2);
    let deck=c.createLinearGradient(-12,-15,42,15);deck.addColorStop(0,'#20324d');deck.addColorStop(.55,'#78a8c4');deck.addColorStop(1,'#e9fbff');artPoly(c,[[39,0],[12,-13],[-12,-10],[-31,0],[-12,10],[12,13]],deck,'rgba(255,255,255,.42)',1);
    let cg=c.createRadialGradient(20,-3,0,18,0,22);cg.addColorStop(0,'#fff');cg.addColorStop(.3,'#9ff5ff');cg.addColorStop(.75,'#2b80d0');cg.addColorStop(1,'rgba(13,30,60,.95)');c.fillStyle=cg;c.shadowColor='#7ef7ff';c.shadowBlur=20;artPath(c,[[36,0],[10,-8],[-2,0],[10,8]]);c.fill();
    c.shadowBlur=0;c.strokeStyle='rgba(255,255,255,.6)';c.lineWidth=1.5;c.beginPath();c.moveTo(55,0);c.lineTo(8,-16);c.moveTo(55,0);c.lineTo(8,16);c.moveTo(-28,-9);c.lineTo(22,-11);c.moveTo(-28,9);c.lineTo(22,11);c.stroke();c.fillStyle='rgba(255,224,138,.9)';for(const s of[-1,1]){c.fillRect(24,s*8-1,25,2);c.fillRect(-16,s*17-1,18,2)}
    c.globalCompositeOperation='lighter';artGlow(c,60,0,22,'#66f6ff',.55);
  }
  c.restore();
}
function drawEnemyShape(c,e){
  c.save();c.translate(e.x,e.y);let r=e.r,color=e.def.color||'#ff5b73',shape=e.def.shape,hit=e.hit?1:0;c.shadowColor=color;c.shadowBlur=hit?38:18;c.globalAlpha=hit?.9:1;
  function core(rad=r*.72){let g=c.createRadialGradient(-rad*.3,-rad*.35,0,0,0,rad*1.2);g.addColorStop(0,'rgba(255,255,255,.9)');g.addColorStop(.22,artAlpha(color,.92));g.addColorStop(1,artAlpha(color,.18));c.fillStyle=g;c.beginPath();c.arc(0,0,rad,0,Math.PI*2);c.fill();c.strokeStyle=artAlpha('#ffffff',.34);c.lineWidth=2;c.stroke()}
  if(shape&&shape.startsWith('boss')){c.rotate((e.phase||1)*.08*Math.sin(stageTime*.7));c.globalCompositeOperation='lighter';for(let i=0;i<3;i++){c.strokeStyle=artAlpha(color,.18-i*.04);c.lineWidth=9-i*2;c.beginPath();c.arc(0,0,r*(1.15+i*.26)+Math.sin(stageTime*2+i)*6,0,Math.PI*2);c.stroke()}c.globalCompositeOperation='source-over'}
  switch(shape){
    case'wisp':core(r*.62);c.globalAlpha=.42;for(let i=0;i<4;i++){c.beginPath();c.ellipse(Math.cos(i*1.7+stageTime)*r*.45,Math.sin(i+stageTime)*r*.3,r*.38,r*.2,i,0,Math.PI*2);c.fill()}break;
    case'skull':core(r*.74);c.fillStyle='#07090e';for(const sx of[-1,1]){c.beginPath();c.ellipse(sx*r*.24,-r*.12,r*.15,r*.2,0,0,Math.PI*2);c.fill();artGlow(c,sx*r*.24,-r*.12,r*.12,'#ff4f6f',.6)}c.fillRect(-r*.28,r*.18,r*.56,r*.1);break;
    case'bug':{let g=c.createLinearGradient(-r,-r,r,r);g.addColorStop(0,artAlpha('#ffffff',.55));g.addColorStop(.18,color);g.addColorStop(1,'#111520');c.fillStyle=g;c.beginPath();c.ellipse(0,0,r*.86,r*.64,0,0,Math.PI*2);c.fill();c.strokeStyle=artAlpha('#ffffff',.38);for(const sy of[-1,1])for(let i=-1;i<=1;i++){c.beginPath();c.moveTo(i*r*.25,sy*r*.28);c.lineTo((i*.28-.62)*r,sy*r*(.68+.08*i));c.stroke()}artGlow(c,r*.46,0,r*.22,color,.5);break}
    case'golem':{let g=c.createLinearGradient(-r,-r,r,r);g.addColorStop(0,'#d9f0ff');g.addColorStop(.42,color);g.addColorStop(1,'#1a202b');c.fillStyle=g;c.fillRect(-r*.56,-r*.52,r*1.12,r*1.04);c.fillRect(-r*.9,-r*.2,r*.28,r*.72);c.fillRect(r*.62,-r*.2,r*.28,r*.72);c.strokeStyle='rgba(255,255,255,.38)';c.strokeRect(-r*.56,-r*.52,r*1.12,r*1.04);artGlow(c,0,-r*.12,r*.28,'#ffd36a',.55);break}
    case'bat':c.fillStyle=artAlpha(color,.86);for(const s of[-1,1]){c.beginPath();c.moveTo(0,0);c.lineTo(s*r*1.45,-r*.62);c.lineTo(s*r*.66,r*.04);c.lineTo(s*r*1.1,r*.48);c.closePath();c.fill()}core(r*.38);break;
    case'flame':{let g=c.createRadialGradient(0,r*.1,2,0,0,r);g.addColorStop(0,'#fff8c7');g.addColorStop(.35,'#ffbd63');g.addColorStop(1,color);c.fillStyle=g;c.beginPath();c.moveTo(0,-r*1.05);c.bezierCurveTo(r*.86,-r*.25,r*.72,r*.58,0,r);c.bezierCurveTo(-r*.74,r*.5,-r*.9,-r*.25,0,-r*1.05);c.fill();artGlow(c,0,-r*.15,r*.42,'#ffd36a',.54);break}
    case'guard':c.rotate(stageTime*.3);artPoly(c,[[0,-r],[r*.78,0],[0,r],[-r*.78,0]],artAlpha(color,.92),'rgba(255,255,255,.55)',2);artGlow(c,0,0,r*.36,'#fff3a3',.5);break;
    case'priest':artPoly(c,[[0,-r*.95],[r*.62,r*.78],[-r*.62,r*.78]],artAlpha(color,.9),'rgba(255,255,255,.55)',2);artGlow(c,0,-r*.72,r*.38,'#ffffff',.55);c.strokeStyle='rgba(255,255,255,.75)';c.beginPath();c.arc(0,-r*1.02,r*.31,0,Math.PI*2);c.stroke();break;
    case'brute':core(r*.66);c.fillStyle=artAlpha(color,.75);c.fillRect(-r*.72,-r*.05,r*1.44,r*1.02);c.strokeStyle='rgba(255,255,255,.35)';c.strokeRect(-r*.72,-r*.05,r*1.44,r*1.02);break;
    case'bossKnight':c.rotate(stageTime*.36);artPoly(c,Array.from({length:18},(_,i)=>{let rr=i%2?r*.82:r*1.18,aa=i*Math.PI*2/18;return[Math.cos(aa)*rr,Math.sin(aa)*rr]}),artAlpha(color,.9),'rgba(255,255,255,.55)',2.5);artGlow(c,0,0,r*.68,'#a995ff',.5);c.strokeStyle='#ff4f6f';c.lineWidth=5;c.beginPath();c.moveTo(-r*.9,-r*.25);c.lineTo(r*.95,0);c.lineTo(-r*.9,r*.25);c.stroke();break;
    case'bossSeraph':for(const s of[-1,1]){artPoly(c,[[0,0],[s*r*1.75,-r*.92],[s*r*.62,0],[s*r*1.75,r*.92]],artAlpha(color,.82),'rgba(255,255,255,.35)',2)}artPoly(c,[[0,-r*1.12],[r*.62,0],[0,r*1.12],[-r*.62,0]],'#eadfff','rgba(255,255,255,.72)',2);artGlow(c,0,0,r*.54,'#7a5cff',.62);break;
    case'bossLeviathan':c.fillStyle='#101927';c.beginPath();c.ellipse(0,0,r*1.56,r*.66,0,0,Math.PI*2);c.fill();for(let i=-3;i<=3;i++){let rr=r*(.36+.06*Math.cos(i));let x=i*r*.36,y=Math.sin(stageTime*2+i)*6;artGlow(c,x,y,rr,color,.45)}c.strokeStyle='#ffb15d';c.lineWidth=4;c.beginPath();c.moveTo(-r*1.38,0);c.lineTo(r*1.42,0);c.stroke();break;
    case'bossHive':c.rotate(stageTime*.18);for(let i=0;i<6;i++){let a=i*Math.PI/3;artGlow(c,Math.cos(a)*r*.54,Math.sin(a)*r*.54,r*.62,color,.34)}artGlow(c,0,0,r*.74,'#ffd6ff',.46);c.fillStyle='#26072c';c.beginPath();c.arc(0,0,r*.25,0,Math.PI*2);c.fill();break;
    default:core(r*.7);break;
  }
  c.restore()
}
function drawPickups(){for(const p of pickups){ctx.save();ctx.translate(p.x,p.y);ctx.globalCompositeOperation='lighter';if(p.type==='heal'){artGlow(ctx,0,0,p.r*3.2,'#ff5b73',.4);ctx.fillStyle='rgba(255,255,255,.95)';ctx.shadowColor='#ff5b73';ctx.shadowBlur=18;artRoundRect(ctx,-p.r*.85,-p.r*.85,p.r*1.7,p.r*1.7,4);ctx.fill();ctx.fillStyle='#ff3156';ctx.fillRect(-3,-8,6,16);ctx.fillRect(-8,-3,16,6)}else{ctx.rotate(stageTime*2.2);artGlow(ctx,0,0,p.r*3.4,'#66f6ff',.42);artPoly(ctx,[[0,-p.r*1.35],[p.r*.92,0],[0,p.r*1.35],[-p.r*.92,0]],'#c9fbff','#66f6ff',1.4)}ctx.restore()}}
function drawParticles(){ctx.save();ctx.globalCompositeOperation='lighter';for(const p of particles){let a=clamp(p.life/p.max,0,1);ctx.globalAlpha=a;artGlow(ctx,p.x,p.y,p.r*2.3,p.color,.36);ctx.fillStyle=p.color;ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fill()}ctx.restore();for(const f of texts){ctx.save();ctx.globalAlpha=clamp(f.life/.6,0,1);ctx.font='900 15px Segoe UI, Microsoft YaHei, sans-serif';ctx.shadowColor=f.color;ctx.shadowBlur=10;ctx.fillStyle=f.color;ctx.fillText(f.text,f.x,f.y);ctx.restore()}}
function drawPrism(c,x,y,r,col){c.save();c.translate(x,y);c.rotate(stageTime*3.6);c.globalCompositeOperation='lighter';artGlow(c,0,0,r*3.2,col,.35);artPoly(c,[[0,-r*1.25],[r*1.08,r*.75],[-r*1.08,r*.75]],artAlpha(col,.9),'rgba(255,255,255,.75)',1.6);c.strokeStyle='rgba(255,255,255,.65)';c.beginPath();c.moveTo(0,-r*1.25);c.lineTo(0,r*.75);c.stroke();c.restore()}
function drawComet(c,x,y,r,col){c.save();c.globalCompositeOperation='lighter';let tg=c.createLinearGradient(x-120,y-150,x,y);tg.addColorStop(0,artAlpha(col,0));tg.addColorStop(.55,artAlpha(col,.28));tg.addColorStop(1,artAlpha('#ffffff',.78));c.strokeStyle=tg;c.lineWidth=Math.max(6,r*.45);c.shadowColor=col;c.shadowBlur=26;c.beginPath();c.moveTo(x-110,y-145);c.quadraticCurveTo(x-50,y-62,x,y);c.stroke();artGlow(c,x,y,r*2.8,col,.78);c.fillStyle='#fff';c.beginPath();c.arc(x,y,Math.max(2,r*.28),0,Math.PI*2);c.fill();c.restore()}
function drawSlash(c,p){c.save();c.translate(player.x,player.y);c.rotate(p.a);let a=clamp(p.life/(p.max||.22),0,1);c.globalCompositeOperation='lighter';for(let i=0;i<5;i++){artStrokeGlow(c,i%2?'#ffffff':p.color,22-i*4,34,a*(.75-i*.09));c.beginPath();c.arc(0,0,p.r+i*6,-.84,.84);c.stroke()}c.restore();c.globalAlpha=1}
function drawFlame(c,p){c.save();c.translate(player.x,player.y);c.rotate(p.a);c.globalCompositeOperation='lighter';for(let i=0;i<7;i++){let rr=p.r-rand(0,22),a=p.arc+rand(-.08,.08);c.globalAlpha=.12+i*.018;c.fillStyle=i%2?'#ffd36a':p.color;c.shadowColor=p.color;c.shadowBlur=30;c.beginPath();c.moveTo(0,0);c.arc(0,0,rr,-a,a);c.closePath();c.fill()}c.restore();c.globalAlpha=1}
function drawIceRing(c,p){c.save();c.globalCompositeOperation='lighter';let a=clamp(p.life/(p.max||.68),0,1);for(let i=0;i<3;i++){artStrokeGlow(c,p.color,10-i*3,26,a*(.55+i*.12));c.beginPath();c.arc(p.x,p.y,p.r+i*5,0,Math.PI*2);c.stroke()}for(let i=0;i<24;i++){let aa=i*Math.PI*2/24+stageTime*1.4;glowCircle(c,p.x+Math.cos(aa)*p.r,p.y+Math.sin(aa)*p.r,2.4,p.color)}c.restore()}
function drawMeteor(c,p){let t=1-p.life/(p.max||.75);c.save();c.globalCompositeOperation='lighter';c.strokeStyle=artAlpha(p.color,.32);c.lineWidth=3;c.setLineDash([8,8]);c.beginPath();c.arc(p.x,p.y,p.impact*t,0,Math.PI*2);c.stroke();c.setLineDash([]);drawComet(c,p.x-120*p.life,p.y-175*p.life,16+24*t,p.color);c.restore()}
function drawZone(c,p){c.save();c.globalCompositeOperation='lighter';let pulse=.5+.5*Math.sin(stageTime*7);c.globalAlpha=.18+pulse*.08;artGlow(c,p.x,p.y,p.r*1.2,p.color,.16);c.strokeStyle=artAlpha(p.color,.56);c.shadowColor=p.color;c.shadowBlur=24;for(let i=0;i<6;i++){c.lineWidth=i===5?3:1;c.beginPath();c.arc(p.x,p.y,p.r*(i+1)/6+Math.sin(stageTime*2+i)*2,0,Math.PI*2);c.stroke()}c.restore();c.globalAlpha=1}
function drawBlackhole(c,p){c.save();c.translate(p.x,p.y);c.rotate(stageTime*3.2);c.globalCompositeOperation='lighter';artGlow(c,0,0,p.r*2.4,p.color,.2);c.fillStyle='rgba(2,1,8,.98)';c.shadowColor=p.color;c.shadowBlur=38;c.beginPath();c.arc(0,0,p.r*.72,0,Math.PI*2);c.fill();for(let i=0;i<5;i++){c.strokeStyle=artAlpha(i%2?'#ffffff':p.color,.66-i*.08);c.lineWidth=3;c.beginPath();c.ellipse(0,0,p.r*(1+i*.17),p.r*(.38+i*.08),i*.3,0,Math.PI*2);c.stroke()}c.restore()}
function drawSpear(c,p){c.save();c.translate(p.x,p.y);c.rotate(Math.atan2(p.vy,p.vx));c.globalCompositeOperation='lighter';let g=c.createLinearGradient(-42,0,36,0);g.addColorStop(0,artAlpha(p.color,0));g.addColorStop(.35,artAlpha(p.color,.75));g.addColorStop(1,'#ffffff');c.strokeStyle=g;c.shadowColor=p.color;c.shadowBlur=28;c.lineWidth=7;c.beginPath();c.moveTo(-42,0);c.lineTo(28,0);c.stroke();artPoly(c,[[38,0],[12,-10],[16,0],[12,10]],'#ffffff',p.color,1.4);c.restore()}
function drawBlade(c,p){c.save();c.translate(p.x,p.y);c.rotate((p.age||stageTime)*9);c.globalCompositeOperation='lighter';artGlow(c,0,0,34,p.color,.28);c.fillStyle=p.color;c.shadowColor=p.color;c.shadowBlur=24;c.beginPath();c.ellipse(0,0,27,9,0,0,Math.PI*2);c.fill();c.fillStyle='#fff';c.beginPath();c.ellipse(8,0,14,3.4,0,0,Math.PI*2);c.fill();c.strokeStyle='rgba(255,255,255,.5)';c.beginPath();c.arc(0,0,31,0,Math.PI*2);c.stroke();c.restore()}
function drawDagger(c,p){c.save();c.translate(p.x,p.y);c.rotate(Math.atan2(p.vy,p.vx));c.globalCompositeOperation='lighter';artGlow(c,0,0,18,p.color,.35);artPoly(c,[[22,0],[-12,-6],[-4,0],[-12,6]],p.color,'rgba(255,255,255,.7)',1.2);c.fillStyle='#fff';c.fillRect(-1,-1,14,2);c.restore()}
function drawMissile(c,p){c.save();c.translate(p.x,p.y);c.rotate(Math.atan2(p.vy,p.vx));c.globalCompositeOperation='lighter';let fg=c.createLinearGradient(-8,0,-38,0);fg.addColorStop(0,'rgba(255,255,255,.95)');fg.addColorStop(.35,artAlpha(p.color,.75));fg.addColorStop(1,artAlpha(p.color,0));c.fillStyle=fg;c.beginPath();c.moveTo(-8,0);c.lineTo(-34,-7);c.lineTo(-18,0);c.lineTo(-34,7);c.closePath();c.fill();c.globalCompositeOperation='source-over';let body=c.createLinearGradient(-12,-7,18,7);body.addColorStop(0,'#7d8b9b');body.addColorStop(.45,'#eef8ff');body.addColorStop(1,'#b8c8d2');artPoly(c,[[18,0],[-11,-7],[-5,0],[-11,7]],body,'rgba(255,255,255,.55)',1);c.fillStyle=p.color;c.fillRect(-7,-2,9,4);c.restore()}
function drawRail(c,p){c.save();c.globalCompositeOperation='lighter';let a=clamp(p.life/(p.max||.18),0,1);artStrokeGlow(c,p.color,20,38,a*.32);c.beginPath();c.moveTo(p.x1,p.y1);c.lineTo(p.x2,p.y2);c.stroke();artStrokeGlow(c,p.color,8,24,a*.82);c.beginPath();c.moveTo(p.x1,p.y1);c.lineTo(p.x2,p.y2);c.stroke();c.strokeStyle='rgba(255,255,255,.92)';c.lineWidth=2.5;c.shadowBlur=0;c.beginPath();c.moveTo(p.x1,p.y1);c.lineTo(p.x2,p.y2);c.stroke();c.restore()}
function drawChain(c,p){c.save();c.globalCompositeOperation='lighter';let a=clamp(p.life/(p.max||.18),0,1);for(let pass=0;pass<2;pass++){c.strokeStyle=pass?'rgba(255,255,255,.9)':artAlpha(p.color,.9);c.lineWidth=pass?2:7;c.shadowColor=p.color;c.shadowBlur=pass?10:26;c.beginPath();for(let i=0;i<p.points.length;i++){let x=p.points[i].x+(i?rand(-7,7):0),y=p.points[i].y+(i?rand(-7,7):0);if(i===0)c.moveTo(x,y);else c.lineTo(x,y)}c.globalAlpha=a;c.stroke()}for(const pt of p.points)glowCircle(c,pt.x,pt.y,5,p.color);c.restore();c.globalAlpha=1}
function drawMine(c,p){c.save();c.translate(p.x,p.y);c.rotate(stageTime*2.4);c.globalCompositeOperation='lighter';artGlow(c,0,0,p.trigger*.55,p.color,.12);c.globalCompositeOperation='source-over';let g=c.createRadialGradient(-5,-5,0,0,0,p.r*1.3);g.addColorStop(0,'#e8f2ff');g.addColorStop(.3,'#354052');g.addColorStop(1,'#0d1119');c.fillStyle=g;c.shadowColor=p.color;c.shadowBlur=18;c.beginPath();c.arc(0,0,p.r,0,Math.PI*2);c.fill();c.strokeStyle=p.color;c.lineWidth=3;for(let i=0;i<6;i++){let a=i*Math.PI/3;c.beginPath();c.moveTo(Math.cos(a)*p.r*.4,Math.sin(a)*p.r*.4);c.lineTo(Math.cos(a)*p.r*1.55,Math.sin(a)*p.r*1.55);c.stroke()}c.restore()}
function drawBeam(c,p){c.save();c.globalCompositeOperation='lighter';let x2=p.x+Math.cos(p.a)*p.len,y2=p.y+Math.sin(p.a)*p.len,a=clamp(p.life/(p.max||.24),0,1);artStrokeGlow(c,p.color,p.width+20,38,a*.2);c.beginPath();c.moveTo(p.x,p.y);c.lineTo(x2,y2);c.stroke();artStrokeGlow(c,p.color,p.width,26,a*.85);c.beginPath();c.moveTo(p.x,p.y);c.lineTo(x2,y2);c.stroke();c.strokeStyle='rgba(255,255,255,.86)';c.lineWidth=Math.max(3,p.width*.28);c.shadowBlur=0;c.beginPath();c.moveTo(p.x,p.y);c.lineTo(x2,y2);c.stroke();c.restore()}
function drawEnemyFireball(c,p){c.save();c.translate(p.x,p.y);c.globalCompositeOperation='lighter';artGlow(c,0,0,p.r*3.2,p.color,.5);let g=c.createRadialGradient(0,0,2,0,0,p.r*1.2);g.addColorStop(0,'#fff6c9');g.addColorStop(.45,'#ffb15d');g.addColorStop(1,p.color);c.fillStyle=g;c.beginPath();c.arc(0,0,p.r,0,Math.PI*2);c.fill();c.strokeStyle=dangerStroke(c);c.lineWidth=dangerWidth(3);c.beginPath();c.arc(0,0,p.r+5,0,Math.PI*2);c.stroke();c.restore()}
function drawEnemyOrb(c,p){c.save();c.translate(p.x,p.y);c.globalCompositeOperation='lighter';artGlow(c,0,0,p.r*3.5,p.color,.45);c.fillStyle=p.color;c.beginPath();c.arc(0,0,p.r,0,Math.PI*2);c.fill();c.strokeStyle=dangerStroke(c);c.lineWidth=dangerWidth(3);c.beginPath();c.arc(0,0,p.r+6,0,Math.PI*2);c.stroke();c.restore()}
function drawEnemyBeam(c,p){c.save();c.globalCompositeOperation='lighter';let x2=p.x+Math.cos(p.a)*p.len,y2=p.y+Math.sin(p.a)*p.len,a=clamp(p.life/p.max,0,1);artStrokeGlow(c,dangerStroke(c),settings.danger?p.width+18:p.width+5,34,a*.88);c.beginPath();c.moveTo(p.x,p.y);c.lineTo(x2,y2);c.stroke();c.strokeStyle=p.color;c.lineWidth=p.width;c.beginPath();c.moveTo(p.x,p.y);c.lineTo(x2,y2);c.stroke();c.restore()}
function drawEnemyBossNova(c,p){c.save();c.globalCompositeOperation='lighter';c.globalAlpha=.2;artGlow(c,p.x,p.y,p.r*1.4,p.color,.16);c.globalAlpha=1;artStrokeGlow(c,dangerStroke(c),dangerWidth(10),28,.85);c.beginPath();c.arc(p.x,p.y,p.r+8,0,Math.PI*2);c.stroke();c.strokeStyle='rgba(255,255,255,.38)';c.lineWidth=2;c.beginPath();c.arc(p.x,p.y,p.r-8,0,Math.PI*2);c.stroke();c.restore()}
function drawVignette(c,w,h){c.save();let g=c.createRadialGradient(w/2,h/2,Math.min(w,h)*.22,w/2,h/2,Math.max(w,h)*.76);g.addColorStop(0,'rgba(0,0,0,0)');g.addColorStop(.72,'rgba(0,0,0,.22)');g.addColorStop(1,'rgba(0,0,0,.72)');c.fillStyle=g;c.fillRect(0,0,w,h);let hpRatio=player?player.hp/player.maxHp:1;if(hpRatio<.32){let pulse=.18+.13*Math.sin(stageTime*8);let rg=c.createRadialGradient(w/2,h/2,Math.min(w,h)*.18,w/2,h/2,Math.max(w,h)*.72);rg.addColorStop(0,'rgba(255,0,60,0)');rg.addColorStop(1,`rgba(255,0,60,${pulse*(1-hpRatio/.32)})`);c.fillStyle=rg;c.fillRect(0,0,w,h)}if(screenFlash>0){c.globalAlpha=screenFlash*.18;c.fillStyle='#ff5b73';c.fillRect(0,0,w,h)}c.globalAlpha=.045;c.fillStyle='#ffffff';for(let y=0;y<h;y+=5)c.fillRect(0,y,w,1);c.globalAlpha=.055;c.fillStyle='rgba(255,245,220,.5)';for(let i=0;i<70;i++){let x=(Math.sin(i*12.989+stageTime*.5)*43758.5453%1+1)%1*w,y=(Math.sin(i*78.23+stageTime*.7)*24634.6345%1+1)%1*h;c.fillRect(x,y,1.2,1.2)}c.restore()}
const __artBaseDrawSkillPreview=drawSkillPreview;
drawSkillPreview=function(c,id,t,w,h){c.clearRect(0,0,w,h);let g=c.createLinearGradient(0,0,w,h);g.addColorStop(0,'#040914');g.addColorStop(.52,'#10202c');g.addColorStop(1,'#211720');c.fillStyle=g;c.fillRect(0,0,w,h);c.save();c.globalCompositeOperation='lighter';c.strokeStyle='rgba(156,236,255,.08)';for(let x=0;x<w;x+=28){c.beginPath();c.moveTo(x,0);c.lineTo(x,h);c.stroke()}for(let y=0;y<h;y+=28){c.beginPath();c.moveTo(0,y);c.lineTo(w,y);c.stroke()}c.restore();c.save();c.translate(w/2,h/2);if(id==='starSword'){drawShip(c,-88,0,0,false,false,.42);drawPreviewSwordWave(c,-28,0,118,0,'#ffd36a',t)}else if(id==='thunderLance'){drawShip(c,-85,0,0,false,false,.38);drawPreviewSpear(c,-20,0,0,'#66f6ff',t)}else if(id==='moonBlade'){drawShip(c,-70,0,0,false,false,.38);drawPreviewBlade(c,Math.sin(t*2)*55,0,'#8ee7ff',t)}else if(id==='frostRing'){drawShip(c,0,0,0,false,false,.36);drawPreviewRing(c,0,0,35+Math.sin(t*4)*22,'#b7f7ff')}else if(id==='holyPrism'){drawShip(c,0,0,0,false,false,.33);for(let i=0;i<3;i++){let a=t*2+i*Math.PI*2/3;drawPrism(c,Math.cos(a)*55,Math.sin(a)*34,9,'#fff3a3')}}else if(id==='shadowDagger'){drawShip(c,-76,0,0,false,false,.36);for(let i=0;i<3;i++)drawPreviewDagger(c,-10+i*38,Math.sin(t*5+i)*18,'#c493ff',0)}else if(id==='meteorStaff'){drawShip(c,-65,18,0,false,false,.34);drawComet(c,35-30*Math.sin(t*2),-30+55*((t*.8)%1),18,'#ff8b42');drawPreviewRing(c,40,30,28,'#ff8b42')}else if(id==='poisonVine'){drawPreviewZone(c,0,12,58,'#70ff8d');for(let i=0;i<5;i++)glowCircle(c,Math.sin(t*2+i)*40,Math.cos(t*1.4+i)*20+8,4,'#70ff8d')}else if(id==='dragonBreath'){drawShip(c,-84,0,0,false,false,.36);drawPreviewFlame(c,-45,0,'#ff5b42',t)}else if(id==='voidHole'){drawPreviewBlackhole(c,0,0,46,'#7a5cff',t);for(let i=0;i<4;i++)glowCircle(c,Math.cos(t+i)*70,Math.sin(t*1.2+i)*40,4,'#c7b0ff')}else if(id==='missilePod'){drawShip(c,-84,0,0,false,false,.36);for(let i=0;i<3;i++)drawPreviewMissile(c,-15+i*36,Math.sin(t*3+i)*18,'#ff9f7a',0)}else if(id==='railCannon'){drawShip(c,-82,0,0,false,false,.36);drawPreviewRail(c,-40,0,112,0,'#a9ecff')}else if(id==='arcEmitter'){drawPreviewChain(c,[[-80,0],[-25,-22],[30,20],[85,-8]],'#8bd8ff',t)}else if(id==='mineLayer'){for(let i=0;i<3;i++)drawPreviewMine(c,-45+i*45,Math.sin(t*2+i)*20,'#ffe38a',t+i)}else if(id==='beamCore'){drawShip(c,-88,0,0,false,false,.36);drawPreviewBeam(c,-48,0,118,0,'#90fff0')}else drawPassivePreview(c,id,t);c.restore()}
function artWeaponRole(id){return ART_WEAPON_ROLE[id]||'武器核心'}
function artFixText(){
  document.title='星魂舰队 Rogue Survivor';
  const labels=document.querySelectorAll('#hud .label');['生命','经验','闪避','推进'].forEach((t,i)=>{if(labels[i])labels[i].textContent=t});
  const weaponTitle=document.querySelector('#weaponList h3');if(weaponTitle)weaponTitle.textContent='武器 / 被动';
  const miniTitle=document.querySelector('#mini h3');if(miniTitle)miniTitle.textContent='操作';
  const mini=document.querySelector('#mini div:not(.panel)');if(mini)mini.innerHTML='<span class="kbd">WASD</span> 移动<br><span class="kbd">鼠标</span> 控制舰首朝向<br><span class="kbd">空格</span> 闪避推进<br><span class="kbd">Shift</span> 按住推进<br><span class="kbd">P / Esc</span> 暂停<br><span class="kbd">M</span> 静音 / 开启音效<br><span class="kbd">R</span> 阵亡后重开';
  const start=document.querySelector('#startOverlay .menu');if(start){let h=start.querySelector('h1'),sub=start.querySelector('.subtitle'),btns=start.querySelectorAll('.btn');if(h)h.textContent='星魂舰队';if(sub)sub.textContent='俯视角太空 Rogue Survivor。开局从随机武器里选择两件装备，在星门边境抵御敌潮和 Boss。';['开始新游戏','操作说明','游戏设置'].forEach((t,i)=>{if(btns[i])btns[i].textContent=t})}
  const diffText={easy:['休闲','休闲：敌人更少、伤害更低，适合体验武器和画面。'],normal:['标准','标准：敌人数量、血量和伤害保持默认。'],hard:['困难','困难：敌人更多、更耐打，Boss 压力更明显。'],nightmare:['噩梦','噩梦：敌潮密度、伤害和血量都显著提高。']};
  for(const k in diffText){if(DIFFICULTY[k]){DIFFICULTY[k].label=diffText[k][0];DIFFICULTY[k].desc=diffText[k][1]}let b=document.getElementById('diff'+k[0].toUpperCase()+k.slice(1));if(b)b.textContent=diffText[k][0]}
  const desc=document.getElementById('difficultyDesc');if(desc&&DIFFICULTY[difficulty])desc.textContent=DIFFICULTY[difficulty].desc;
  const settingsBox=document.getElementById('settingsPanel');if(settingsBox){let h=settingsBox.querySelector('h2');if(h)h.textContent='设置';let spans=settingsBox.querySelectorAll('.menuLine span:first-child');['音量','屏幕震动','伤害数字','粒子特效','危险预警增强','敌人受击反馈'].forEach((t,i)=>{if(spans[i])spans[i].textContent=t})}
  const help=document.getElementById('help');if(help&&!help.classList.contains('startSubPanel'))help.textContent='WASD 移动，鼠标控制朝向，空格闪避，Shift 推进。红色描边是敌方危险技能，低血量时屏幕边缘会闪烁。击杀敌人获得经验，少量掉落血包。';
  const pause=document.querySelector('#pauseOverlay .menu');if(pause){let h=pause.querySelector('h1'),sub=pause.querySelector('.subtitle'),btns=pause.querySelectorAll('.btn');if(h)h.textContent='暂停';if(sub)sub.textContent='战斗已暂停。按 P / Esc 或点击继续。';if(btns[0])btns[0].textContent='继续游戏';if(btns[1])btns[1].textContent='重新开始'}
  const over=document.querySelector('#gameOver .menu');if(over){let h=over.querySelector('h1'),b=over.querySelector('.btn');if(h)h.textContent='战斗结束';if(b)b.textContent='重新开始'}
  if(typeof RARITIES==='object'){Object.assign(RARITIES.common,{tier:'白',name:'普通'});Object.assign(RARITIES.uncommon,{tier:'绿',name:'优秀'});Object.assign(RARITIES.rare,{tier:'蓝',name:'稀有'});Object.assign(RARITIES.epic,{tier:'紫',name:'史诗'});Object.assign(RARITIES.legendary,{tier:'金',name:'传说'})}
}
artFixText();
showStage=function(){let el=document.getElementById('bigStage');el.innerHTML=`第 ${stage} 关<small>${stage<5?'守住星门，等待 Boss 降临':'最终关：深渊裂隙'}</small>`;el.classList.add('show');setTimeout(()=>el.classList.remove('show'),1800)}
updateUI=function(){if(!player)return;document.getElementById('hpFill').style.width=clamp(player.hp/player.maxHp*100,0,100)+'%';document.getElementById('xpFill').style.width=clamp(player.xp/player.nextXp*100,0,100)+'%';document.getElementById('dashFill').style.width=clamp((1-player.dashCd/player.dashMax)*100,0,100)+'%';document.getElementById('boostFill').style.width=clamp(player.boost/player.boostMax*100,0,100)+'%';document.getElementById('stats').innerHTML=`<div>等级：${player.level}</div><div>击杀：${kills}</div><div>关卡：${stage}</div><div>敌人：${enemies.length}</div><div>生命：${Math.ceil(player.hp)}/${player.maxHp}</div><div>Boss：${bossSpawned?'已出现':'未出现'}</div><div>暴击：${Math.round(player.crit*100)}%</div><div>被动：${Object.keys(player.skills).length}</div>${player.build?`<div>构筑保底：${player.build.rarityPity}</div><div>武器：${Object.keys(player.weapons).length}</div>`:''}`;let wh=Object.keys(player.weapons).map(id=>{let w=weaponDefs.find(x=>x.id===id);return`<div style="color:${w.color}">◆ ${w.name} Lv.${player.weapons[id].level} <span style="color:#9fb1c7">/ ${artWeaponRole(id)}</span></div>`}).join('');let sh=Object.keys(player.skills).map(id=>{let s=skillDefs.find(x=>x.id===id);return`<div style="color:#d7e9ff">◇ ${s.name} Lv.${player.skills[id]}</div>`}).join('');document.getElementById('weapons').innerHTML=wh+sh;document.getElementById('stageName').textContent=`第 ${stage} 关`;document.getElementById('stageTime').textContent=`${fmt(stageTime)} / ${fmt(STAGE_LEN)}`;document.getElementById('timelineFill').style.width=clamp(stageTime/STAGE_LEN*100,0,100)+'%';let pct=stageTime/STAGE_LEN;document.getElementById('stageHint').textContent=pct<.31?'小规模敌群正在靠近':pct<.63?'第一轮大规模波次':pct<.88?'第二轮大规模波次':'Boss 即将出现 / 已经出现';updateBossHud();artFixText()}
showStartingWeaponSelect=function(){choosingStart=true;startPickCount=0;const overlay=document.getElementById('levelOverlay'),cards=document.getElementById('cards'),title=overlay.querySelector('h1'),sub=overlay.querySelector('.subtitle');title.textContent='选择初始武器';sub.innerHTML='开局随机出现 6 个 Lv.1 初始武器，请选择其中两个。'+rarityLegendHTML();cards.innerHTML='';shuffle(weaponDefs).slice(0,6).forEach(w=>{const div=buildChoiceCard({id:w.id,title:w.name,desc:w.desc,tag:`初始武器 / Lv.1 / ${artWeaponRole(w.id)}`,rarity:'common',kind:'weapon',noRarityTrack:true},()=>{if(player.weapons[w.id]||!choosingStart)return;addWeapon(w.id);startPickCount++;div.style.opacity=.45;div.style.pointerEvents='none';const tag=div.querySelector('.tag');if(tag)tag.textContent='已选择';if(startPickCount>=2){choosingStart=false;overlay.style.display='none';title.textContent='星舰改装';sub.textContent='选择一项升级。';paused=false;clearKeys();message('第 1 关开始')}});cards.appendChild(div)});overlay.style.display='flex'}
levelUp=function(){paused=true;const overlay=document.getElementById('levelOverlay');overlay.querySelector('h1').textContent='星舰改装';overlay.querySelector('.subtitle').innerHTML='选择一项升级。卡牌按白、绿、蓝、紫、金排序，高阶卡牌拥有更强视觉和构筑价值。'+rarityLegendHTML();const cards=document.getElementById('cards');cards.innerHTML='';buildUpgradeChoices().forEach(c=>{const div=buildChoiceCard(c,()=>{if(c.kind==='weapon')addWeapon(c.id);else applySkill(c.id);syncBuildBonuses();overlay.style.display='none';paused=false;clearKeys();updateUI()});cards.appendChild(div)});overlay.style.display='flex'}
if(typeof showBossRewardSelect==='function'){const __artBossReward=showBossRewardSelect;showBossRewardSelect=function(){__artBossReward();const overlay=document.getElementById('levelOverlay');overlay.querySelector('h1').textContent='Boss 战利品';overlay.querySelector('.subtitle').innerHTML='选择一项高阶战利品。至少包含一张传说或史诗级选项。'+rarityLegendHTML()}}

/* === User request: bloom off === */
let ART_BLOOM_DISABLED=true;
function installNoBloomCanvas(){
  try{
    const proto=CanvasRenderingContext2D&&CanvasRenderingContext2D.prototype;
    const desc=Object.getOwnPropertyDescriptor(proto,'shadowBlur');
    if(desc&&desc.set&&desc.get&&desc.configurable!==false){
      Object.defineProperty(proto,'shadowBlur',{configurable:true,get(){return 0},set(){desc.set.call(this,0)}});
    }
  }catch(e){}
}
installNoBloomCanvas();
artGlow=function(c,x,y,r,color,core=.9){
  const rr=Math.max(1,Math.min(r*.38,18));
  const g=c.createRadialGradient(x,y,0,x,y,rr);
  g.addColorStop(0,'rgba(255,255,255,'+Math.min(.72,core*.72)+')');
  g.addColorStop(.45,artAlpha(color,.72));
  g.addColorStop(1,artAlpha(color,.06));
  c.fillStyle=g;
  c.beginPath();
  c.arc(x,y,rr,0,Math.PI*2);
  c.fill();
}
artStrokeGlow=function(c,color,lw,blur=18,alpha=1){
  c.strokeStyle=artAlpha(color,alpha);
  c.lineWidth=lw;
  c.shadowBlur=0;
}
glowCircle=function(c,x,y,r,color){
  c.save();
  c.globalCompositeOperation='source-over';
  c.shadowBlur=0;
  const rr=Math.max(1.4,r);
  c.fillStyle=artAlpha(color,.86);
  c.beginPath();
  c.arc(x,y,rr,0,Math.PI*2);
  c.fill();
  c.strokeStyle='rgba(255,255,255,.5)';
  c.lineWidth=Math.max(1,rr*.18);
  c.beginPath();
  c.arc(x,y,rr*.72,0,Math.PI*2);
  c.stroke();
  c.restore();
}


/* === Stability patch: pause fix, queued level choices, safe wave spawning, refresh tokens === */
let __fixRunId = 0;
let __fixStageToken = 0;
let __pendingLevelChoices = 0;
let __upgradeRefreshCharges = 1;

function __levelOverlayOpen(){
  const overlay=document.getElementById('levelOverlay');
  return !!overlay && overlay.style.display==='flex';
}
function __removeRefreshRow(){
  const row=document.querySelector('#levelOverlay .refreshRow');
  if(row)row.remove();
}
function __syncRefreshCharge(){
  if(player)player.refreshCharges=__upgradeRefreshCharges;
}
function __gainRefreshCharge(n=1){
  __upgradeRefreshCharges=Math.max(0,__upgradeRefreshCharges+n);
  __syncRefreshCharge();
}
function __renderUpgradePanel({title,subtitle,choiceBuilder,onPick,fromQueue=false,playSound=true}){
  if(!player||gameOver)return;
  paused=true;
  const overlay=document.getElementById('levelOverlay'),cards=document.getElementById('cards'),head=overlay.querySelector('h1'),sub=overlay.querySelector('.subtitle');
  __removeRefreshRow();
  head.textContent=title;
  sub.innerHTML=subtitle;
  const row=document.createElement('div');
  row.className='refreshRow';
  row.innerHTML=`<button class="smallBtn refreshBtn">刷新卡牌</button><span class="refreshCount">剩余刷新次数：${__upgradeRefreshCharges}</span><span class="refreshHint">过关 +1，可积攒</span>`;
  sub.insertAdjacentElement('afterend',row);
  const btn=row.querySelector('.refreshBtn'),count=row.querySelector('.refreshCount');
  function updateRefreshUI(){
    count.textContent=`剩余刷新次数：${__upgradeRefreshCharges}`;
    btn.disabled=__upgradeRefreshCharges<=0;
    btn.classList.toggle('disabled',__upgradeRefreshCharges<=0);
  }
  function closeAfterPick(){
    overlay.style.display='none';
    __removeRefreshRow();
    if(fromQueue)__pendingLevelChoices=Math.max(0,__pendingLevelChoices-1);
    paused=false;
    clearKeys();
    __syncRefreshCharge();
    updateUI();
    if(__pendingLevelChoices>0)setTimeout(__tryOpenNextQueuedLevelUp,0);
  }
  function renderChoices(){
    cards.innerHTML='';
    const choices=choiceBuilder();
    choices.forEach(c=>{
      const div=buildChoiceCard(c,()=>{
        onPick(c);
        closeAfterPick();
      });
      cards.appendChild(div);
    });
  }
  btn.onclick=()=>{
    if(__upgradeRefreshCharges<=0)return;
    __upgradeRefreshCharges--;
    __syncRefreshCharge();
    playSfx('ui');
    renderChoices();
    updateRefreshUI();
    updateUI();
    message(`已刷新卡牌，剩余 ${__upgradeRefreshCharges} 次`);
  };
  renderChoices();
  updateRefreshUI();
  overlay.style.display='flex';
  if(playSound)playSfx('level');
}
function __tryOpenNextQueuedLevelUp(){
  if(__pendingLevelChoices<=0||!player||gameOver||choosingStart||__bossRewardChoiceOpen||__levelOverlayOpen())return;
  __openLevelUpChoice(true);
}
function __openLevelUpChoice(fromQueue=false){
  __renderUpgradePanel({
    title:'星舰改装',
    subtitle:'选择一项升级。卡牌按白、绿、蓝、紫、金排序，高阶卡牌拥有更强视觉和构筑价值。'+rarityLegendHTML(),
    choiceBuilder:buildUpgradeChoices,
    fromQueue,
    onPick(c){
      if(c.kind==='weapon')addWeapon(c.id);else applySkill(c.id);
      syncBuildBonuses();
      message('改装已装备');
    }
  });
}

const __fixBaseInit = init;
init=function(startSelect=false){
  __fixRunId++;
  __fixStageToken++;
  __pendingLevelChoices=0;
  __upgradeRefreshCharges=1;
  __bossRewardChoiceOpen=false;
  __bossRewardClaimedStage=0;
  __fixBaseInit(startSelect);
  __syncRefreshCharge();
  updateUI();
};

togglePause=function(force){
  if(gameOver)return;
  if(__levelOverlayOpen())return;
  paused = force !== undefined ? !!force : !paused;
  document.getElementById('pauseOverlay').style.display=paused?'flex':'none';
  clearKeys();
  playSfx('ui');
};

levelUp=function(){
  __openLevelUpChoice(false);
};

gainXp=function(v){
  if(!player||gameOver)return;
  const gained=v*(player.xpMul||1);
  player.xp+=gained;
  let gainedLevels=0;
  while(player.xp>=player.nextXp){
    player.xp-=player.nextXp;
    player.level++;
    player.nextXp=Math.floor(player.nextXp*1.23+15);
    gainedLevels++;
  }
  if(gainedLevels>0){
    __pendingLevelChoices+=gainedLevels;
    playSfx('level');
    __tryOpenNextQueuedLevelUp();
  }
  updateUI();
};

function bossEncounterActive(){
  return bossSpawned && Array.isArray(enemies) && enemies.some(e=>e&&!e.dead&&e.def&&e.def.boss);
}

spawnWave=function(n){
  const runAtSpawn=__fixRunId;
  const stageAtSpawn=__fixStageToken;
  for(let i=0;i<n;i++){
    setTimeout(()=>{
      if(runAtSpawn!==__fixRunId)return;
      if(stageAtSpawn!==__fixStageToken)return;
      if(!started||gameOver||paused||__levelOverlayOpen())return;
      // Boss 存活期间暂停波次小怪；Boss 死亡后才恢复刷怪。
      if(bossEncounterActive())return;
      spawnEnemy(true);
    },i*80);
  }
};

spawnBoss=function(){
  playSfx('boss');
  const def=bossDefs[(stage-1)%bossDefs.length];
  spawnDef(def,1+stage*.35,true);
  return def;
};

updateStage=function(dt){
  let diff=DIFFICULTY[difficulty];
  let cap=Math.floor((25+stage*5)*diff.spawn);

  if(!bossSpawned&&stageTime>STAGE_LEN*.88){
    bossSpawned=true;
    const bossDef=spawnBoss();
    spawnTick=0;
    message('Boss 出现：'+(bossDef&&bossDef.name?bossDef.name:'Boss'));
  }

  const bossActive=bossEncounterActive();

  // Boss 存活期间不再持续生成普通小怪；Boss 死亡后恢复。
  if(!bossActive&&enemies.length<cap){
    spawnTick-=dt;
    if(spawnTick<=0){
      spawnTick=Math.max(.38,(1.55-stage*.12-stageTime/130)/diff.spawn);
      spawnEnemy(false);
    }
  }
  if(!bossActive&&!waveFlags.w1&&stageTime>STAGE_LEN*.31){
    waveFlags.w1=true;
    spawnWave(Math.floor((8+stage*2)*diff.spawn));
    message('大规模波次来袭！');
  }
  if(!bossActive&&!waveFlags.w2&&stageTime>STAGE_LEN*.63){
    waveFlags.w2=true;
    spawnWave(Math.floor((10+stage*3)*diff.spawn));
    message('第二波敌潮来袭！');
  }
  if(stageTime>STAGE_LEN&&bossSpawned&&!bossEncounterActive())nextStage();
};

nextStage=function(){
  const rewardedThisStage=__bossRewardClaimedStage===stage;
  __fixStageToken++;
  __gainRefreshCharge(1);
  stage++;
  stageTime=0;
  waveFlags={w1:false,w2:false};
  bossSpawned=false;
  spawnTick=0;
  player.hp=clamp(player.hp+35,0,player.maxHp);
  showStage();
  updateUI();
  message(`通过关卡，刷新次数 +1（现有 ${__upgradeRefreshCharges}）`);
  if(!rewardedThisStage)levelUp();
  else __tryOpenNextQueuedLevelUp();
};

showBossRewardSelect=function(){
  if(!player||gameOver||__bossRewardChoiceOpen)return;
  __bossRewardChoiceOpen=true;
  __bossRewardClaimedStage=stage;
  __renderUpgradePanel({
    title:'Boss 战利品',
    subtitle:'选择一项高阶战利品。本次至少出现一张金色卡牌。'+rarityLegendHTML(),
    choiceBuilder:buildBossRewardChoices,
    onPick(c){
      applySkill(c.id);
      syncBuildBonuses();
      __bossRewardChoiceOpen=false;
      message('Boss 战利品已装备');
    }
  });
};

const __fixBaseStartWeaponSelect = showStartingWeaponSelect;
showStartingWeaponSelect=function(){
  __removeRefreshRow();
  __fixBaseStartWeaponSelect();
  __removeRefreshRow();
};

const __fixBaseUpdateUI = updateUI;
updateUI=function(){
  __fixBaseUpdateUI();
  const stats=document.getElementById('stats');
  if(stats&&player){
    stats.insertAdjacentHTML('beforeend',`<div>刷新：${__upgradeRefreshCharges}</div><div>待选升级：${__pendingLevelChoices}</div>`);
  }
};

(function installRefreshChoiceStyles(){
  const css=`
  .refreshRow{display:flex;align-items:center;gap:10px;margin:12px 0 4px;flex-wrap:wrap;color:#cbd3ff;font-size:13px}
  .refreshRow .refreshBtn{background:linear-gradient(90deg,#5c7cff,#66f6ff);border-color:rgba(126,247,255,.65)}
  .refreshRow .refreshBtn.disabled,.refreshRow .refreshBtn:disabled{opacity:.42;cursor:not-allowed;filter:grayscale(.35);transform:none}
  .refreshCount{font-weight:900;color:#ffe08a}
  .refreshHint{opacity:.82}
  `;
  const style=document.createElement('style');
  style.textContent=css;
  document.head.appendChild(style);
})();

