    if(player.scrapAwakened&&elite&&Math.random()<.35)pickups.push({type:'xp',x:x+rand(-16,16),y:y+rand(-16,16),r:8,val:10+stage*2});
    if(player.repairAwakened&&boss){player.hp=clamp(player.hp+player.maxHp*.18,0,player.maxHp);}
