    __v4PrevUpdateUI();if(!player)return;ensureStores();
    const advLines=ADVANCED_IDS.filter(id=>advancedCurrent(id)>0).map(id=>{const s=defOf(id),r=ADV_RULES[id],done=advancedCurrent(id)+0.000001>=r.max,aw=player.awakenings&&player.awakenings[id];return `<div style="color:${aw?'#ffd36a':done?'#c58cff':'#d7e9ff'}">◇ ${escHtml(s?s.name:id)} <span style="color:#9fb1c7">${escHtml(progressText(ADV_RULES,id,advancedCurrent))}${aw?' / 觉醒':done?' / 上限':''}</span></div>`;}).join('');
