    expandedMagnet:{tag:'资源',unit:'percent',max:1.20,values:{green:.12,blue:.20,purple:.32},apply(p,v){p.pickupMul*=1+v}},
    targetingAI:{tag:'输出',unit:'percent',max:.80,values:{green:.05,blue:.10,purple:.15,legendary:.20},apply(p,v){p.crit=Math.min(.95,(p.crit||0)+v)}},
    critDamageAmp:{tag:'输出',unit:'percent',max:1.80,values:{green:.10,blue:.15,purple:.20,legendary:.25},apply(p,v){p.critDmg=(p.critDmg===undefined?.75:p.critDmg)+v}},
    defenseMatrix:{tag:'生存',unit:'percent',max:.60,values:{green:.05,blue:.10,purple:.15},apply(p,v){p.defense=Math.min(.60,(p.defense||0)+v)}},
    dashCharge:{tag:'机动',unit:'charge',max:2,values:{blue:1},apply(p,v){ensureDashCharges(p);p.dashChargesMax=Math.min(3,(p.dashChargesMax||1)+Math.round(v));p.dashCharges=Math.min(p.dashChargesMax,(p.dashCharges||1)+Math.round(v));}},
