  upsertSkill({id:'dashCharge',name:'备用闪避',tag:'机动',rarity:'rare',desc:'蓝色基础卡。闪避次数 +1，最多拥有 3 次闪避。'});

  function defOf(id){return skillDefs.find(s=>s.id===id)}
