      let roll=rand(0,total),idx=0;
      for(;idx<copy.length;idx++){roll-=weight(copy[idx]);if(roll<=0)break;}
      const chosen=copy[Math.min(idx,copy.length-1)];picks.push(chosen);
      copy=copy.filter(c=>!sameChoice(c,chosen));
