      div.innerHTML=`<div class="rarityColorMark" aria-hidden="true"></div>${buildPreviewHTML(c.id)}<h3>${escHtml(c.title||'')}</h3><p>${br(desc)}</p><div class="cardMeta"><span class="tag">${escHtml(tag)}</span><span class="buildTag">+${escHtml(amount)}</span></div>`;
