/* === User patch v45: 60FPS gameplay + low-FPS pixel animation feel === */
(function(){
  const VISUAL_FPS = {
    fx: 18,          // 尾焰、敌人闪烁、武器特效的视觉节奏
    bg: 12,          // 背景星尘/氛围层节奏
    particles: 22,   // 爆炸/拖尾粒子更新节奏
    ui: 24,          // HUD/血条/经验条 DOM 刷新节奏
    preview: 18      // 升级卡预览动画节奏
  };
  const quantizeTime = (t,fps)=>Math.floor((t||0)*fps)/fps;
  const fxFrame = ()=>Math.floor((stageTime||0)*VISUAL_FPS.fx);
  const bgFrame = ()=>Math.floor((stageTime||0)*VISUAL_FPS.bg);
  const fxTime = ()=>fxFrame()/VISUAL_FPS.fx;
  const bgTime = ()=>bgFrame()/VISUAL_FPS.bg;
  function noSmooth(c){
    if(!c)return;
    c.imageSmoothingEnabled=false;
    c.webkitImageSmoothingEnabled=false;
    c.mozImageSmoothingEnabled=false;
    c.msImageSmoothingEnabled=false;
  }

  // 1) 粒子只按 22FPS 更新，但不影响子弹、敌人、碰撞和移动。
  if(typeof updateParticles==='function'){
    let particleAcc = 0;
    updateParticles=function(dt){
      if(paused||gameOver)return;
      particleAcc += dt;
      const step = 1 / VISUAL_FPS.particles;
      if(particleAcc < step) return;
      const used = Math.min(particleAcc, step * 3);
      particleAcc = 0;
      const damping = Math.pow(.96, used/(1/60));
      if(Array.isArray(particles)){
        for(let i=particles.length-1;i>=0;i--){
          const p=particles[i];
          p.life -= used;
          p.x += (p.vx||0) * used;
          p.y += (p.vy||0) * used;
          p.vx = (p.vx||0) * damping;
          p.vy = (p.vy||0) * damping;
          if(p.life<=0)particles.splice(i,1);
        }
      }
      if(Array.isArray(texts)){
        for(let i=texts.length-1;i>=0;i--){
          const f=texts[i];
          f.life -= used;
          f.y -= 28 * used;
          if(f.life<=0)texts.splice(i,1);
        }
      }
    };
  }

  // 2) HUD DOM 刷新降到 24FPS，避免每帧反复改 DOM。
  if(typeof updateUI==='function'){
    const rawUpdateUI45 = updateUI;
    let lastUi = 0;
    updateUI=function(force=false){
      const now = performance.now();
      if(force || now - lastUi >= 1000 / VISUAL_FPS.ui || paused || gameOver){
        lastUi = now;
        return rawUpdateUI45.apply(this,arguments);
      }
    };
  }

  // 3) 重新接管 draw：游戏逻辑仍然 60FPS，但绘制时把“动画时间”量化。
  //    角色位置、敌人位置、子弹位置不降帧；只有闪烁/旋转/呼吸/背景氛围降帧。
  if(typeof draw==='function'){
    draw=function(){
      noSmooth(ctx);
      ctx.clearRect(0,0,W,H);
      const useShake=(shake>0.45)?shake:0;
      const sx=Math.round((Math.random()-.5)*useShake*settings.shake);
      const sy=Math.round((Math.random()-.5)*useShake*settings.shake);
      const camX=Math.round(camera.x),camY=Math.round(camera.y);
      const realStageTime = stageTime;
      const qtFx = fxTime();
      const qtBg = bgTime();
      ctx.save();
      try{
        // 临时把 stageTime 换成量化时间，让所有依赖 stageTime 的视觉动画变成逐帧像素感。
        stageTime = qtFx;
        ctx.translate(-camX+sx,-camY+sy);
        drawWorld(ctx,camX,camY,W,H,qtBg);
        drawPickups();
        drawEnemies();
        ctx.save();ctx.globalCompositeOperation='lighter';drawProjectiles();drawParticles();ctx.restore();
        drawPlayer();
        drawForegroundAtmosphere(ctx,camX,camY,W,H,qtBg);
      }finally{
        stageTime = realStageTime;
        ctx.restore();
      }
      drawVignette(ctx,W,H);
    };
  }

  // 4) 火焰和闪电这类原本每帧随机的效果改成“固定帧随机”，不再 60FPS 噪声乱跳。
  function randFixed(seed){
    const s=Math.sin(seed*127.1+311.7)*43758.5453;
    return s-Math.floor(s);
  }
  function stepRand(frame,i,min,max){return min+(max-min)*randFixed(frame*31+i*17)}

  if(typeof drawFlame==='function'){
    drawFlame=function(c,p){
      const fr=fxFrame();
      c.save();noSmooth(c);c.translate(Math.round(player.x),Math.round(player.y));c.rotate(p.a);c.shadowBlur=0;
      const alphaBase=.11+.04*((fr%2)?1:0);
      for(let i=0;i<5;i++){
        const rr=Math.round(p.r-stepRand(fr,i,0,18));
        const arcJ=stepRand(fr,i+20,-.06,.06);
        c.globalAlpha=alphaBase+(i===0?.08:0);
        c.fillStyle=i%2?'#ffd36a':p.color;
        c.beginPath();
        c.moveTo(0,0);
        c.arc(0,0,rr,-p.arc+arcJ,p.arc+arcJ);
        c.closePath();
        c.fill();
      }
      c.restore();c.globalAlpha=1;
    };
  }

  if(typeof drawChain==='function'){
    drawChain=function(c,p){
      const fr=fxFrame();
      c.save();noSmooth(c);c.globalAlpha=p.life/p.max;c.strokeStyle=p.color;c.shadowBlur=0;c.lineWidth=3;c.beginPath();
      for(let i=0;i<p.points.length;i++){
        const pt=p.points[i];
        const jx=stepRand(fr,i,-5,5),jy=stepRand(fr,i+50,-5,5);
        if(i===0)c.moveTo(Math.round(pt.x),Math.round(pt.y));
        else c.lineTo(Math.round(pt.x+jx),Math.round(pt.y+jy));
      }
      c.stroke();c.restore();c.globalAlpha=1;
    };
  }

  // 5) 尾焰节奏降到 18FPS，但位置仍跟随玩家，避免停下来抖动。
  if(typeof drawEngineFlame==='function'){
    const prevEngine45 = drawEngineFlame;
    drawEngineFlame=function(c,boost=false,blink=false,flamePower=.18){
      const real = stageTime;
      stageTime = fxTime();
      try{return prevEngine45.call(this,c,boost,blink,flamePower)}
      finally{stageTime = real;}
    };
  }

  // 6) 方便以后调参：在控制台可查看/改这些值。
  window.pixelAnimTuning = VISUAL_FPS;
})();
/* === End user patch v45 === */

