/* === Stability patch v10: prevent late-game freeze from duplicated preview loops and object overflow === */
(function installLateGameStabilityPatchV10(){
  const LIMITS={particles:720,texts:140,projectiles:360,pickups:520,enemies:130};
  function trimArray(arr,max){
    if(Array.isArray(arr)&&arr.length>max)arr.splice(0,arr.length-max);
  }
  function trimRuntimeObjects(){
    try{
      trimArray(particles,LIMITS.particles);
      trimArray(texts,LIMITS.texts);
      trimArray(projectiles,LIMITS.projectiles);
      trimArray(pickups,LIMITS.pickups);
      if(Array.isArray(enemies)&&enemies.length>LIMITS.enemies){
        const bosses=enemies.filter(e=>e&&e.def&&e.def.boss);
        const normal=enemies.filter(e=>!(e&&e.def&&e.def.boss));
        enemies=[...normal.slice(-(LIMITS.enemies-bosses.length)),...bosses];
      }
    }catch(e){}
  }

  // Only one preview loop is allowed. Previously each extra call could start another infinite requestAnimationFrame loop.
  let previewLoopRunning=false,previewLast=0;
  renderPreviewCanvases=function(){
    if(previewLoopRunning)return;
    previewLoopRunning=true;
    function previewStep(now){
      if(now-previewLast>33){
        previewLast=now;
        document.querySelectorAll('.previewCanvas').forEach(cv=>{
          const c=cv.getContext('2d'),id=cv.dataset.preview,t=performance.now()/1000;
          drawSkillPreview(c,id,t,cv.width,cv.height);
        });
      }
      requestAnimationFrame(previewStep);
    }
    requestAnimationFrame(previewStep);
  };

  const oldUpdate=update;
  update=function(dt){
    oldUpdate(dt);
    trimRuntimeObjects();
  };

  const oldUpdateUI=updateUI;
  let uiLast=0;
  updateUI=function(){
    const now=performance.now();
    if(now-uiLast<80)return;
    uiLast=now;
    oldUpdateUI();
  };
})();
/* === End stability patch v10 === */

