(function(){
  function fsElement(){
    return document.fullscreenElement || document.webkitFullscreenElement || document.msFullscreenElement || null;
  }

  function requestGameFullscreen(){
    if(fsElement())return;
    const el=document.documentElement;
    const req=el.requestFullscreen || el.webkitRequestFullscreen || el.msRequestFullscreen;
    if(!req)return;
    try{
      const p=req.call(el);
      if(p && typeof p.catch==='function')p.catch(()=>{});
    }catch(e){}
  }

  function exitGameFullscreen(){
    if(!fsElement())return;
    const exit=document.exitFullscreen || document.webkitExitFullscreen || document.msExitFullscreen;
    if(!exit)return;
    try{
      const p=exit.call(document);
      if(p && typeof p.catch==='function')p.catch(()=>{});
    }catch(e){}
  }

  const __fsOldTogglePause=togglePause;
  togglePause=function(force){
    const ret=__fsOldTogglePause.apply(this,arguments);
    try{
      if(typeof paused!=='undefined' && paused){
        exitGameFullscreen();
      }else if(typeof started!=='undefined' && started && !(typeof gameOver!=='undefined' && gameOver)){
        requestGameFullscreen();
      }
    }catch(e){}
    return ret;
  };

  const __fsOldEndGame=endGame;
  endGame=function(){
    exitGameFullscreen();
    return __fsOldEndGame.apply(this,arguments);
  };
})();

