// Script block 6 moved from index.html
(function(){
  function fsElement(){
    return document.fullscreenElement || document.webkitFullscreenElement || document.msFullscreenElement || null;
  }
  function levelChoiceOpen(){
    const ov=document.getElementById('levelOverlay');
    return ov && ov.style.display==='flex';
  }

  // When the browser handles Esc first, keydown may not reach the game.
  // So if fullscreen is exited while the game is running, treat that as Pause.
  let suppressFullscreenPauseUntil=0;
  function shouldPauseAfterFullscreenExit(){
    if(fsElement())return false;
    if(Date.now()<suppressFullscreenPauseUntil)return false;
    if(typeof started==='undefined' || !started)return false;
    if(typeof gameOver!=='undefined' && gameOver)return false;
    if(typeof paused!=='undefined' && paused)return false;
    if(levelChoiceOpen())return false;
    return true;
  }
  function pauseBecauseFullscreenExited(){
    if(!shouldPauseAfterFullscreenExit())return;
    try{
      togglePause(true);
    }catch(e){
      try{
        paused=true;
        const ov=document.getElementById('pauseOverlay');
        if(ov)ov.style.display='flex';
        document.body.classList.add('ui-paused');
        if(typeof clearKeys==='function')clearKeys();
      }catch(_e){}
    }
  }
  ['fullscreenchange','webkitfullscreenchange','MSFullscreenChange'].forEach(ev=>{
    document.addEventListener(ev,pauseBecauseFullscreenExited);
  });

  // Avoid a death/restart-triggered fullscreen exit briefly becoming a pause overlay.
  const __escFixOldEndGame=endGame;
  endGame=function(){
    suppressFullscreenPauseUntil=Date.now()+650;
    return __escFixOldEndGame.apply(this,arguments);
  };
})();

