(function(){
  if(window.__pauseSettingsSeparateVolumeV16)return;
  window.__pauseSettingsSeparateVolumeV16=true;

  function safeClamp(v,a,b){
    if(typeof clamp==='function')return clamp(v,a,b);
    return Math.max(a,Math.min(b,v));
  }
  function pct(v){return Math.round(safeClamp(v,0,1)*100)}

  // Separate volumes. Keep settings.volume as the SFX volume for old code compatibility.
  settings.sfxVolume = typeof settings.sfxVolume==='number' ? settings.sfxVolume : (typeof settings.volume==='number' ? settings.volume : .32);
  settings.bgmVolume = typeof settings.bgmVolume==='number' ? settings.bgmVolume : .14;
  settings.volume = settings.sfxVolume;

  window.setCustomBgmVolume=function(){
    if(customBgm)customBgm.volume=safeClamp(settings.bgmVolume,0,1);
  };

  function applySfxVolume(){
    settings.volume=settings.sfxVolume;
    if(masterGain)masterGain.gain.value=audioEnabled?safeClamp(settings.sfxVolume,0,1):0;
  }

  function syncVolumeLabels(){
    const bgm=document.getElementById('bgmVolumeValue');
    const sfx=document.getElementById('sfxVolumeValue');
    const pBgm=document.getElementById('pauseBgmVolumeValue');
    const pSfx=document.getElementById('pauseSfxVolumeValue');
    if(bgm)bgm.textContent=pct(settings.bgmVolume)+'%';
    if(sfx)sfx.textContent=pct(settings.sfxVolume)+'%';
    if(pBgm)pBgm.textContent=pct(settings.bgmVolume)+'%';
    if(pSfx)pSfx.textContent=pct(settings.sfxVolume)+'%';
    document.querySelectorAll('[data-volume-slider="bgm"]').forEach(el=>{el.value=pct(settings.bgmVolume)});
    document.querySelectorAll('[data-volume-slider="sfx"]').forEach(el=>{el.value=pct(settings.sfxVolume)});
  }

  const __sepOldEnsureAudio=ensureAudio;
  ensureAudio=function(){
    const ret=__sepOldEnsureAudio.apply(this,arguments);
    applySfxVolume();
    setCustomBgmVolume();
    return ret;
  };

  const __sepOldUpdateSetting=updateSetting;
  updateSetting=function(name,value){
    if(name==='bgmVolume'||name==='musicVolume'){
      settings.bgmVolume=safeClamp(Number(value)/100,0,1);
      setCustomBgmVolume();
      syncVolumeLabels();
      return;
    }
    if(name==='sfxVolume'||name==='volume'){
      settings.sfxVolume=safeClamp(Number(value)/100,0,1);
      applySfxVolume();
      syncVolumeLabels();
      return;
    }
    return __sepOldUpdateSetting.apply(this,arguments);
  };

  function replaceStartSettingsVolume(){
    const panel=document.getElementById('settingsPanel');
    if(!panel||panel.dataset.separateVolume==='1')return;
    panel.dataset.separateVolume='1';
    const firstLine=panel.querySelector('.menuLine');
    if(firstLine){
      firstLine.outerHTML=`
        <div class="menuLine"><span>背景音乐</span><input data-volume-slider="bgm" class="slider" type="range" min="0" max="100" value="${pct(settings.bgmVolume)}" oninput="updateSetting('bgmVolume',this.value)"><span id="bgmVolumeValue" class="volValue">${pct(settings.bgmVolume)}%</span></div>
        <div class="menuLine"><span>游戏音效</span><input data-volume-slider="sfx" class="slider" type="range" min="0" max="100" value="${pct(settings.sfxVolume)}" oninput="updateSetting('sfxVolume',this.value)"><span id="sfxVolumeValue" class="volValue">${pct(settings.sfxVolume)}%</span></div>`;
    }
  }

  function installPauseSettingsPanel(){
    const pauseMenu=document.querySelector('#pauseOverlay .menu');
    if(!pauseMenu||document.getElementById('pauseSettingsPanel'))return;
    const restartBtn=pauseMenu.querySelectorAll('.btn')[1];
    const settingsBtn=document.createElement('button');
    settingsBtn.className='btn ghost';
    settingsBtn.textContent='游戏设置';
    settingsBtn.type='button';
    settingsBtn.onclick=function(){window.togglePauseSettingsPanel()};
    if(restartBtn)pauseMenu.insertBefore(settingsBtn,restartBtn);
    else pauseMenu.appendChild(settingsBtn);

    const panel=document.createElement('div');
    panel.id='pauseSettingsPanel';
    panel.innerHTML=`
      <h2>游戏设置</h2>
      <div class="menuLine"><span>背景音乐</span><input data-volume-slider="bgm" class="slider" type="range" min="0" max="100" value="${pct(settings.bgmVolume)}" oninput="updateSetting('bgmVolume',this.value)"><span id="pauseBgmVolumeValue" class="volValue">${pct(settings.bgmVolume)}%</span></div>
      <div class="menuLine"><span>游戏音效</span><input data-volume-slider="sfx" class="slider" type="range" min="0" max="100" value="${pct(settings.sfxVolume)}" oninput="updateSetting('sfxVolume',this.value)"><span id="pauseSfxVolumeValue" class="volValue">${pct(settings.sfxVolume)}%</span></div>
      <div class="menuLine"><span>屏幕震动</span><input class="slider" type="range" min="0" max="100" value="${Math.round((settings.shake||0)*100)}" oninput="updateSetting('shake',this.value)"></div>
      <div class="menuLine"><span>伤害数字</span><span class="toggle ${settings.damageNumbers?'on':''}" onclick="toggleSetting('damageNumbers',this)"></span></div>
      <div class="menuLine"><span>粒子特效</span><span class="toggle ${settings.particles?'on':''}" onclick="toggleSetting('particles',this)"></span></div>
      <div class="menuLine"><span>危险预警增强</span><span class="toggle ${settings.danger?'on':''}" onclick="toggleSetting('danger',this)"></span></div>
      <div class="menuLine"><span>敌人受击反馈</span><span class="toggle ${settings.enemyHitFeedback?'on':''}" onclick="toggleSetting('enemyHitFeedback',this)"></span></div>`;
    pauseMenu.appendChild(panel);
  }

  window.togglePauseSettingsPanel=function(){
    installPauseSettingsPanel();
    const panel=document.getElementById('pauseSettingsPanel');
    if(!panel)return;
    panel.style.display=panel.style.display==='none'||!panel.style.display?'block':'none';
    syncVolumeLabels();
    if(typeof playSfx==='function')playSfx('ui');
  };

  // Ensure pause/continue controls the custom BGM even after later fullscreen patches replaced togglePause.
  const __sepOldTogglePause=togglePause;
  togglePause=function(force){
    const ret=__sepOldTogglePause.apply(this,arguments);
    try{
      const panel=document.getElementById('pauseSettingsPanel');
      if(!paused && panel)panel.style.display='none';
      if(paused)pauseCustomBgm();
      else playCustomBgm();
    }catch(e){}
    return ret;
  };

  const __sepOldToggleAudio=toggleAudio;
  toggleAudio=function(){
    const ret=__sepOldToggleAudio.apply(this,arguments);
    applySfxVolume();
    setCustomBgmVolume();
    syncVolumeLabels();
    return ret;
  };

  replaceStartSettingsVolume();
  installPauseSettingsPanel();
  applySfxVolume();
  setCustomBgmVolume();
  syncVolumeLabels();
})();

