(function(){
  if(window.__xpEnemyBalancePatchV18)return;
  window.__xpEnemyBalancePatchV18=true;

  // 经验升级曲线：起步经验降低，之后每级大约增加 12%，升级节奏更平滑。
  const XP_START=24;
  const XP_GROWTH=1.12;
  function nextLevelXp(current){
    return Math.max(Math.ceil(current*XP_GROWTH),current+1);
  }

  const __xpPatchOldFreshPlayer=freshPlayer;
  freshPlayer=function(){
    const p=__xpPatchOldFreshPlayer.apply(this,arguments);
    p.nextXp=XP_START;
    return p;
  };

  gainXp=function(v){
    if(!player||gameOver)return;
    const gained=v*(player.xpMul||1);
    player.xp+=gained;
    let gainedLevels=0;
    while(player.xp>=player.nextXp){
      player.xp-=player.nextXp;
      player.level++;
      player.nextXp=nextLevelXp(player.nextXp);
      gainedLevels++;
    }
    if(gainedLevels>0){
      __pendingLevelChoices+=gainedLevels;
      playSfx('level');
      __tryOpenNextQueuedLevelUp();
    }
    updateUI();
  };

  // 全难度少量加强：敌人数量约 +8%，敌人血量约 +6%。
  const tunedDifficulty={
    easy:{hp:.827,spawn:.886,desc:'休闲：升级经验每级约 +12%；敌人数量和血量比原版略高，但整体压力仍较低。'},
    normal:{hp:1.06,spawn:1.08,desc:'标准：升级经验每级约 +12%；敌人数量和血量略微提高，战斗更紧凑。'},
    hard:{hp:1.293,spawn:1.253,desc:'困难：升级经验每级约 +12%；敌人密度和血量在原困难基础上小幅提高。'},
    nightmare:{hp:1.569,spawn:1.426,desc:'噩梦：升级经验每级约 +12%；敌潮密度和血量在原噩梦基础上小幅提高。'}
  };
  for(const k in tunedDifficulty){
    if(!DIFFICULTY[k])continue;
    DIFFICULTY[k].hp=tunedDifficulty[k].hp;
    DIFFICULTY[k].spawn=tunedDifficulty[k].spawn;
    DIFFICULTY[k].desc=tunedDifficulty[k].desc;
  }
  const desc=document.getElementById('difficultyDesc');
  if(desc&&DIFFICULTY[difficulty])desc.textContent=DIFFICULTY[difficulty].desc;
})();

