(function(){
  if(typeof buildChoiceCard!=='function')return;
  const __v22PrevBuildChoiceCard=buildChoiceCard;

  function esc22(s){
    return String(s??'').replace(/[&<>"]/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[m]));
  }
  function br22(s){return esc22(s).replace(/\n/g,'<br>');}
  function normalizeLine22(line){
    let s=String(line||'').trim();
    if(!s)return '';
    s=s.replace(/，?本次提升\s*\d+\s*级。?$/,'。');
    s=s.replace(/^Lv\.(\d+)\s*→\s*Lv\.(\d+)。?$/,'Lv.$1 → Lv.$2');
    s=s.replace(/^(白色|绿色|蓝色|紫色|金色)(基础卡|技能卡|强化卡|构筑卡|高阶卡|高级卡|卡牌)?[：:。]\s*/,'');
    s=s.replace(/^Boss\s*奖励[：:。]\s*/,'');
    return s.trim();
  }
  function isExtraLine22(line){
    const s=String(line||'').trim();
    return !s ||
      /加入武器库时/.test(s) ||
      /获得武器卡固定为白色/.test(s) ||
      /当前武器槽已满/.test(s) ||
      /强化没有等级上限/.test(s) ||
      /Boss\s*奖励保底金卡/.test(s) ||
      /达到上限后自动移出卡池/.test(s) ||
      /^基础强化[：:]/.test(s) ||
      /^高阶构筑[：:]/.test(s) ||
      /^白色获得卡[：:]/.test(s) ||
      /强化卡[：:].*只会出现在/.test(s) ||
      /不消耗选择/.test(s) ||
      /如果不想替换/.test(s);
  }
  function cleanParagraphText22(text,c){
    let raw=String(text||'').replace(/\r/g,'\n').split(/\n+/);
    let lines=[];
    for(let line of raw){
      line=normalizeLine22(line);
      if(isExtraLine22(line))continue;
      if(line)lines.push(line);
    }
    // 去重，避免同一条说明被多个补丁重复拼进去
    const seen=new Set();
    lines=lines.filter(l=>{const k=l.replace(/\s+/g,'');if(seen.has(k))return false;seen.add(k);return true;});
    if(c&&c.kind==='weapon'&&c.weaponAction==='upgrade'){
      // 强化卡只保留等级变化和核心数值变化，避免卡面过长。
      lines=lines.slice(0,5);
    }else if(c&&c.kind==='weapon'){
      // 获得武器卡保留武器简介和前几项基础数值。
      lines=lines.slice(0,4);
    }else{
      lines=lines.slice(0,4);
    }
    return lines.join('\n');
  }
  function cleanCard22(div,c){
    if(!div)return div;
    div.classList.add('v22CleanCard');
    const p=div.querySelector('p');
    if(p){
      const cleaned=cleanParagraphText22(p.innerText||p.textContent||'',c);
      if(cleaned)p.innerHTML=br22(cleaned);
    }
    const footers=div.querySelectorAll('.choiceFooter');
    footers.forEach(f=>f.remove());
    // 保留标签和品质，但去掉标签里偏说明性质的长句。
    const tags=div.querySelectorAll('.tag,.buildTag');
    tags.forEach(t=>{
      let s=(t.textContent||'').trim();
      s=s.replace(/\s*·\s*达到上限后自动移出卡池/g,'');
      s=s.replace(/\s*·\s*可取消并返回原卡牌选择/g,'');
      s=s.replace(/^基础强化[：:]/,'');
      t.textContent=s;
    });
    return div;
  }

  buildChoiceCard=function(c,onPick){
    const div=__v22PrevBuildChoiceCard(c,onPick);
    return cleanCard22(div,c);
  };

  function cleanExistingCards22(){
    const cards=document.querySelectorAll('#cards .card');
    cards.forEach(card=>{
      if(card.dataset.v22Cleaned==='1')return;
      card.dataset.v22Cleaned='1';
      cleanCard22(card,null);
    });
  }
  const root=document.getElementById('cards');
  if(root&&window.MutationObserver){
    const obs=new MutationObserver(()=>setTimeout(cleanExistingCards22,0));
    obs.observe(root,{childList:true,subtree:true});
  }

  if(typeof __openLevelUpChoice==='function'&&typeof __renderUpgradePanel==='function'){
    __openLevelUpChoice=function(fromQueue=false){
      __renderUpgradePanel({
        title:'星舰改装',
        subtitle:'选择一项升级。',
        choiceBuilder:buildUpgradeChoices,
        fromQueue,
        onPick(c){
          if(c.kind==='weapon')addWeapon(c.id);else applySkill(c.id);
          if(typeof syncBuildBonuses==='function')syncBuildBonuses();
          if(typeof tryUnlockAwakenings==='function')tryUnlockAwakenings();
          message('改装已装备');
        }
      });
    };
    levelUp=function(){__openLevelUpChoice(false);};
  }

  const __v22PrevShowBossReward=typeof showBossRewardSelect==='function'?showBossRewardSelect:null;
  if(__v22PrevShowBossReward&&typeof __renderUpgradePanel==='function'&&typeof buildBossRewardChoices==='function'){
    showBossRewardSelect=function(){
      if(!player||gameOver||__bossRewardChoiceOpen)return;
      __bossRewardChoiceOpen=true;
      __bossRewardClaimedStage=stage;
      __renderUpgradePanel({
        title:'Boss 战利品',
        subtitle:'选择一项奖励。',
        choiceBuilder:buildBossRewardChoices,
        onPick(c){
          applySkill(c.id);
          if(typeof syncBuildBonuses==='function')syncBuildBonuses();
          __bossRewardChoiceOpen=false;
          message('Boss 战利品已装备');
        }
      });
    };
  }
})();

