// Script block 14 moved from index.html
(function(){
  function escV23(s){
    return String(s==null?'':s).replace(/[&<>"']/g,function(m){
      return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m];
    });
  }
  function textWithBreaksV23(el){
    if(!el)return '';
    let html=el.innerHTML||'';
    html=html
      .replace(/<br\s*\/?\s*>/gi,'\n')
      .replace(/<\/div>/gi,'\n')
      .replace(/<\/p>/gi,'\n')
      .replace(/<[^>]+>/g,'');
    const box=document.createElement('textarea');
    box.innerHTML=html;
    return box.value;
  }
  function cleanLineV23(line){
    return String(line||'')
      .replace(/\u00a0/g,' ')
      .replace(/[ \t]+/g,' ')
      .trim();
  }
  function formatCardTextV23(raw){
    let s=String(raw||'')
      .replace(/\r/g,'\n')
      .replace(/\u00a0/g,' ')
      .replace(/[ \t]+/g,' ')
      .replace(/\n[ \t]+/g,'\n')
      .trim();

    // Repair descriptions that were accidentally joined into one long sentence.
    s=s
      .replace(/(生命低于\s*\d+%\s*时)(?=\S)/g,'$1\n')
      .replace(/(武器伤害提高\s*\d+%)(?=，?击杀)/g,'$1\n')
      .replace(/(击杀回复倍率提高)(?=适用武器)/g,'$1\n')
      .replace(/(燃烧触发概率提高\s*\d+%)(?=燃烧每秒)/g,'$1\n')
      .replace(/(对低血敌人的处决伤害提高\s*\d+%)(?=Boss)/g,'$1\n')
      .replace(/(暴击命中更容易引发小范围爆炸)(?=爆炸强度)/g,'$1\n')
      .replace(/(经验收益提高\s*\d+%)(?=精英)/g,'$1\n')
      .replace(/(击杀回复提高\s*[\d.]+\s*点)(?=精英)/g,'$1\n')
      .replace(/(暴击率提高\s*\d+%)(?=强化)/g,'$1\n')
      .replace(/(击杀触发小型奇点的概率提高\s*\d+%)(?=范围类)/g,'$1\n')
      .replace(/(多武器组合收益提高\s*\d+%)(?=一部分)/g,'$1\n')
      .replace(/(被减速、牵引或控制的敌人)(?=受到)/g,'$1\n')
      .replace(/(追踪和回旋流派获得\s*\d+%\s*强化)(?=提高)/g,'$1\n')
      .replace(/(范围类武器半径额外提升)(?=适用武器)/g,'$1\n')
      .replace(/(强化棱镜、光束和轨道炮体系)(?=适用武器)/g,'$1\n')
      .replace(/(提高处决与暴击收益)(?=适用武器)/g,'$1\n')
      .replace(/(击杀回复倍率提高)(?=适用武器)/g,'$1\n')
      .replace(/([^\n])适用武器：/g,'$1\n适用武器：')
      .replace(/([^\n])出现条件：/g,'$1\n出现条件：');

    const seen=new Set();
    return s.split(/\n+/)
      .map(cleanLineV23)
      .filter(Boolean)
      .filter(function(line){
        const key=line.replace(/\s+/g,'');
        if(seen.has(key))return false;
        seen.add(key);
        return true;
      })
      .join('\n');
  }
  function applyCardBreakFixV23(root){
    const scope=root&&root.querySelectorAll?root:document;
    scope.querySelectorAll('#cards .card p').forEach(function(p){
      const raw=textWithBreaksV23(p);
      const formatted=formatCardTextV23(raw);
      if(!formatted)return;
      if(p.dataset.v23Formatted===formatted)return;
      p.dataset.v23Formatted=formatted;
      p.innerHTML=formatted.split('\n').map(escV23).join('<br>');
    });
  }

  if(typeof buildChoiceCard==='function'){
    const __v23PrevBuildChoiceCard=buildChoiceCard;
    buildChoiceCard=function(c,onPick){
      const div=__v23PrevBuildChoiceCard(c,onPick);
      setTimeout(function(){applyCardBreakFixV23(div);},0);
      return div;
    };
  }

  const cards=document.getElementById('cards');
  if(cards&&window.MutationObserver){
    const obs=new MutationObserver(function(){
      clearTimeout(applyCardBreakFixV23._t);
      applyCardBreakFixV23._t=setTimeout(function(){applyCardBreakFixV23(cards);},0);
    });
    obs.observe(cards,{childList:true,subtree:true});
  }
  document.addEventListener('DOMContentLoaded',function(){applyCardBreakFixV23(document);});
  setTimeout(function(){applyCardBreakFixV23(document);},0);
})();

