// Script block 15 moved from index.html
(function(){
  /*
    v24 目标：删除旧版“构筑卡 / 高阶构筑 / 定向构筑”和“构筑共鸣”。
    保留：武器卡、武器强化卡、基础技能卡、Boss 奖励面板、刷新卡牌功能。
  */
  const REMOVED_BUILD_CARD_IDS=new Set([
    'emberCatalyst','executionLens','stormRelay','criticalOverload','phaseCapacitor',
    'scrapHarvester','repairSpoils','aegisBattery','bloodReactor','prismProtocol',
    'singularityForge','goldenCore','blastMatrix','glacialCommand','shadowContract',
    'orbitalSync','survivalProtocol','overdriveLoop',
    // 这三个原先被移动到“定向构筑卡”，现在也从卡池移除。
    'warheadArray','fieldAmplifier','acceleratorRails'
  ]);
  const BUILD_TEXT_RE=/构筑|共鸣|定向构筑|高阶构筑|适用武器/;

  function stripRemovedSkillDefsV24(){
    if(!Array.isArray(skillDefs))return;
    for(let i=skillDefs.length-1;i>=0;i--){
      const s=skillDefs[i];
      if(!s)continue;
      if(REMOVED_BUILD_CARD_IDS.has(s.id))skillDefs.splice(i,1);
    }
  }
  stripRemovedSkillDefsV24();

  function isRemovedBuildChoiceV24(c){
    if(!c)return true;
    if(c.kind==='weapon')return false;
    const id=String(c.id||'');
    if(REMOVED_BUILD_CARD_IDS.has(id))return true;
    if(c.advanced||c.v19MovedBuild||c.v19Build||c.movedBuild||c.advancedTier)return true;
    const text=[c.title,c.desc,c.tag].map(v=>String(v||'')).join(' ');
    if(BUILD_TEXT_RE.test(text))return true;
    return false;
  }

  function choiceKeyV24(c){
    if(!c)return '';
    if(c.kind==='weapon')return 'weapon:'+c.id+':'+(c.weaponAction||'')+':'+(c.upgradeLevels||'')+':'+(c.rarity||'');
    return 'skill:'+c.id+':'+(c.basicTier||'')+':'+(c.rarity||'');
  }

  function collectSafeChoicesV24(sourceFn,need=3,tries=80,skillsOnly=false){
    const seen=new Set(),out=[];
    for(let i=0;i<tries&&out.length<need*4;i++){
      let arr=[];
      try{arr=sourceFn?sourceFn()||[]:[];}catch(e){arr=[];}
      for(const c of arr){
        if(!c)continue;
        if(skillsOnly&&c.kind==='weapon')continue;
        if(isRemovedBuildChoiceV24(c))continue;
        const key=choiceKeyV24(c);
        if(seen.has(key))continue;
        seen.add(key);
        out.push(c);
      }
    }
    return out;
  }

  function fallbackWeaponChoicesV24(limit=3){
    if(!Array.isArray(weaponDefs)||!player)return [];
    const out=[];
    const owned=player.weapons||{};
    const full=Object.keys(owned).length>=6;
    for(const w of weaponDefs){
      const held=owned[w.id];
      if(held){
        out.push({
          kind:'weapon',id:w.id,weaponAction:'upgrade',upgradeLevels:1,
          title:'强化 '+w.name,
          desc:'提升这把武器的伤害、范围或触发效率。',
          tag:'强化武器',rarity:'uncommon'
        });
      }else if(!full){
        out.push({
          kind:'weapon',id:w.id,weaponAction:'new',upgradeLevels:0,
          title:'获得 '+w.name,
          desc:w.desc||'获得一把新的武器。',
          tag:'获得武器',rarity:'common'
        });
      }
      if(out.length>=limit)break;
    }
    return out;
  }

  function safeSliceV24(arr,count){
    const clean=(arr||[]).filter(c=>!isRemovedBuildChoiceV24(c));
    return clean.slice(0,count);
  }

  const __v24PrevBuildUpgradeChoices=typeof buildUpgradeChoices==='function'?buildUpgradeChoices:null;
  buildUpgradeChoices=function(){
    stripRemovedSkillDefsV24();
    let choices=collectSafeChoicesV24(__v24PrevBuildUpgradeChoices,3,80,false);
    if(choices.length<3)choices=choices.concat(fallbackWeaponChoicesV24(3-choices.length));
    return safeSliceV24(choices,3);
  };

  const __v24PrevBuildBossRewardChoices=typeof buildBossRewardChoices==='function'?buildBossRewardChoices:null;
  buildBossRewardChoices=function(){
    stripRemovedSkillDefsV24();
    let choices=collectSafeChoicesV24(__v24PrevBuildBossRewardChoices||__v24PrevBuildUpgradeChoices,3,80,true);
    if(choices.length<3)choices=collectSafeChoicesV24(__v24PrevBuildUpgradeChoices,3,80,false);
    if(choices.length<3)choices=choices.concat(fallbackWeaponChoicesV24(3-choices.length));
    return safeSliceV24(choices,3);
  };

  // 彻底关闭构筑共鸣：不再解锁、不再显示、不再影响数值。
  syncBuildBonuses=function(){return;};
  activeBuildLines=function(){return [];};
  buildTagSummary=function(){return '';};
  buildTagCount=function(){return 0;};

  const __v24PrevApplySkill=typeof applySkill==='function'?applySkill:null;
  applySkill=function(id){
    if(REMOVED_BUILD_CARD_IDS.has(String(id))){
      if(typeof message==='function')message('构筑卡已移除');
      if(typeof playSfx==='function')playSfx('ui');
      return;
    }
    return __v24PrevApplySkill?__v24PrevApplySkill(id):undefined;
  };

  function cleanupBuildUIV24(){
    const stats=document.getElementById('stats');
    if(stats){
      Array.from(stats.children).forEach(el=>{
        const t=el.textContent||'';
        if(/构筑|稀有保底|构筑保底|高阶卡池|高阶上限/.test(t))el.remove();
      });
    }
    const weaponsEl=document.getElementById('weapons');
    if(weaponsEl){
      Array.from(weaponsEl.children).forEach(el=>{
        const t=el.textContent||'';
        const isRemovedSkill=Array.from(REMOVED_BUILD_CARD_IDS).some(id=>{
          const s=Array.isArray(skillDefs)?skillDefs.find(x=>x&&x.id===id):null;
          return s&&s.name&&t.includes(s.name);
        });
        if(/构筑共鸣|定向构筑|高阶构筑/.test(t)||isRemovedSkill){
          el.classList.add('v24RemovedBuildBlock');
          el.remove();
        }
      });
    }
    const sub=document.querySelector('#levelOverlay .subtitle');
    if(sub&&BUILD_TEXT_RE.test(sub.textContent||''))sub.textContent='选择一项升级。';
  }

  const __v24PrevUpdateUI=typeof updateUI==='function'?updateUI:null;
  updateUI=function(){
    if(__v24PrevUpdateUI)__v24PrevUpdateUI();
    cleanupBuildUIV24();
  };

  if(typeof __renderUpgradePanel==='function'){
    __openLevelUpChoice=function(fromQueue=false){
      __renderUpgradePanel({
        title:'星舰改装',
        subtitle:'选择一项升级。',
        choiceBuilder:buildUpgradeChoices,
        fromQueue,
        onPick(c){
          if(c.kind==='weapon')addWeapon(c.id);else applySkill(c.id);
          if(typeof tryUnlockAwakenings==='function')tryUnlockAwakenings();
          message('改装已装备');
        }
      });
      cleanupBuildUIV24();
    };
    levelUp=function(){__openLevelUpChoice(false);};

    showBossRewardSelect=function(){
      if(!player||gameOver||__bossRewardChoiceOpen)return;
      __bossRewardChoiceOpen=true;
      __bossRewardClaimedStage=stage;
      __renderUpgradePanel({
        title:'Boss 战利品',
        subtitle:'选择一项奖励。',
        choiceBuilder:buildBossRewardChoices,
        onPick(c){
          if(c.kind==='weapon')addWeapon(c.id);else applySkill(c.id);
          __bossRewardChoiceOpen=false;
          message('Boss 战利品已装备');
        }
      });
      cleanupBuildUIV24();
    };
  }

  const cardsRoot=document.getElementById('cards');
  if(cardsRoot&&window.MutationObserver){
    new MutationObserver(function(){
      setTimeout(function(){
        Array.from(cardsRoot.querySelectorAll('.card')).forEach(card=>{
          const t=card.textContent||'';
          if(/高阶构筑|定向构筑|构筑卡|适用武器/.test(t))card.remove();
        });
        cleanupBuildUIV24();
      },0);
    }).observe(cardsRoot,{childList:true,subtree:true});
  }

  document.addEventListener('DOMContentLoaded',function(){stripRemovedSkillDefsV24();cleanupBuildUIV24();});
  setTimeout(function(){stripRemovedSkillDefsV24();cleanupBuildUIV24();},0);
})();

