    v25Pierce:{name:'贯星校准',label:'直线穿透类',weapons:['thunderLance','railCannon','beamCore'],stats:['damage','speed'],max:{damage:.34,speed:.24},values:{green:{damage:.08,speed:.05},blue:{damage:.12,speed:.08},purple:{damage:.18,speed:.11},gold:{damage:.24,speed:.14}}},
    v25Homing:{name:'寻迹阵列',label:'自动追踪类',weapons:['shadowDagger','missilePod','arcEmitter'],stats:['damage','speed'],max:{damage:.30,speed:.20},values:{green:{damage:.07,speed:.04},blue:{damage:.11,speed:.07},purple:{damage:.16,speed:.10},gold:{damage:.21,speed:.13}}},
    v25Explode:{name:'爆裂核心',label:'范围爆破类',weapons:['meteorStaff','missilePod','mineLayer'],stats:['damage','area'],max:{damage:.36,area:.24},values:{green:{damage:.08,area:.05},blue:{damage:.13,area:.08},purple:{damage:.19,area:.12},gold:{damage:.25,area:.16}}},
