(function(){
  const AIMED_ZONE_TYPES_V32={meteor:true,zone:true,blackhole:true,mine:true};
  function aimPointV32(){
    const x=(camera&&Number.isFinite(camera.x)?camera.x:0)+(mouse&&Number.isFinite(mouse.x)?mouse.x:W/2);
    const y=(camera&&Number.isFinite(camera.y)?camera.y:0)+(mouse&&Number.isFinite(mouse.y)?mouse.y:H/2);
    return {
      x:typeof clamp==='function'?clamp(x,40,WORLD-40):x,
      y:typeof clamp==='function'?clamp(y,40,WORLD-40):y
    };
  }

  const prevFireWeapon=typeof fireWeapon==='function'?fireWeapon:null;
  if(prevFireWeapon){
    fireWeapon=function(w,lvl){
      if(!w||!AIMED_ZONE_TYPES_V32[w.type])return prevFireWeapon(w,lvl);

      const target=aimPointV32();
      const start=Array.isArray(projectiles)?projectiles.length:0;
      const oldNearest=typeof nearestEnemy==='function'?nearestEnemy:null;

      try{
        if(oldNearest){
          nearestEnemy=function(){ return {x:target.x,y:target.y,hp:1,dead:false,r:1}; };
        }
        return prevFireWeapon(w,lvl);
      }finally{
        if(oldNearest)nearestEnemy=oldNearest;

        // 毒藤 / 黑洞 / 陨石 / 地雷全部以鼠标十字准星为中心生成。
        // 陨石和地雷原本有随机落点，这里也校正到准星中心，避免看起来还是自动乱丢。
        if(Array.isArray(projectiles)){
          for(let i=start;i<projectiles.length;i++){
            const p=projectiles[i];
            if(p&&AIMED_ZONE_TYPES_V32[p.type]){
              p.x=target.x;
              p.y=target.y;
              p.v32MouseAimed=true;
            }
          }
        }
      }
    };
  }
})();

