// Script block 26 moved from index.html
(function(){
  // 放大命中/状态数字，并加一层较薄的黑色描边，提升在复杂背景上的可读性。
  drawParticles=function(){
    if(Array.isArray(particles)){
      for(const p of particles){
        ctx.globalAlpha=typeof clamp==='function'?clamp(p.life/p.max,0,1):Math.max(0,Math.min(1,p.life/p.max));
        ctx.fillStyle=p.color;
        ctx.beginPath();
        ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
        ctx.fill();
        ctx.globalAlpha=1;
      }
    }

    if(Array.isArray(texts)){
      ctx.save();
      ctx.textAlign='center';
      ctx.textBaseline='middle';
      ctx.font='bold 18px Segoe UI, Arial, Microsoft YaHei, sans-serif';
      ctx.lineJoin='round';
      ctx.miterLimit=2;
      ctx.lineWidth=2.2;
      ctx.strokeStyle='rgba(0,0,0,.88)';

      for(const f of texts){
        const alpha=typeof clamp==='function'?clamp(f.life/.6,0,1):Math.max(0,Math.min(1,f.life/.6));
        ctx.globalAlpha=alpha;
        ctx.strokeText(f.text,f.x,f.y);
        ctx.fillStyle=f.color||'#fff';
        ctx.fillText(f.text,f.x,f.y);
      }

      ctx.restore();
      ctx.globalAlpha=1;
    }
  };
})();

