  // 尺寸与角度微调都集中在这里。
  const TURRET_BASE_SIZE=54;          // 底座显示大小。想更大/更小改这里。
  const TURRET_BARREL_W=24;           // 炮筒宽度。
  const TURRET_BARREL_H=64;           // 炮筒长度。
  const TURRET_BARREL_BACK=.22;       // 炮筒有多少比例留在炮塔中心后方。
  const TURRET_BARREL_ROT_OFFSET=Math.PI/2; // 图2.png 默认朝上时用 Math.PI/2；如果图片本身朝右，改成 0。

  function clamp49(v,a,b){return typeof clamp==='function'?clamp(v,a,b):Math.max(a,Math.min(b,v));}
  function imgReady49(img){return !!(img&&img.complete&&img.naturalWidth>0&&img.naturalHeight>0);}
