(function(){
  if(window.__mousePlacementStaggerV51)return;
  window.__mousePlacementStaggerV51=true;

  // 多个“靠鼠标准星布置”的武器同时冷却完成时，只允许一个先落点，其他会按这个间隔依次布置。
  // 想让间隔更明显可改成 0.35；想更紧凑可改成 0.18。
  const MOUSE_PLACEMENT_GAP_V51=0.28;
  const MOUSE_PLACED_TYPES_V51={
    meteor:true,      // 陨石法杖
    zone:true,        // 毒藤印记
    blackhole:true,   // 虚空黑洞
    mine:true,        // 磁暴地雷
    energyTurret:true // 高能炮塔
  };

  function isMousePlacedWeaponV51(w){
    return !!(w&&MOUSE_PLACED_TYPES_V51[w.type]);
  }
  function weaponCooldownV51(w,lvl){
    const cd=Number(w&&w.cd)||0.5;
    const mul=player&&Number.isFinite(player.cdMul)?player.cdMul:1;
    return Math.max(.05,cd*mul*(1-.05*((Number(lvl)||1)-1)));
  }

  updateWeapons=function(dt){
    if(!player)return;
    player.orbit=(player.orbit||0)+dt;
    if(player.regen>0)player.hp=clamp(player.hp+player.regen*dt,0,player.maxHp);

    player.v51MousePlacementCd=Math.max(0,(player.v51MousePlacementCd||0)-dt);
    let placedMouseWeaponThisFrame=false;

    for(const id in player.weapons){
      const w=Array.isArray(weaponDefs)?weaponDefs.find(x=>x&&x.id===id):null;
      if(!w)continue;
      const lvl=player.weapons[id].level;
      if(!Number.isFinite(player.timers[id]))player.timers[id]=0;
      player.timers[id]-=dt;

      if(w.type==='orbital'){
        if(typeof orbitalDamage==='function')orbitalDamage(dt,w,lvl);
        continue;
      }

      if(player.timers[id]<=0){
        const mousePlaced=isMousePlacedWeaponV51(w);

        // 关键逻辑：如果已有一个鼠标落点武器刚布置，其他鼠标落点武器先保持“待释放”，等共享间隔结束再放。
        if(mousePlaced&&(player.v51MousePlacementCd>0||placedMouseWeaponThisFrame)){
          continue;
        }

        const before=Array.isArray(projectiles)?projectiles.length:0;
        fireWeapon(w,lvl);
        player.timers[id]=weaponCooldownV51(w,lvl);

        if(mousePlaced){
          const after=Array.isArray(projectiles)?projectiles.length:before;
          // 只有真的生成了布置物，才占用共享布置间隔；例如炮塔数量已满时不会拖慢其他落点武器。
          if(after>before){
            player.v51MousePlacementCd=MOUSE_PLACEMENT_GAP_V51;
            placedMouseWeaponThisFrame=true;
          }
        }
      }
    }
  };
})();

