  const WING_IMAGE_SIZE_V52=42;
  const WING_IMAGE_ALPHA_V52=.96;
  const WING_IMAGE_ROTATION_OFFSET_V52=Math.PI/2; // 如果 7.png 本身朝右，改成 0；如果朝下，改成 -Math.PI/2。
  const WING_SHOT_SPEED_V52=690;

  const shadowFleetImgV52=new Image();
  let shadowFleetImgReadyV52=false;
