  shadowFleetImgV52.onerror=function(){console.warn('未能加载幽影舰队图片 7.png，请确认它位于 html 同级的 resource 文件夹内');};
  shadowFleetImgV52.src='./resource/7.png';

  function clamp52(v,a,b){
    return typeof clamp==='function'?clamp(v,a,b):Math.max(a,Math.min(b,v));
  }
  function angleLerp52(a,b,t){
    return a+Math.atan2(Math.sin(b-a),Math.cos(b-a))*clamp52(t,0,1);
  }
