    c.fillStyle='#25164b';
    c.strokeStyle='#9a7cff';
    c.lineWidth=2;
    c.beginPath();
    c.moveTo(0,-14);c.lineTo(12,10);c.lineTo(0,5);c.lineTo(-12,10);c.closePath();
