(function(){
  if(window.__shadowFleetDirectionNoseV54)return;
  window.__shadowFleetDirectionNoseV54=true;

  // 7.png 默认“朝上”，所以绘制时用：飞行/瞄准角度 + Math.PI/2。
  // WING_NOSE_OFFSET_V54：僚机子弹从机头射出的位置；如果觉得太靠前/靠后，就调这个值。
  const WING_NOSE_OFFSET_V54=25;
  const WING_AIM_SMOOTH_V54=12;

  function clamp54(v,a,b){return typeof clamp==='function'?clamp(v,a,b):Math.max(a,Math.min(b,v));}
  function smooth54(rate,dt){return typeof smooth01==='function'?smooth01(rate,dt):1-Math.exp(-rate*dt);}
  function angleLerp54(a,b,t){return a+Math.atan2(Math.sin(b-a),Math.cos(b-a))*clamp54(t,0,1);}
  function isWing54(p){return p&&p.type==='v33Wingman'&&(p.hp===undefined||p.hp>0);}
  function isLiveEnemy54(e){return e&&!e.dead&&e.hp>0&&Number.isFinite(e.x)&&Number.isFinite(e.y);}
  function wingAimAngle54(p){
    if(isLiveEnemy54(p.v53Target))return Math.atan2(p.v53Target.y-p.y,p.v53Target.x-p.x);
    if(isLiveEnemy54(p.v52Target))return Math.atan2(p.v52Target.y-p.y,p.v52Target.x-p.x);
    const sp=Math.hypot(p.vx||0,p.vy||0);
    if(sp>6)return Math.atan2(p.vy||0,p.vx||0);
    if(Number.isFinite(p.v53Angle))return p.v53Angle;
    if(Number.isFinite(p.v52Angle))return p.v52Angle;
    return player&&Number.isFinite(player.angle)?player.angle:0;
  }
  function syncWingAnglesAndMuzzles54(dt){
    if(!Array.isArray(projectiles))return;
    const t=smooth54(WING_AIM_SMOOTH_V54,Number.isFinite(dt)?dt:.016);
    for(const p of projectiles){
      if(!isWing54(p))continue;
      const aim=wingAimAngle54(p);
      const cur=Number.isFinite(p.v54AimAngle)?p.v54AimAngle:(Number.isFinite(p.v53Angle)?p.v53Angle:(Number.isFinite(p.v52Angle)?p.v52Angle:aim));
      p.v54AimAngle=angleLerp54(cur,aim,t);
      // v52 的 7.png 绘制函数读取 v52Angle；这里同步过去，飞机才会真正朝向目标/飞行方向。
      p.v53Angle=p.v54AimAngle;
      p.v52Angle=p.v54AimAngle;
      p.angle=p.v54AimAngle;
      p.v54NoseX=p.x+Math.cos(p.v54AimAngle)*WING_NOSE_OFFSET_V54;
      p.v54NoseY=p.y+Math.sin(p.v54AimAngle)*WING_NOSE_OFFSET_V54;
    }
    for(const s of projectiles){
      if(!s||s.type!=='v33WingShot'||s.v54NoseFixed)continue;
      if(!(s.v53FromShadowFleet||s.v52FromShadowFleet))continue;
      const a=Math.atan2(s.vy||0,s.vx||1);
      // 旧逻辑在僚机中心生成子弹；这里把出生点推到机头，视觉上就是从飞机前端射出。
      s.x+=Math.cos(a)*WING_NOSE_OFFSET_V54;
      s.y+=Math.sin(a)*WING_NOSE_OFFSET_V54;
      s.v54NoseFixed=true;
    }
  }

})();

