(function(){
  'use strict';
  function finite58(v,f){return Number.isFinite(v)?v:f;}
  function clamp58(v,a,b){return Math.max(a,Math.min(b,v));}
  function angleDiff58(a,b){return Math.abs(Math.atan2(Math.sin(a-b),Math.cos(a-b)));}
  function hasStarSwordId58(w){return w&&(w.id==='starSword'||w.name==='星火剑'||(w.type==='melee'&&w.color==='#ffd36a'));}

  // 星火剑：保留原来“金色弧形斩”的外观，只让这道弧形斩向前飞出去。
  try{
    if(Array.isArray(weaponDefs)){
      const ss=weaponDefs.find(w=>w&&w.id==='starSword');
      if(ss){
        ss.desc='向前切出一道飞行的星火弧斩。';
        ss.type='melee';
        ss.cd=.32; // 冷却调低
      }
    }
  }catch(e){}

  const prevFireWeapon58=typeof fireWeapon==='function'?fireWeapon:null;
  if(prevFireWeapon58){
    fireWeapon=function(w,lvl){
      if(!hasStarSwordId58(w))return prevFireWeapon58.apply(this,arguments);
      if(!player||!Array.isArray(projectiles))return;
      try{if(typeof playWeaponSfx==='function')playWeaponSfx('melee');}catch(e){}
      const lv=Math.max(1,Math.round(finite58(lvl,1)));
      const a=finite58(player.angle,0);
      const area=player&&Number.isFinite(player.areaMul)?player.areaMul:1;
      const dmgMul=player&&Number.isFinite(player.damageMul)?player.damageMul:1;
      const spdMul=player&&Number.isFinite(player.projSpeedMul)?player.projSpeedMul:1;
      const count=1;
      const rangeMul=1+(lv-1)*.16;
      for(let i=0;i<count;i++){
        const aa=a+(i-(count-1)/2)*.16;
        const r=(82+lv*8)*area;
        projectiles.push({
          type:'starSlashCut58',
          x:player.x+Math.cos(aa)*42,
          y:player.y+Math.sin(aa)*42,
          vx:Math.cos(aa)*(650+lv*14)*spdMul,
          vy:Math.sin(aa)*(650+lv*14)*spdMul,
          a:aa,
          r:r,
          arc:.84,
          hitWidth:28+lv*2,
          dmg:typeof rollDamage==='function'?rollDamage((28+lv*10)*dmgMul):(28+lv*10)*dmgMul,
          life:.58*rangeMul,
          max:.58*rangeMul,
          color:(w&&w.color)||'#ffd36a',
          pierce:2+Math.floor(lv/2),
          age:0,
          hitList:[]
        });
      }
    };
  }

  function updateStarSlash58(p,dt){
    p.life-=dt;
    p.age=(p.age||0)+dt;
    p.x+=finite58(p.vx,0)*dt;
    p.y+=finite58(p.vy,0)*dt;
    const col=p.color||'#ffd36a';
    const canHit=(p.pierce||0)>0;
    if(canHit&&Array.isArray(enemies)){
      for(const e of enemies){
        if(!e||e.dead||p.hitList&&p.hitList.includes(e))continue;
        const dx=e.x-p.x,dy=e.y-p.y,d=Math.hypot(dx,dy);
        const aa=Math.atan2(dy,dx);
        const inArc=angleDiff58(aa,p.a)<(p.arc||.84);
        const onBlade=d<(p.r+(e.r||0))&&d>Math.max(0,p.r-(p.hitWidth||30)-(e.r||0));
        // 略放宽中心区域，避免弧形斩刚飞出时贴脸漏判定。
        const nearRoot=d<Math.max(42,(p.hitWidth||30)*1.6)+(e.r||0)&&inArc;
        if(inArc&&(onBlade||nearRoot)){
          try{hitEnemy(e,p.dmg||20,col);}catch(err){}
          if(!p.hitList)p.hitList=[];
          p.hitList.push(e);
          p.pierce=(p.pierce||1)-1;
          if(p.pierce<=0){p.pierce=0;break;}
        }
      }
    }
  }

  function drawStarSlashCut58(c,p){
    if(!c||!p)return;
    const life=clamp58(finite58(p.life,p.max||.44)/(finite58(p.max,.44)||.44),0,1);
    const grow=clamp58((p.age||0)/.10,0,1);
    c.save();
    c.translate(p.x,p.y);
    c.rotate(finite58(p.a,0));
    c.globalCompositeOperation='lighter';
    c.globalAlpha=life;
    // 飞行拖尾，只做淡淡的，不改变主体外观。
    const trailLen=64+20*(1-life);
    const tg=c.createLinearGradient(-trailLen,0,18,0);
    tg.addColorStop(0,'rgba(255,211,106,0)');
    tg.addColorStop(.55,'rgba(255,211,106,.16)');
    tg.addColorStop(1,'rgba(255,255,255,.32)');
    c.strokeStyle=tg;
    c.lineWidth=16;
    c.lineCap='round';
    c.beginPath();
    c.moveTo(-trailLen,0);
    c.lineTo(4,0);
    c.stroke();
    // 主体沿用原星火剑的弧形斩：金色/白色粗弧线。
    const rr=(p.r||90)*(0.92+0.08*grow);
    for(let i=0;i<5;i++){
      if(typeof artStrokeGlow==='function'){
        artStrokeGlow(c,i%2?'#ffffff':(p.color||'#ffd36a'),22-i*4,34,life*(.78-i*.09));
      }else{
        c.shadowColor=p.color||'#ffd36a';
        c.shadowBlur=30;
        c.strokeStyle=i%2?'rgba(255,255,255,.78)':(p.color||'#ffd36a');
        c.lineWidth=22-i*4;
      }
      c.beginPath();
      c.arc(0,0,rr+i*6,-.84,.84);
      c.stroke();
    }
    c.restore();
    c.globalAlpha=1;
    c.globalCompositeOperation='source-over';
  }

  // 卡牌预览也改回“原星火剑弧光”，只是展示它向前切出去。
  if(typeof drawPreviewSwordWave==='function'){
    drawPreviewSwordWave=function(c,x,y,len,a,col,t){
      c.save();
      c.translate(x+((t||0)*105%92),y);
      c.rotate(a||0);
      c.globalCompositeOperation='lighter';
      c.globalAlpha=.82;
      for(let i=0;i<4;i++){
        c.strokeStyle=i%2?'rgba(255,255,255,.82)':(col||'#ffd36a');
        c.shadowColor=col||'#ffd36a';
        c.shadowBlur=24;
        c.lineWidth=16-i*4;
        c.beginPath();
        c.arc(0,0,44+i*4,-.84,.84);
        c.stroke();
      }
      c.restore();
    };
  }

  // 文案同步，避免升级卡仍写成“直线剑气”。
  try{
    if(typeof WEAPON_BUILD_META==='object'&&WEAPON_BUILD_META.starSword)WEAPON_BUILD_META.starSword.build='飞行弧斩';
    if(typeof ART_WEAPON_ROLE==='object')ART_WEAPON_ROLE.starSword='飞行弧斩';
  }catch(e){}
})();

