      const baseDmg=(5.8+lvl*1.35)*Number(player.damageMul||1)*b.damage;
      // 等离子射线扇形参数：
      // PLASMA_FAN_ANGLE_SCALE_V87：角度展开倍率。越大，每条射线向外张开的角度越明显；越小，射线越接近平行。
      // PLASMA_SIDE_SPREAD_V87：起点左右展开距离。越大，多条射线的起点越像分布在机翼/弧线两侧。
      // PLASMA_CENTER_FORWARD_V87：整体起点向机头前方移动的距离。越大，射线越靠近机头前方生成。
      // PLASMA_ARC_BACK_V87：弧线回收强度。越大，两侧射线起点越靠后，中间射线越靠前，弧形越明显。
      const PLASMA_FAN_ANGLE_SCALE_V87=.88;
