   outer.addColorStop(0,'rgba(70,0,8,0)');
outer.addColorStop(.16,'rgba(120,10,22,.14)');
outer.addColorStop(.52,'rgba(175,22,34,.20)');
outer.addColorStop(.86,'rgba(120,10,22,.13)');
outer.addColorStop(1,'rgba(70,0,8,0)');
    c.fillStyle=outer;
    c.beginPath();
    c.moveTo(x1,0);
