    c.globalAlpha=.56*pulse;
    c.shadowBlur=5;
    c.shadowColor='rgba(255,128,82,.26)';
    let core=c.createLinearGradient(x1,0,x2,0);
core.addColorStop(0,'rgba(160,18,28,0)');
core.addColorStop(.18,'rgba(205,34,46,.24)');
core.addColorStop(.52,'rgba(245,58,62,.34)');
core.addColorStop(.84,'rgba(190,24,38,.22)');
core.addColorStop(1,'rgba(160,18,28,0)');
    c.fillStyle=core;
    c.beginPath();
    c.moveTo(x1+w*1.45,0);
    c.quadraticCurveTo(x1+len*.24,-coreW,x2-w*.85,0);
    c.quadraticCurveTo(x1+len*.24,coreW,x1+w*1.45,0);
    c.closePath();
    c.fill();

    // ===== 4. 前端能量点：只做小范围橙红亮点，不做纯白爆点 =====
    c.globalAlpha=.46*pulse;
    c.shadowBlur=12;
    c.shadowColor='rgba(255,92,58,.42)';
    const tip=c.createRadialGradient(x2,0,0,x2,0,w*2.8);
    tip.addColorStop(0,'rgba(255,154,96,.52)');
    tip.addColorStop(.42,'rgba(255,72,52,.34)');
