(function(){
  if(window.__weaponCardWordingV90)return;
  window.__weaponCardWordingV90=true;

  const QUALITY_LABELS_V90={1:'普通',2:'优秀',3:'稀有',4:'史诗',5:'传说'};

  function weaponDefV90(id){
    return (Array.isArray(weaponDefs)?weaponDefs:[]).find(function(w){return w&&w.id===id;})||
      {id:id,name:id,desc:'获得一把新武器。',build:'武器'};
  }
  function targetQualityV90(c){
    if(c&&Number.isFinite(Number(c.targetQuality)))return Math.max(1,Math.min(5,Math.round(Number(c.targetQuality))));
    const lv=player&&player.weapons&&player.weapons[c&&c.id]?Number(player.weapons[c.id].level||1):0;
    return lv>0?Math.max(1,Math.min(5,Math.round(lv)+1)):1;
  }
  function qualityLabelV90(c){
    return QUALITY_LABELS_V90[targetQualityV90(c)]||QUALITY_LABELS_V90[1];
  }
  function appendTextLinesV90(el,lines){
    lines.forEach(function(line,i){
      if(i)el.appendChild(document.createElement('br'));
      el.appendChild(document.createTextNode(line));
    });
  }

  (window.__choiceCardPostProcessors=window.__choiceCardPostProcessors||[]).push(function(div,c){
    if(!div||!c||c.kind!=='weapon')return div;

    const w=weaponDefV90(c.id);
    const title=div.querySelector('h3');
    const desc=div.querySelector('p');
    const label=div.querySelector('.cardMeta .buildTag');
    const statLines=desc?String(desc.innerText||desc.textContent||'').replace(/\r/g,'\n').split(/\n+/).map(function(s){return s.trim();}).filter(Boolean):[];

    if(c.weaponAction==='upgrade'){
      if(title)title.textContent='强化 '+w.name;
      if(desc){
        desc.textContent='';
        desc.appendChild(document.createTextNode(w.desc||'强化该武器。'));
        if(statLines.length){
          desc.appendChild(document.createElement('br'));
          desc.appendChild(document.createElement('br'));
          appendTextLinesV90(desc,statLines);
        }
      }
      if(label)label.textContent=qualityLabelV90(c);
    }else{
      if(label)label.textContent='普通';
    }

    return div;
  });
})();

