      const line=isUpgrade&&next>cur?'格挡概率 '+prismBlockPercentV105(cur)+' → '+prismBlockPercentV105(next):'格挡概率 '+prismBlockPercentV105(1);
      p.appendChild(document.createElement('br'));
      p.appendChild(document.createTextNode(line));
