// Script block 82b: consolidate final card post-processors from V103-V105.
(function(){
  if(window.__choiceCardFinalPipelineInstalled)return;
  window.__choiceCardFinalPipelineInstalled=true;
  const baseBuildChoiceCard=typeof buildChoiceCard==='function'?buildChoiceCard:null;
  if(!baseBuildChoiceCard)return;
  buildChoiceCard=function(c,onPick){
    let choice=c;
    const pre=window.__choiceCardPreProcessors||[];
    for(const fn of pre){
      try{
        const next=fn(choice,c);
        if(next)choice=next;
      }catch(e){console.error(e);}
    }
    let div=null;
    const builders=window.__choiceCardBuilders||[];
    for(const fn of builders){
      try{
        div=fn(choice,onPick,c);
        if(div)break;
      }catch(e){console.error(e);}
    }
    if(!div)div=baseBuildChoiceCard.call(this,choice,onPick);
    const post=window.__choiceCardPostProcessors||[];
    for(const fn of post){
      try{
        div=fn(div,choice,c)||div;
      }catch(e){console.error(e);}
    }
    return div;
  };
})();

