    fillGlow125(c,col,22,.92);
    c.beginPath();c.arc(0,0,r*(.82+.08*pulse),0,Math.PI*2);c.fill();
    c.rotate(t*1.8+(p.x+p.y)*.003);
    lineGlow125(c,dangerHardV125,dangerWidth125(2.8),12,.95);
    c.setLineDash([Math.max(4,r*.48),Math.max(5,r*.36)]);
    c.beginPath();c.arc(0,0,r+6+pulse*1.5,0,Math.PI*2);c.stroke();
