    if(name.indexOf('熔核')>=0||s.indexOf('magma')>=0)return 'magma';
    if(name.indexOf('火焰')>=0||s==='flame')return 'flame';
    if(name.indexOf('冰甲')>=0||s==='guard')return 'iceguard';
    if(name.indexOf('镜甲')>=0||s.indexOf('glasswasp')>=0||attack==='v93ShardFan')return 'glasswasp';
    if(name.indexOf('裂相')>=0||s.indexOf('riftexecutioner')>=0||attack==='v93RiftOrbs')return 'rift';
    if(name.indexOf('雷铸')>=0||s.indexOf('stormwarden')>=0||attack==='v93StormPulse')return 'storm';
    if(name.indexOf('祭司')>=0||s==='priest')return 'priest';
    if(name.indexOf('巨魔')>=0||s==='brute')return 'brute';
    return attack||String(p&&p.type||'enemy');
